double e_atof(const char *num)
{
	char *endp;
	double d;

	errno = 0;
	d = strtod(num, &endp);

	if (endp == num || *endp != '\0') {
		fprintf(stderr, "not a valid floating point number: %s\n", num);
		exit(EXIT_FAILURE);
	}
	if (errno == ERANGE) {
		fprintf(stderr, "floating point value out of range: %s\n", num);
		exit(EXIT_FAILURE);
	}

	return d;
}

void parseInput(char *input)
{
	char *args[128];
	char *token;
	int argc = 0;
	pid_t pid;
	int status;

	if (input == NULL)
		return;

	/* Strip the trailing newline, if any. */
	input[strcspn(input, "\n")] = '\0';

	token = strtok(input, " \t");
	while (token != NULL && argc < (int)(sizeof(args) / sizeof(args[0])) - 1) {
		args[argc++] = token;
		token = strtok(NULL, " \t");
	}
	args[argc] = NULL;

	if (argc == 0)
		return;

	/* Built-in commands. */
	if (strcmp(args[0], "exit") == 0)
		exit(EXIT_SUCCESS);

	if (strcmp(args[0], "cd") == 0) {
		const char *dir = (args[1] != NULL) ? args[1] : getenv("HOME");
		if (dir != NULL && chdir(dir) != 0)
			perror("cd");
		return;
	}

	pid = fork();
	if (pid < 0) {
		perror("fork");
		return;
	}

	if (pid == 0) {
		execvp(args[0], args);
		perror(args[0]);
		_exit(EXIT_FAILURE);
	}

	if (waitpid(pid, &status, 0) < 0)
		perror("waitpid");
}

