int build_seq(table_t *T, int table_size, int num_addr)
{
	int start, i, count = 0;
	char key[2];

	if (T == NULL || table_size <= 0 || num_addr <= 0)
		return 0;

	key[1] = '\0';

	while (count < num_addr) {
		/* Pick a random starting address for this sequence. */
		start = rand() % table_size;

		/* Lay down a sequence of up to 26 adjacent keys. */
		for (i = 0; i < 26 && count < num_addr; i++) {
			int idx = (start + i) % table_size;

			if (T[idx].valid)
				continue;

			key[0] = (char)('a' + i);
			T[idx].key = (char)key[0];
			T[idx].valid = 1;
			count++;
		}
	}

	return count;
}

