void gupcr_backtrace (void)
{
	void *frames[GUPCR_MAX_BACKTRACE_SIZE];
	int nframes;
	int fd = STDERR_FILENO;
	char *prefix;
	char fname[1024];
	int opened = 0;

	prefix = getenv ("UPC_BACKTRACEFILE");
	if (prefix != NULL)
	{
		if (*prefix == '\0')
			prefix = "trace";

		snprintf (fname, sizeof (fname), "%s-%d.%d",
			  prefix, (int) getpid (), MYTHREAD);

		fd = open (fname, O_WRONLY | O_CREAT | O_TRUNC, 0644);
		if (fd < 0)
			fd = STDERR_FILENO;
		else
			opened = 1;
	}

	nframes = backtrace (frames, GUPCR_MAX_BACKTRACE_SIZE);
	backtrace_symbols_fd (frames, nframes, fd);

	if (opened)
		close (fd);
}

void ProcessKeyboard(Camera_Movement direction, float deltaTime)
{
	float velocity = MovementSpeed * deltaTime;

	switch (direction) {
	case FORWARD:
		Position.x += Front.x * velocity;
		Position.y += Front.y * velocity;
		Position.z += Front.z * velocity;
		break;
	case BACKWARD:
		Position.x -= Front.x * velocity;
		Position.y -= Front.y * velocity;
		Position.z -= Front.z * velocity;
		break;
	case LEFT:
		Position.x -= Right.x * velocity;
		Position.y -= Right.y * velocity;
		Position.z -= Right.z * velocity;
		break;
	case RIGHT:
		Position.x += Right.x * velocity;
		Position.y += Right.y * velocity;
		Position.z += Right.z * velocity;
		break;
	}
}

int launch_child(char **args, char **directories)
{
	pid_t pid;
	int status;

	(void)directories;

	if (args == NULL || args[0] == NULL)
		return 1;

	pid = fork();
	if (pid < 0) {
		perror("fork");
		return 1;
	}

	if (pid == 0) {
		/* Child process. */
		if (execvp(args[0], args) == -1)
			perror(args[0]);
		_exit(EXIT_FAILURE);
	}

	/* Parent process: wait for the child to finish. */
	do {
		if (waitpid(pid, &status, WUNTRACED) < 0) {
			perror("waitpid");
			break;
		}
	} while (!WIFEXITED(status) && !WIFSIGNALED(status));

	return 1;
}

static inline void adj_guesttime(u64 hosttime, u64 reftime, u8 adj_flags)
{
	unsigned long flags;
	u64 cur_reftime;

	/*
	 * Save the adjustments made to the host time so that the
	 * current wall clock can be reconstructed later on.
	 */
	spin_lock_irqsave(&host_ts.lock, flags);

	cur_reftime = hv_read_reference_counter();
	host_ts.host_time = hosttime;
	host_ts.ref_time = cur_reftime;

	/*
	 * TimeSync v4 messages contain reference time (guest's Hyper-V
	 * clocksource read when the time sample was generated); we can
	 * improve the precision by adding the delta between now and the
	 * time of generation.
	 */
	if (ts_srv_version > TS_VERSION_3)
		host_ts.host_time += (cur_reftime - reftime);

	spin_unlock_irqrestore(&host_ts.lock, flags);

	/* Schedule work to do do_settimeofday64() only on a hard sync. */
	if (adj_flags & ICTIMESYNCFLAG_SYNC)
		schedule_work(&adj_time_work);
}

int deriveKeys(struct cryptoVar *cryptoStructPtr, struct authVar *authStructPtr)
{
	unsigned char derived[64];

	if (cryptoStructPtr == NULL || authStructPtr == NULL)
		return -1;

	/*
	 * Derive a 64-byte key using scrypt, then split it: the first half is
	 * the encryption key and the second half is the authentication key.
	 */
	if (crypto_pwhash_scryptsalsa208sha256_ll(
			cryptoStructPtr->password, cryptoStructPtr->passwordLen,
			cryptoStructPtr->salt, cryptoStructPtr->saltLen,
			(uint64_t)1 << 14, 8, 1,
			derived, sizeof(derived)) != 0) {
		return -1;
	}

	memcpy(cryptoStructPtr->key, derived, 32);
	memcpy(authStructPtr->key, derived + 32, 32);

	/* Wipe the combined key material. */
	memset(derived, 0, sizeof(derived));

	return 0;
}

void I2CFIFOClear(unsigned int baseAdd, unsigned int flag)
{
	/*
	 * Setting the appropriate bit (TXFIFO_CLR or RXFIFO_CLR) in the
	 * buffer control register flushes the corresponding FIFO.
	 */
	HWREG(baseAdd + I2C_BUF) |= flag;
}

static Datum
make_text_key(char flag, const char *str, int len)
{
	text	   *item;
	char		hashbuf[10];

	if (len > JGIN_MAXLENGTH)
	{
		uint32		hashval;

		hashval = DatumGetUInt32(hash_any((const unsigned char *) str, len));
		snprintf(hashbuf, sizeof(hashbuf), "%08x", hashval);
		str = hashbuf;
		len = 8;
		flag |= JGINFLAG_HASHED;
	}

	/*
	 * Now build the text Datum.  For simplicity we always emit the flag
	 * byte as the first byte of the string.
	 */
	item = (text *) palloc(VARHDRSZ + len + 1);
	SET_VARSIZE(item, VARHDRSZ + len + 1);

	*VARDATA(item) = flag;

	memcpy(VARDATA(item) + 1, str, len);

	return PointerGetDatum(item);
}

#ifndef DIR_CHAR
#define DIR_CHAR '/'
#endif

static cmsBool isabsolutepath(const char *path)
{
	char ThreeChars[4];

	if (path == NULL)
		return FALSE;
	if (path[0] == 0)
		return FALSE;

	strncpy(ThreeChars, path, 3);
	ThreeChars[3] = 0;

	if (ThreeChars[0] == DIR_CHAR)
		return TRUE;

#ifdef CMS_IS_WINDOWS_
	if (isalpha((int) ThreeChars[0]) && ThreeChars[1] == ':')
		return TRUE;
#endif
	return FALSE;
}

cmsBool BuildAbsolutePath(const char *relPath, const char *basePath, char *buffer, cmsUInt32Number MaxLen)
{
	const char *p;
	cmsUInt32Number len;

	/* Already absolute? */
	if (isabsolutepath(relPath)) {
		strncpy(buffer, relPath, MaxLen);
		buffer[MaxLen - 1] = 0;
		return TRUE;
	}

	/* No, search for the last folder separator in the base path. */
	for (p = basePath + strlen(basePath) - 1; p >= basePath; p--) {
		if (*p == DIR_CHAR)
			break;
	}

	if (p < basePath) {
		/* Base path has no separator: corrupted? */
		buffer[0] = 0;
		return FALSE;
	}

	len = (cmsUInt32Number)(p - basePath) + 1;
	if (len >= MaxLen)
		return FALSE;

	/* Copy the directory part of the base path. */
	memmove(buffer, basePath, len);
	buffer[len] = 0;

	/* Append the relative part. */
	strncat(buffer, relPath, MaxLen - len - 1);
	buffer[MaxLen - 1] = 0;

	return TRUE;
}

char *strndup2(const char *s1, const char *s2, char sep, size_t maxlen)
{
	size_t l1, l2, full, off, outlen;
	char *tmp, *result;

	if (s1 == NULL && s2 == NULL)
		return NULL;

	l1 = (s1 != NULL) ? strlen(s1) : 0;
	l2 = (s2 != NULL) ? strlen(s2) : 0;

	if (s1 != NULL && s2 != NULL)
		full = l1 + 1 + l2;	/* room for the separator */
	else
		full = l1 + l2;

	tmp = malloc(full + 1);
	if (tmp == NULL)
		return NULL;

	if (s1 != NULL && s2 != NULL) {
		memcpy(tmp, s1, l1);
		tmp[l1] = sep;
		memcpy(tmp + l1 + 1, s2, l2);
	} else if (s1 != NULL) {
		memcpy(tmp, s1, l1);
	} else {
		memcpy(tmp, s2, l2);
	}
	tmp[full] = '\0';

	/* If the (stitched) result is too long, cut it from the front. */
	if (full > maxlen) {
		off = full - maxlen;
		outlen = maxlen;
	} else {
		off = 0;
		outlen = full;
	}

	result = malloc(outlen + 1);
	if (result == NULL) {
		free(tmp);
		return NULL;
	}

	memcpy(result, tmp + off, outlen);
	result[outlen] = '\0';

	free(tmp);
	return result;
}

void swim_shuffle_members(struct swim *swim)
{
	struct mh_swim_table_t *members = swim->members;
	int i = 0;
	mh_int_t node;

	for (node = mh_first(members); node != mh_end(members);
	     node = mh_next(members, node), ++i) {
		struct swim_member *m = *mh_swim_table_node(members, node);
		int j = swim_scaled_rand(0, i);

		swim->shuffled[i] = swim->shuffled[j];
		swim->shuffled[j] = m;
	}
}

static void
CompatInterrupt(int signo)
{
	GNode *gn;

	if (curTarg != NULL && !Targ_Precious(curTarg)) {
		char *p1;
		char *file = Var_Value(TARGET, curTarg, &p1);

		if (!noExecute && eunlink(file) != -1)
			Error("*** %s removed", file);

		bmake_free(p1);

		/*
		 * Run .INTERRUPT only if hit with interrupt from the user.
		 * Commands are run with interrupts ignored.
		 */
		gn = Targ_FindNode(".INTERRUPT", TARG_NOCREATE);
		if (gn != NULL)
			Compat_Make(gn, gn);
	}

	exit(signo);
}

int iwpm_add_mapping_cb(struct sk_buff *skb, struct netlink_callback *cb)
{
	struct iwpm_sa_data *iwpm_addr;
	struct iwpm_nlmsg_request *nlmsg_request = NULL;
	struct nlattr *nltb[IWPM_NLA_RMANAGE_MAPPING_MAX];
	struct sockaddr_storage *local_sockaddr;
	struct sockaddr_storage *mapped_sockaddr;
	const char *msg_type;
	int ret = -EINVAL;

	msg_type = "Add Mapping response";
	if (iwpm_parse_nlmsg(cb, IWPM_NLA_RMANAGE_MAPPING_MAX,
			     resp_add_policy, nltb, msg_type))
		return ret;

	atomic_set(&echo_nlmsg_seq, cb->nlh->nlmsg_seq);

	nlmsg_request = iwpm_find_nlmsg_request(cb->nlh->nlmsg_seq);
	if (!nlmsg_request) {
		pr_info("%s: Could not find a matching request (seq = %u)\n",
			__func__, cb->nlh->nlmsg_seq);
		return ret;
	}
	iwpm_addr = nlmsg_request->req_buffer;
	local_sockaddr = (struct sockaddr_storage *)
			nla_data(nltb[IWPM_NLA_RMANAGE_ADDR]);
	mapped_sockaddr = (struct sockaddr_storage *)
			nla_data(nltb[IWPM_NLA_RMANAGE_MAPPED_LOC_ADDR]);

	if (iwpm_compare_sockaddr(local_sockaddr, &iwpm_addr->loc_addr)) {
		nlmsg_request->err_code = IWPM_USERSPACE_MAPPING_ERR;
		goto add_mapping_response_exit;
	}
	if (mapped_sockaddr->ss_family != local_sockaddr->ss_family) {
		pr_info("%s: Sockaddr family doesn't match the requested one\n",
			__func__);
		nlmsg_request->err_code = IWPM_USERSPACE_MAPPING_ERR;
		goto add_mapping_response_exit;
	}
	memcpy(&iwpm_addr->mapped_loc_addr, mapped_sockaddr,
	       sizeof(*mapped_sockaddr));
	iwpm_print_sockaddr(&iwpm_addr->loc_addr,
			    "add_mapping: Local sockaddr:");
	iwpm_print_sockaddr(&iwpm_addr->mapped_loc_addr,
			    "add_mapping: Mapped local sockaddr:");
	ret = 0;

add_mapping_response_exit:
	nlmsg_request->request_done = 1;
	/* always for the kernel client */
	nlmsg_request->err_code = ret ? nlmsg_request->err_code : 0;
	up(&nlmsg_request->sem);
	iwpm_free_nlmsg_request(&nlmsg_request->kref);
	return ret;
}

const char *kallsyms_lookup(unsigned long addr, unsigned long *symbolsize,
			    unsigned long *offset, char **modname, char *namebuf)
{
	const char *ret;

	namebuf[KSYM_NAME_LEN - 1] = 0;
	namebuf[0] = 0;

	if (is_ksym_addr(addr)) {
		unsigned long pos;

		pos = get_symbol_pos(addr, symbolsize, offset);
		/* Grab name */
		kallsyms_expand_symbol(get_symbol_offset(pos),
				       namebuf, KSYM_NAME_LEN);
		if (modname)
			*modname = NULL;
		return namebuf;
	}

	/* See if it's in a module or vmlinux + kallsyms holes. */
	ret = module_address_lookup(addr, symbolsize, offset,
				    modname, namebuf);
	if (!ret)
		ret = bpf_address_lookup(addr, symbolsize,
					 offset, modname, namebuf);

	if (!ret)
		ret = ftrace_mod_address_lookup(addr, symbolsize,
						offset, modname, namebuf);
	return ret;
}

void randomize()
{
	size_t i;

	/* Fisher-Yates shuffle: produces a uniformly random permutation. */
	for (i = count; i-- > 1;) {
		size_t j = (size_t)(rand() % (int)(i + 1));
		element_t tmp = elements[i];
		elements[i] = elements[j];
		elements[j] = tmp;
	}
}

int mac_get_irq_list (char *buf)
{
	int i, len = 0;
	irq_node_t *node;

	for (i = VIA1_SOURCE_BASE; i < NUM_MAC_SOURCES + 8; i++) {
		node = mac_irq_list[i];
		if (node == NULL)
			continue;

		len += sprintf(buf + len, "%3d: %10u ", i, mac_irq_count[i]);
		do {
			len += sprintf(buf + len, "%s\n", node->devname);
			node = node->next;
			if (node != NULL)
				len += sprintf(buf + len, "                 ");
		} while (node != NULL);
	}

	return len;
}

