char * strjoin (char **s1, char *s2)
{
	size_t l1, l2;
	char *result;

	l1 = (*s1 != NULL) ? strlen(*s1) : 0;
	l2 = (s2 != NULL) ? strlen(s2) : 0;

	result = malloc(l1 + l2 + 1);
	if (result == NULL)
		return NULL;

	if (*s1 != NULL)
		memcpy(result, *s1, l1);
	if (s2 != NULL)
		memcpy(result + l1, s2, l2);
	result[l1 + l2] = '\0';

	/* Free the old copy of *s1 and assign the new one. */
	free(*s1);
	*s1 = result;

	return *s1;
}

bool parse_option_str(const char *str, const char *option)
{
	while (*str) {
		if (!strncmp(str, option, strlen(option))) {
			str += strlen(option);
			if (!*str || *str == ',')
				return true;
		}

		while (*str && *str != ',')
			str++;

		if (*str == ',')
			str++;
	}

	return false;
}

int* loadArray(int* len)
{
	int n, i;
	int *arr;

	if (len == NULL)
		return NULL;

	*len = 0;

	if (scanf("%d", &n) != 1 || n <= 0)
		return NULL;

	arr = malloc((size_t)n * sizeof(*arr));
	if (arr == NULL)
		return NULL;

	for (i = 0; i < n; i++) {
		if (scanf("%d", &arr[i]) != 1) {
			free(arr);
			return NULL;
		}
	}

	*len = n;
	return arr;
}

