int do_page_fault(struct pt_regs *regs, unsigned long address, unsigned long error_code)
{
    struct task_struct *tsk = current;
    struct mm_struct *mm = tsk->mm;
    struct vm_area_struct *vma;
    int write = error_code & 2;

    /* If we are in an interrupt or have no user context, we must not
       take the fault. */
    if (in_interrupt() || !mm)
        return 1;

    down_read(&mm->mmap_sem);

    vma = find_vma(mm, address);
    if (!vma)
        goto bad_area;
    if (vma->vm_start <= address)
        goto good_area;
    if (!(vma->vm_flags & VM_GROWSDOWN))
        goto bad_area;
    if (expand_stack(vma, address))
        goto bad_area;

good_area:
    if (write) {
        if (!(vma->vm_flags & VM_WRITE))
            goto bad_area;
    } else {
        if (!(vma->vm_flags & (VM_READ | VM_EXEC)))
            goto bad_area;
    }

    if (handle_mm_fault(mm, vma, address, write) <= 0)
        goto bad_area;

    up_read(&mm->mmap_sem);
    return 0;

bad_area:
    up_read(&mm->mmap_sem);
    return 1;
}

