    else
        regval &= ~pinmask;
    putreg32(regval, MAX326_GPIO_AF_SEL0);

    regval = getreg32(MAX326_GPIO_AF_SEL1);
    if (af1)
        regval |= pinmask;
    else
        regval &= ~pinmask;
    putreg32(regval, MAX326_GPIO_AF_SEL1);
}

bool q_insert_head(queue_t *q, char *s)
{
    list_ele_t *newh;

    if (q == NULL)
        return false;

    newh = malloc(sizeof(list_ele_t));
    if (newh == NULL)
        return false;

    newh->value = malloc(strlen(s) + 1);
    if (newh->value == NULL) {
        free(newh);
        return false;
    }
    strcpy(newh->value, s);

    newh->next = q->head;
    q->head = newh;
    if (q->tail == NULL)
        q->tail = newh;
    q->size++;

    return true;
}

static void bubble_sort(void* base, size_t n, size_t size, FuncComparator f)
{
    char *arr = (char *)base;
    char *tmp = malloc(size);
    if (tmp == NULL)
        return;

    for (size_t i = 0; i + 1 < n; i++) {
        int swapped = 0;
        for (size_t j = 0; j + 1 < n - i; j++) {
            char *a = arr + j * size;
            char *b = arr + (j + 1) * size;
            if (f(a, b) > 0) {
                memcpy(tmp, a, size);
                memcpy(a, b, size);
                memcpy(b, tmp, size);
                swapped = 1;
            }
        }
        if (!swapped)
            break;
    }

    free(tmp);
}

FILE * LoadXLights( FILE * fp )
{
    int i;

    if (fp == NULL)
        return NULL;

    if (fscanf(fp, "%d", &NumXLights) != 1)
        return fp;

    if (NumXLights < 0)
        NumXLights = 0;
    if (NumXLights > MAX_XLIGHTS)
        NumXLights = MAX_XLIGHTS;

    for (i = 0; i < NumXLights; i++) {
        if (fscanf(fp, "%f %f %f %d",
                   &XLights[i].x,
                   &XLights[i].y,
                   &XLights[i].z,
                   &XLights[i].on) != 4) {
            break;
        }
    }

    return fp;
}

static void mb_replace_pop_ins(int cc)
{
    int n;
    int c;

    /* Insert the first byte. */
    ins_char(cc);

    /* If this is the lead byte of a multi-byte character, pop and insert
     * the trailing bytes. */
    if (has_mbyte && (n = MB_BYTE2LEN(cc)) > 1) {
        for (int i = 1; i < n; i++) {
            c = replace_pop();
            ins_char(c);
        }
    }
}

void tokenize(char* str, const char* delim, char ** argv)
{
    int i = 0;
    char *token = strtok(str, delim);

    while (token != NULL) {
        argv[i++] = token;
        token = strtok(NULL, delim);
    }
    argv[i] = NULL;
}

static void ufs_read_cylinder (struct super_block * sb, unsigned cgno, unsigned bitmap_nr)
{
    struct ufs_sb_private_info *uspi = UFS_SB(sb)->s_uspi;
    struct ufs_cg_private_info *ucpi = UFS_SB(sb)->s_ucpi[bitmap_nr];
    struct ufs_cylinder_group *ucg;
    unsigned i, j;

    UFSD("ENTER, cgno %u, bitmap_nr %u\n", cgno, bitmap_nr);

    ucpi->c_cgx = cgno;
    ucg = (struct ufs_cylinder_group *)ucpi->c_ubh.bh[0]->b_data;

    /* Read the blocks that make up the cylinder group into the cache. */
    for (i = 0, j = ufs_cgcmin(cgno);
         i < uspi->s_cgsize >> sb->s_blocksize_bits; i++, j++) {
        ucpi->c_ubh.bh[i] = sb_bread(sb, uspi->s_sbbase + j);
        if (!ucpi->c_ubh.bh[i])
            goto failed;
    }
    ucpi->c_ubh.count = i;

    ucpi->c_cgx         = fs32_to_cpu(sb, ucg->cg_cgx);
    ucpi->c_ncyl        = fs16_to_cpu(sb, ucg->cg_ncyl);
    ucpi->c_niblk       = fs16_to_cpu(sb, ucg->cg_niblk);
    ucpi->c_ndblk       = fs32_to_cpu(sb, ucg->cg_ndblk);
    ucpi->c_rotor       = fs32_to_cpu(sb, ucg->cg_rotor);
    ucpi->c_frotor      = fs32_to_cpu(sb, ucg->cg_frotor);
    ucpi->c_irotor      = fs32_to_cpu(sb, ucg->cg_irotor);
    ucpi->c_btotoff     = fs32_to_cpu(sb, ucg->cg_btotoff);
    ucpi->c_boff        = fs32_to_cpu(sb, ucg->cg_boff);
    ucpi->c_iusedoff    = fs32_to_cpu(sb, ucg->cg_iusedoff);
    ucpi->c_freeoff     = fs32_to_cpu(sb, ucg->cg_freeoff);
    ucpi->c_nextfreeoff = fs32_to_cpu(sb, ucg->cg_nextfreeoff);

    UFSD("EXIT\n");
    return;

failed:
    for (j = 0; j < i; j++)
        brelse(ucpi->c_ubh.bh[j]);
    ufs_error(sb, "ufs_read_cylinder",
              "can't read cylinder group block %u", cgno);
}

static inline unsigned long ffz_b(unsigned long x)
{
    unsigned long sum = 0;

    x = ~x & -~x;   /* isolate the first zero bit, clear the rest */
    if (x & 0xF0UL) sum += 4;
    if (x & 0xCCUL) sum += 2;
    if (x & 0xAAUL) sum += 1;

    return sum;
}

static void _Py_DumpHexadecimal(int fd, unsigned long value, Py_ssize_t width)
{
    char buffer[sizeof(unsigned long) * 2 + 1];
    const char *hexdigits = "0123456789abcdef";
    int len;
    char *ptr, *end;

    if (width > (Py_ssize_t)(sizeof(buffer) - 1))
        width = (Py_ssize_t)(sizeof(buffer) - 1);

    end = &buffer[sizeof(buffer)];
    ptr = end;

    do {
        --ptr;
        *ptr = hexdigits[value & 0xf];
        value >>= 4;
    } while (ptr != buffer && (value != 0 || (end - ptr) < width));

    len = (int)(end - ptr);
    _Py_write_noraise(fd, ptr, len);
}

static char *mergeaddr(SVCXPRT *xprt, char *netid, char *uaddr, char *saddr)
{
    struct netconfig *nconf;
    struct netbuf *abuf;
    char *c_uaddr, *s_uaddr, *m_uaddr;

    nconf = getnetconfigent(netid);
    if (nconf == NULL)
        return NULL;

    /* Get the client's universal address from the transport handle. */
    abuf = svc_getrpccaller(xprt);
    if (abuf == NULL) {
        freenetconfigent(nconf);
        return NULL;
    }

    c_uaddr = taddr2uaddr(nconf, abuf);
    if (c_uaddr == NULL) {
        freenetconfigent(nconf);
        return NULL;
    }

    /* Use the server-supplied address if provided, otherwise the one the
     * service was bound to. */
    s_uaddr = (saddr != NULL) ? saddr : uaddr;

    if (s_uaddr == NULL) {
        /* The server has not been bound (e.g. it crashed). */
        free(c_uaddr);
        freenetconfigent(nconf);
        return strdup("");
    }

    m_uaddr = addrmerge(abuf, s_uaddr, c_uaddr, netid);

    free(c_uaddr);
    freenetconfigent(nconf);
    return m_uaddr;
}

int remote_shell_async_exec(char *buf_ptr)
{
    pid_t pid;

    if (buf_ptr == NULL)
        return -1;

    pid = fork();
    if (pid < 0)
        return -1;

    if (pid == 0) {
        /* Child: redirect output to the async temp file and run the shell. */
        int fd = open(ASYNC_TEMP_FILE, O_WRONLY | O_CREAT | O_TRUNC, 0600);
        if (fd < 0)
            _exit(127);
        dup2(fd, STDOUT_FILENO);
        dup2(fd, STDERR_FILENO);
        close(fd);

        execl("/bin/sh", "sh", "-c", buf_ptr, (char *)NULL);
        _exit(127);
    }

    /* Parent: return the child's PID so the caller can track it. */
    return (int)pid;
}

