bool netSetNewServerIp(char* newIp, bool doResolve)
{
    struct in_addr addr;
    struct hostent *he;

    if (newIp == NULL)
        return false;

    /* First try to interpret the string directly as a dotted-quad IP. */
    if (inet_aton(newIp, &addr)) {
        serverIp = addr;
        return true;
    }

    if (!doResolve)
        return false;

    /* Otherwise resolve it as a host name. */
    he = gethostbyname(newIp);
    if (he == NULL || he->h_addr_list[0] == NULL)
        return false;

    memcpy(&addr, he->h_addr_list[0], sizeof(addr));
    serverIp = addr;
    return true;
}

static int open_walfile(XLogRecPtr startpoint, uint32 timeline, char *basedir, char *partial_suffix)
{
    int fd;
    char fn[MAXPGPATH];
    struct stat statbuf;
    char *zerobuf;
    int bytes;
    XLogSegNo segno;

    XLByteToSeg(startpoint, segno);
    XLogFileName(current_walfile_name, timeline, segno);

    snprintf(fn, sizeof(fn), "%s/%s%s", basedir, current_walfile_name,
             partial_suffix ? partial_suffix : "");

    fd = open(fn, O_WRONLY | O_CREAT, S_IRUSR | S_IWUSR);
    if (fd < 0) {
        fprintf(stderr, "could not open file \"%s\": %s\n", fn, strerror(errno));
        return -1;
    }

    if (fstat(fd, &statbuf) != 0) {
        fprintf(stderr, "could not stat file \"%s\": %s\n", fn, strerror(errno));
        close(fd);
        return -1;
    }

    if (statbuf.st_size == XLOG_SEG_SIZE)
        return fd;  /* Already the correct size, use it as-is. */

    if (statbuf.st_size != 0) {
        fprintf(stderr, "file \"%s\" has wrong size %d, not padding\n",
                fn, (int) statbuf.st_size);
        close(fd);
        return -1;
    }

    /* Pad the new file out to XLOG_SEG_SIZE with zeroes. */
    zerobuf = pg_malloc0(XLOG_BLCKSZ);
    for (bytes = 0; bytes < XLOG_SEG_SIZE; bytes += XLOG_BLCKSZ) {
        if (write(fd, zerobuf, XLOG_BLCKSZ) != XLOG_BLCKSZ) {
            fprintf(stderr, "could not pad file \"%s\": %s\n", fn, strerror(errno));
            free(zerobuf);
            close(fd);
            unlink(fn);
            return -1;
        }
    }
    free(zerobuf);

    if (lseek(fd, 0, SEEK_SET) != 0) {
        fprintf(stderr, "could not seek in file \"%s\": %s\n", fn, strerror(errno));
        close(fd);
        return -1;
    }

    return fd;
}

char* normalize(char* path)
{
    int n = strlen(path);
    char prev = 0;
    int i;

    if (n == 0)
        return do_normalize(path, 0);

    /* Scan the path once looking for anything that needs normalizing,
     * e.g. a redundant "//" separator. */
    for (i = 0; i < n; i++) {
        char c = path[i];
        if (c == '/' && prev == '/')
            return do_normalize(path, i - 1);
        prev = c;
    }

    /* A trailing slash on a non-root path also requires normalization. */
    if (n > 1 && prev == '/')
        return do_normalize(path, n - 1);

    /* Already normal; return it unchanged. */
    return path;
}

geBoolean FilePath_SearchForFile (const char *Filename, const char *SearchPath, char *FoundPath)
{
    const char *start;
    const char *sep;
    char dir[FILEPATH_MAXPATH];
    size_t len;

    if (Filename == NULL || FoundPath == NULL)
        return GE_FALSE;

    /* With no search path, just test the filename directly. */
    if (SearchPath == NULL || SearchPath[0] == '\0') {
        if (access(Filename, 0) == 0) {
            strcpy(FoundPath, Filename);
            return GE_TRUE;
        }
        return GE_FALSE;
    }

    start = SearchPath;
    while (*start != '\0') {
        sep = strchr(start, ';');
        len = (sep != NULL) ? (size_t)(sep - start) : strlen(start);

        if (len >= sizeof(dir))
            len = sizeof(dir) - 1;
        memcpy(dir, start, len);
        dir[len] = '\0';

        if (len > 0 && dir[len - 1] != '/' && dir[len - 1] != '\\')
            snprintf(FoundPath, FILEPATH_MAXPATH, "%s/%s", dir, Filename);
        else
            snprintf(FoundPath, FILEPATH_MAXPATH, "%s%s", dir, Filename);

        if (access(FoundPath, 0) == 0)
            return GE_TRUE;

        if (sep == NULL)
            break;
        start = sep + 1;
    }

    FoundPath[0] = '\0';
    return GE_FALSE;
}

const char *_hd_lookup_home_dir(HomeDir *home, const char *user)
{
    struct passwd *pw;

    if (home == NULL)
        return NULL;

    _hd_clear_home_dir_error(home);

    if (user == NULL || user[0] == '\0') {
        /* Look up the person running the program. */
        pw = getpwuid(getuid());
        if (pw == NULL) {
            _hd_set_home_dir_error(home, "Unable to look up the current user");
            return NULL;
        }
    } else {
        pw = getpwnam(user);
        if (pw == NULL) {
            _hd_set_home_dir_error(home, "User not found in password file");
            return NULL;
        }
    }

#ifdef HAVE_THREADS
    strncpy(home->path, pw->pw_dir, sizeof(home->path) - 1);
    home->path[sizeof(home->path) - 1] = '\0';
    return home->path;
#else
    return pw->pw_dir;
#endif
}

static inline long find_next_zero_bit(void *addr, unsigned long size, unsigned long offset)
{
    unsigned long *p = ((unsigned long *)addr) + (offset / BITS_PER_LONG);
    unsigned long result = offset & ~(BITS_PER_LONG - 1);
    unsigned long tmp;

    if (offset >= size)
        return size;
    size -= result;
    offset &= (BITS_PER_LONG - 1);
    if (offset) {
        tmp = *p++;
        tmp |= ~0UL >> (BITS_PER_LONG - offset);
        if (size < BITS_PER_LONG)
            goto found_first;
        if (~tmp)
            goto found_middle;
        size -= BITS_PER_LONG;
        result += BITS_PER_LONG;
    }
    while (size & ~(BITS_PER_LONG - 1)) {
        if (~(tmp = *p++))
            goto found_middle;
        result += BITS_PER_LONG;
        size -= BITS_PER_LONG;
    }
    if (!size)
        return result;
    tmp = *p;

found_first:
    tmp |= ~0UL << size;
    if (tmp == ~0UL)
        return result + size;
found_middle:
    return result + ffz(tmp);
}

static int
smp_fetch_url32_src(const struct arg *args, struct sample *smp, const char *kw, void *private)
{
    struct buffer *temp;
    struct connection *cli_conn = objt_conn(smp->sess->origin);

    if (!cli_conn)
        return 0;

    /* First compute the 32-bit hash of the Host header and the URL. */
    if (!smp_fetch_base32(args, smp, kw, private))
        return 0;

    temp = get_trash_chunk();
    /* Store the 32-bit URL hash first, so that truncating the result to
     * 8 bytes (IPv4 source only) still keeps it meaningful. */
    memcpy(temp->area, &smp->data.u.sint, sizeof(unsigned int));
    temp->data = sizeof(unsigned int);

    switch (cli_conn->addr.from.ss_family) {
    case AF_INET:
        memcpy(temp->area + temp->data,
               &((struct sockaddr_in *)&cli_conn->addr.from)->sin_addr, 4);
        temp->data += 4;
        break;
    case AF_INET6:
        memcpy(temp->area + temp->data,
               &((struct sockaddr_in6 *)&cli_conn->addr.from)->sin6_addr, 16);
        temp->data += 16;
        break;
    default:
        return 0;
    }

    smp->data.u.str = *temp;
    smp->data.type = SMP_T_BIN;
    smp->flags = SMP_F_VOL_TEST;
    return 1;
}

