void rndini ( int seed1, int seed2 )
{
    /* If both seeds are zero, seed from the current time to produce a
     * non-deterministic sequence. */
    if (seed1 == 0 && seed2 == 0) {
        time_t now = time(NULL);
        seed1 = (int)(now & 0x7fffffff);
        seed2 = (int)((now ^ 0x5DEECE66DL) & 0x7fffffff);
    }

    /* Neither seed may be zero, which would degenerate the generator. */
    if (seed1 == 0)
        seed1 = 1;
    if (seed2 == 0)
        seed2 = 1;

    rnd_seed1 = (unsigned long)seed1;
    rnd_seed2 = (unsigned long)seed2;
    rnd_initialized = 1;
}

