static int hw_breakpoint_pending(unsigned long addr, unsigned int fsr,
				 struct pt_regs *regs)
{
	int ret = 0;
	u32 dscr;

	/* We must be called with interrupts disabled. */
	ARM_DBG_READ(c0, c1, 0, dscr);

	/* Determine the reason for the debug event and dispatch it. */
	switch (ARM_DSCR_MOE(dscr)) {
	case ARM_ENTRY_BREAKPOINT:
		breakpoint_handler(addr, regs);
		break;
	case ARM_ENTRY_ASYNC_WATCHPOINT:
		WARN(1, "Asynchronous watchpoint exception taken. "
			"Debugging results may be unreliable\n");
		/* Fall through */
	case ARM_ENTRY_SYNC_WATCHPOINT:
		watchpoint_handler(addr, fsr, regs);
		break;
	default:
		ret = 1; /* Unhandled fault. */
	}

	return ret;
}

int mutils_binary_to_hex_buf(unsigned char *in, int in_len, char *out, int *out_len)
{
	static const char hex[] = "0123456789abcdef";
	int i;

	if (in == NULL || out == NULL || out_len == NULL || in_len < 0)
		return -1;

	/* Need room for in_len*2 hex chars plus a NUL terminator. */
	if (*out_len <= in_len * 2)
		return -1;

	for (i = 0; i < in_len; i++) {
		out[i * 2]     = hex[(in[i] >> 4) & 0x0f];
		out[i * 2 + 1] = hex[in[i] & 0x0f];
	}
	out[in_len * 2] = '\0';

	*out_len = in_len * 2;
	return in_len * 2;
}

