int FileExists(char *fname)
{
	char *clobber;

	if (access(fname, F_OK) != 0)
		return 0;

	clobber = getenv("imclobber");
	if (clobber != NULL && strcmp(clobber, "yes") == 0) {
		if (remove(fname) != 0) {
