/* Configuration describing the layout of the input table.  These are set up
   by the caller when the column mapping is determined. */
extern char *g_words[];		/* tokenized fields of the current line */
extern int   g_ra_col;		/* column index holding the RA value    */
extern int   g_dec_col;		/* column index holding the DEC value   */
extern int   g_id_col;		/* first column index of the ID value   */
extern int   g_id_ncol;		/* number of columns forming the ID     */

int vot_parseTableLine(char *idlist, int nwords, double *ra, double *dec)
{
	int i;

	if (idlist == NULL || ra == NULL || dec == NULL || nwords <= 0)
		return -1;

	/* Extract the RA and DEC values from their columns. */
	*ra  = (g_ra_col  >= 0 && g_ra_col  < nwords) ? atof(g_words[g_ra_col])  : 0.0;
	*dec = (g_dec_col >= 0 && g_dec_col < nwords) ? atof(g_words[g_dec_col]) : 0.0;

	/* Concatenate the id column(s) into a single space-delimited string. */
	idlist[0] = '\0';
	for (i = 0; i < g_id_ncol; i++) {
		int col = g_id_col + i;

		if (col < 0 || col >= nwords)
			break;
		if (i > 0)
			strcat(idlist, " ");
		strcat(idlist, g_words[col]);
	}

	return 0;
}

#include <stdio.h>
#include <openssl/md5.h>

Source_Status md5(char *hash, FILE *fd)
{
	MD5_CTX ctx;
	unsigned char digest[MD5_DIGEST_LENGTH];
	unsigned char buf[4096];
	size_t n;
	int i;

	if (hash == NULL || fd == NULL)
		return ERROR;

	if (MD5_Init(&ctx) != 1)
		return ERROR;

	while ((n = fread(buf, 1, sizeof(buf), fd)) > 0)
		MD5_Update(&ctx, buf, n);

	if (ferror(fd))
		return ERROR;

	MD5_Final(digest, &ctx);

	for (i = 0; i < MD5_DIGEST_LENGTH; i++)
		sprintf(&hash[i * 2], "%02x", digest[i]);
	hash[MD5_DIGEST_LENGTH * 2] = '\0';

	return DONE;
}

