	struct list_head list;
} element_t;

bool q_insert_head(struct list_head *head, char *s)
{
	element_t *node;
	size_t len;

	if (!head || !s)
		return false;

	node = malloc(sizeof(*node));
	if (!node)
		return false;

	len = strlen(s) + 1;
	node->value = malloc(len);
	if (!node->value) {
		free(node);
		return false;
	}
	memcpy(node->value, s, len);

	list_add(&node->list, head);
	return true;
}

#include <stdio.h>

static int compareOutput(char *cmd, char *expected)
{
	FILE *cmd_fp;
	FILE *exp_fp;
	int a, b;
	int result = 1;

	cmd_fp = popen(cmd, "r");
	if (cmd_fp == NULL)
		return 0;

	exp_fp = fopen(expected, "r");
	if (exp_fp == NULL) {
		pclose(cmd_fp);
		return 0;
	}

	do {
		a = fgetc(cmd_fp);
		b = fgetc(exp_fp);
		if (a != b) {
			result = 0;
			break;
		}
	} while (a != EOF);

	pclose(cmd_fp);
	fclose(exp_fp);

	return result;
}

static int package_satisfies_dependency(int package, int depend_type)
{
	int status_num = search_status_hashtable(name_hashtable[package_hashtable[package]->name]);

	/* Status could be unset if the package is a pure virtual provides,
	 * which cannot satisfy any dependency by itself. */
	if (status_hashtable[status_num] == NULL)
		return 0;

	switch (depend_type) {
	case EDGE_PRE_DEPENDS:
		return get_status(status_num, 3) == search_name_hashtable("installed");
	case EDGE_DEPENDS:
		return get_status(status_num, 1) == search_name_hashtable("install");
	}
	return 0;
}

ret_t
http2d_buffer_encode_md5_digest (http2d_buffer_t *buf)
{
	int                i;
	struct MD5Context  context;
	unsigned char      digest[16];
	static const char  hex[] = "0123456789abcdef";

	MD5Init (&context);
	MD5Update (&context, (unsigned char *) buf->buf, buf->len);
	MD5Final (digest, &context);

	/* Ensure room for 32 hex characters plus a trailing NUL. */
	http2d_buffer_ensure_size (buf, 33);

	for (i = 0; i < 16; i++) {
		buf->buf[(i << 1)]     = hex[digest[i] >> 4];
		buf->buf[(i << 1) + 1] = hex[digest[i] & 0x0f];
	}
	buf->buf[32] = '\0';
	buf->len     = 32;

	return ret_ok;
}

