}

#include <stdlib.h>

ACPI_STATUS
AcpiDbConvertToBuffer (
	char            *String,
	ACPI_OBJECT     *Object)
{
	UINT32           i;
	UINT32           Length;
	UINT8           *Buffer;
	char            *This;
	char            *Next;

	/* First pass: count the number of buffer elements */

	Length = 0;
	This = String;
	while (*This) {
		while (*This == ' ' || *This == ',')
			This++;
		if (*This == 0)
			break;
		Length++;
		while (*This && *This != ' ' && *This != ',')
			This++;
	}

	if (Length == 0)
		return AE_BAD_PARAMETER;

	Buffer = ACPI_ALLOCATE (Length);
	if (!Buffer)
		return AE_NO_MEMORY;

	/* Second pass: convert each token to a byte value */

	This = String;
	for (i = 0; i < Length; i++) {
		while (*This == ' ' || *This == ',')
			This++;
		Buffer[i] = (UINT8) strtoul (This, &Next, 16);
		This = Next;
	}

	Object->Type = ACPI_TYPE_BUFFER;
	Object->Buffer.Pointer = Buffer;
	Object->Buffer.Length = Length;

	return AE_OK;
}

/* The cosine look-up table stores values in descending order. */
extern const unsigned int cosine_table[];

static int binarySearch(unsigned int value, unsigned int N)
{
	int low = 0;
	int high = (int)N - 1;
	int mid = 0;

	while (low <= high) {
		mid = low + (high - low) / 2;

		if (cosine_table[mid] == value)
			return mid;
		else if (cosine_table[mid] > value)
			low = mid + 1;	/* cosine decreases as the angle grows */
		else
			high = mid - 1;
	}

	/* No exact match; return the closest index found. */
	return low;
}

