void writeCString(unsigned char** pptr, const char* string)
{
	int len = (int) strlen(string);
	unsigned char *ptr = *pptr;

	/* Write the two-byte big-endian length prefix. */
	*ptr++ = (unsigned char)(len >> 8);
	*ptr++ = (unsigned char)(len & 0xFF);

	memcpy(ptr, string, len);
	ptr += len;

	*pptr = ptr;
}

int32_t _ipu_disp_set_window_pos(struct ipu_soc *ipu, ipu_channel_t channel,
				int16_t x_pos, int16_t y_pos)
{
	u32 reg;
	uint32_t flow;
	uint32_t dp_srm_shift;

	if ((channel == MEM_FG_SYNC) || (channel == MEM_FG_ASYNC0)) {
		flow = DP_SYNC;
		dp_srm_shift = 3;
	} else if (channel == MEM_FG_ASYNC1) {
		flow = DP_ASYNC0;
		dp_srm_shift = 5;
	} else {
		return -EINVAL;
	}

	ipu_dp_set_window_pos(ipu, flow, x_pos, y_pos);

	/* Set the source of the SRM update and trigger it. */
	reg = ipu_cm_read(ipu, IPU_SRM_PRI2) & ~(0x03 << dp_srm_shift);
	reg |= (0x01 << dp_srm_shift);
	ipu_cm_write(ipu, reg, IPU_SRM_PRI2);

	return 0;
}

