} string;

void str_append (string* dst, string suffix)
{
	size_t new_len;
	char  *buf;

	if (dst == NULL || suffix.len == 0 || suffix.data == NULL)
		return;

	new_len = dst->len + suffix.len;

	buf = malloc (new_len + 1);
	if (buf == NULL)
		return;

	if (dst->data != NULL) {
		memcpy (buf, dst->data, dst->len);
		free (dst->data);
	}
	memcpy (buf + dst->len, suffix.data, suffix.len);
	buf[new_len] = '\0';

	dst->data = buf;
	dst->len  = new_len;
}

static void search_wiener_finish(const RestorationTileLimits *limits,
		const Av1PixelRect *tile_rect, int32_t rest_unit_idx, void *priv)
{
	WienerSearchCtx *ctx = (WienerSearchCtx *)priv;
	RestUnitSearchInfo *rusi = &ctx->rusi[rest_unit_idx];
	const MACROBLOCK *const x = ctx->x;
	int64_t bits_none, bits_wiener;
	double cost_none, cost_wiener;

	(void)limits;
	(void)tile_rect;

	/* SSE for the "no restoration" and "wiener" candidates was computed
	   during the search pass and cached in the rusi entry. */
	const int64_t sse_none = rusi->sse[RESTORE_NONE];
	const int64_t sse_wiener = rusi->sse[RESTORE_WIENER];

	bits_none = x->wiener_restore_cost[0];
	bits_wiener = x->wiener_restore_cost[1] +
		(count_wiener_bits(&rusi->wiener, &ctx->ref_wiener) << AV1_PROB_COST_SHIFT);

	cost_none = RDCOST_DBL(x->rdmult, bits_none >> 4, sse_none);
	cost_wiener = RDCOST_DBL(x->rdmult, bits_wiener >> 4, sse_wiener);

	if (cost_wiener < cost_none) {
		rusi->best_rtype[RESTORE_WIENER - 1] = RESTORE_WIENER;
		rusi->sse[RESTORE_SWITCHABLE] = sse_wiener;
		ctx->ref_wiener = rusi->wiener;
		ctx->bits += bits_wiener;
	} else {
		rusi->best_rtype[RESTORE_WIENER - 1] = RESTORE_NONE;
		rusi->sse[RESTORE_SWITCHABLE] = sse_none;
		ctx->bits += bits_none;
	}
}

