#include <stdlib.h>
#include <SDL2/SDL.h>

struct MotionReturn {
	float x;
	float y;
};

extern SDL_Joystick *joysticks[];

struct MotionReturn controllerJoyMotion(int controller)
{
	struct MotionReturn motion = { 0.0f, 0.0f };
	const int deadzone = 8000;
	const float maxAxis = 32767.0f;
	int rawX, rawY;

	rawX = SDL_JoystickGetAxis(joysticks[controller], 0);
	rawY = SDL_JoystickGetAxis(joysticks[controller], 1);

	/* Apply the deadzone. */
	if (abs(rawX) < deadzone)
		rawX = 0;
	if (abs(rawY) < deadzone)
		rawY = 0;

	motion.x = (float)rawX / maxAxis;
	motion.y = (float)rawY / maxAxis;

	/* Clamp to the -1.0 .. 1.0 range. */
	if (motion.x > 1.0f)
		motion.x = 1.0f;
	else if (motion.x < -1.0f)
		motion.x = -1.0f;

	if (motion.y > 1.0f)
		motion.y = 1.0f;
	else if (motion.y < -1.0f)
		motion.y = -1.0f;

	return motion;
}

