#include "safe-ctype.h"

static int
dlang_hexdigit (char c)
{
  if (ISDIGIT (c))
    return c - '0';
  if (c >= 'a' && c <= 'f')
    return c - 'a' + 10;
  if (c >= 'A' && c <= 'F')
    return c - 'A' + 10;
  return 0;
}

static const char *
dlang_value (string *decl, const char *mangled, const char *name, char type)
{
  if (mangled == NULL || *mangled == '\0')
    return NULL;

  switch (type)
    {
    case 'n':			/* null */
      string_append (decl, "null");
      break;

    case 'b':			/* bool */
      string_append (decl, (*mangled++ == '0') ? "false" : "true");
      break;

    case 'i':			/* integer */
      if (*mangled == 'N')
	{
	  string_append (decl, "-");
	  mangled++;
	}
      if (! ISDIGIT (*mangled))
	return NULL;
      while (ISDIGIT (*mangled))
	string_appendn (decl, mangled++, 1);
      break;

    case 'e':			/* real / floating point */
      while (ISXDIGIT (*mangled) || *mangled == 'N'
	     || *mangled == 'P' || *mangled == '.')
	string_appendn (decl, mangled++, 1);
      break;

    case 'a':			/* character array (string) */
    case 'w':
    case 'd':
      {
	unsigned long len = 0;

	if (! ISDIGIT (*mangled))
	  return NULL;
	while (ISDIGIT (*mangled))
	  len = len * 10 + (*mangled++ - '0');
	if (*mangled != '_')
	  return NULL;
	mangled++;

	string_append (decl, "\"");
	while (len-- > 0 && ISXDIGIT (mangled[0]) && ISXDIGIT (mangled[1]))
	  {
	    char c = (char) ((dlang_hexdigit (mangled[0]) << 4)
			     | dlang_hexdigit (mangled[1]));
	    string_appendn (decl, &c, 1);
	    mangled += 2;
	  }
	string_append (decl, "\"");
      }
      break;

    default:
      return NULL;
    }

  (void) name;
  return mangled;
}

static void
add_struct_fields (struct type *type, VEC (char_ptr) **output,
		   char *fieldname, int namelen)
{
  int i;

  CHECK_TYPEDEF (type);
  for (i = 0; i < TYPE_NFIELDS (type); ++i)
    {
      if (i < TYPE_N_BASECLASSES (type))
	add_struct_fields (TYPE_BASECLASS (type, i), output,
			   fieldname, namelen);
      else if (TYPE_FIELD_NAME (type, i))
	{
	  if (TYPE_FIELD_NAME (type, i)[0] != '\0')
	    {
	      if (! strncmp (TYPE_FIELD_NAME (type, i), fieldname, namelen))
		VEC_safe_push (char_ptr, *output,
			       xstrdup (TYPE_FIELD_NAME (type, i)));
	    }
	  else if (TYPE_CODE (TYPE_FIELD_TYPE (type, i)) == TYPE_CODE_UNION)
	    {
	      /* Recurse into anonymous unions.  */
	      add_struct_fields (TYPE_FIELD_TYPE (type, i), output,
				 fieldname, namelen);
	    }
	}
    }

  for (i = TYPE_NFN_FIELDS (type) - 1; i >= 0; --i)
    {
      const char *name = TYPE_FN_FIELDLIST_NAME (type, i);

      if (name && ! strncmp (name, fieldname, namelen))
	{
	  if (! computed_type_name (name))
	    VEC_safe_push (char_ptr, *output, xstrdup (name));
	}
    }
}

int
smbc_urlencode(char *dest, char *src, int max_dest_len)
{
    static const char hex[] = "0123456789ABCDEF";

    while (*src != '\0' && max_dest_len >= 3) {
        if ((*src < '0' && *src != '-' && *src != '.') ||
            (*src > '9' && *src < 'A') ||
            (*src > 'Z' && *src < 'a' && *src != '_') ||
            (*src > 'z')) {
            *dest++ = '%';
            *dest++ = hex[(*src >> 4) & 0x0f];
            *dest++ = hex[*src & 0x0f];
            max_dest_len -= 3;
        } else {
            *dest++ = *src;
            max_dest_len--;
        }
        src++;
    }

    *dest = '\0';
    max_dest_len--;

    return max_dest_len;
}

