#include <string.h>
#include <stdlib.h>
#include <errno.h>

typedef unsigned int uint32;

/* Convert an UTF-8 string into its precomposed (Form C) equivalent. */
extern int CodeSet_Utf8FormDToFormC(const char *bufIn, unsigned int sizeIn,
                                    char **bufOut, unsigned long *sizeOut);
/* Convert a precomposed name into the HGFS cross platform form (in place). */
extern void HgfsConvertToCrossPlatformName(char *name);
/* Undo the HGFS escaping of a cross platform name (in place); returns
   the resulting length, or a negative value on failure. */
extern int HgfsEscape_Undo(char *name, unsigned int bufSize);

int
HgfsNameToWireEncoding(const char *bufIn, uint32 bufInSize,
                       char *bufOut, uint32 bufOutSize)
{
    char *precomposed = NULL;
    unsigned long precomposedLen = 0;
    int outSize;

    if (bufIn == NULL || bufOut == NULL || bufOutSize == 0) {
        return -EINVAL;
    }

    /* 1) Convert the input string into precomposed (Form C) form. */
    if (!CodeSet_Utf8FormDToFormC(bufIn, bufInSize,
                                  &precomposed, &precomposedLen)) {
        return -EINVAL;
    }

    if (precomposedLen >= bufOutSize) {
        free(precomposed);
        return -ENAMETOOLONG;
    }

    memcpy(bufOut, precomposed, precomposedLen);
    bufOut[precomposedLen] = '\0';
    free(precomposed);

    /* 2) Convert the precomposed string to the cross platform form. */
    HgfsConvertToCrossPlatformName(bufOut);

    /* 3) Unescape the cross platform string. */
    outSize = HgfsEscape_Undo(bufOut, bufOutSize);
    if (outSize < 0) {
        return -EINVAL;
    }

    return outSize;
}

/* Hash function for symbol table lookup, as specified by the
   System V ABI.  Do not change this. */
unsigned long
elf_hash(const char *name)
{
    const unsigned char *p = (const unsigned char *) name;
    unsigned long h = 0;
    unsigned long g;

    while (*p != '\0') {
        h = (h << 4) + *p++;
        g = h & 0xf0000000UL;
        if (g != 0)
            h ^= g >> 24;
        h &= ~g;
    }

    return h;
}

