extern char *grub_strcpy(char *dest, const char *src);

char *
grub_resolve_relative_path(const char *base, const char *path)
{
    char *result;
    grub_size_t baselen;

    /* An absolute path is returned verbatim. */
    if (path[0] == '/')
        return grub_strdup(path);

    baselen = grub_strlen(base);
    result = grub_malloc(baselen + grub_strlen(path) + 2);
    if (result == NULL)
        return NULL;

    grub_memcpy(result, base, baselen);
    if (baselen == 0 || result[baselen - 1] != '/')
        result[baselen++] = '/';
    grub_strcpy(result + baselen, path);

    return result;
}

#include <fcntl.h>
#include <unistd.h>
#include <sys/types.h>

static int copyfile(char *outfile, char *infile)
{
    int in, out;
    ssize_t nread;
    char buf[8192];

    in = open(infile, O_RDONLY);
    if (in < 0)
        return -1;

    out = open(outfile, O_WRONLY | O_CREAT | O_TRUNC, 0644);
    if (out < 0) {
        close(in);
        return -1;
    }

    while ((nread = read(in, buf, sizeof(buf))) > 0) {
        char *p = buf;
        ssize_t left = nread;

        while (left > 0) {
            ssize_t nwritten = write(out, p, (size_t) left);
            if (nwritten < 0) {
                close(in);
                close(out);
                return -1;
            }
            left -= nwritten;
            p += nwritten;
        }
    }

    if (nread < 0) {
        close(in);
        close(out);
        return -1;
    }

    close(in);
    if (close(out) < 0)
        return -1;

    return 0;
}

