#define PW_MESSAGE_AUTHENTICATOR 80

static int add_msg_auth_attr(rc_handle *rh, char *secret,
                             AUTH_HDR *auth, int total_length)
{
    unsigned char *ptr;
    unsigned char digest[EVP_MAX_MD_SIZE];
    unsigned int md_len = 0;
    int total_length_new;

    (void) rh;

    /* Append the attribute header and 16 zero bytes for the digest. */
    ptr = (unsigned char *) auth + total_length;
    *ptr++ = PW_MESSAGE_AUTHENTICATOR;
    *ptr++ = 18;                 /* 2 (header) + 16 (digest) */
    memset(ptr, 0, 16);

    total_length_new = total_length + 18;
    auth->length = htons((unsigned short) total_length_new);

    /* Compute HMAC-MD5 over the whole packet with the attribute zeroed. */
    HMAC(EVP_md5(), secret, (int) strlen(secret),
         (unsigned char *) auth, (size_t) total_length_new,
         digest, &md_len);

    memcpy(ptr, digest, 16);

    return total_length_new;
}

