typedef enum {
    EST_ERR_NONE = 0,
    EST_ERR_INVALID_PARAMETERS,
    EST_ERR_MALLOC,
    EST_ERR_X509_ATTR
} EST_ERROR;

EST_ERROR
est_add_challengePassword(const char *base64_ptr, int b64_len,
                          char **new_csr, int *pop_len)
{
    ASN1_STRING *pwd;
    X509_ATTRIBUTE *attr;
    unsigned char *der = NULL;
    int der_len;

    if (base64_ptr == NULL || new_csr == NULL || pop_len == NULL)
        return EST_ERR_INVALID_PARAMETERS;

    pwd = ASN1_STRING_new();
    if (pwd == NULL)
        return EST_ERR_MALLOC;

    if (!ASN1_STRING_set(pwd, base64_ptr, b64_len)) {
        ASN1_STRING_free(pwd);
        return EST_ERR_MALLOC;
    }

    /* Build the PKCS#9 challengePassword attribute; the attribute now
       owns the ASN1_STRING and will free it. */
    attr = X509_ATTRIBUTE_create(NID_pkcs9_challengePassword,
                                 V_ASN1_PRINTABLESTRING, pwd);
    if (attr == NULL) {
        ASN1_STRING_free(pwd);
        return EST_ERR_MALLOC;
    }

    der_len = i2d_X509_ATTRIBUTE(attr, &der);
    if (der_len <= 0) {
        X509_ATTRIBUTE_free(attr);
        return EST_ERR_X509_ATTR;
    }

    *new_csr = (char *) der;
    *pop_len = der_len;

    X509_ATTRIBUTE_free(attr);
    return EST_ERR_NONE;
}

