#include <stdlib.h>

unsigned int
ZX7Compress(const unsigned char *srcData, unsigned int inLength,
            unsigned char **outData)
{
    unsigned char *out;
    unsigned int outCap, outLen, i;
    unsigned int flagPos;
    unsigned char flagMask;

    if (outData == NULL)
        return 0;

    outCap = inLength + inLength / 8 + 16;
    out = malloc(outCap);
    if (out == NULL) {
        *outData = NULL;
        return 0;
    }

    /* First 3 bytes hold the 24-bit uncompressed size. */
    out[0] = (unsigned char) (inLength & 0xff);
    out[1] = (unsigned char) ((inLength >> 8) & 0xff);
    out[2] = (unsigned char) ((inLength >> 16) & 0xff);
    outLen = 3;

    flagPos = 0;
    flagMask = 0;

    i = 0;
    while (i < inLength) {
        unsigned int bestLen = 0, bestOff = 0;
        unsigned int windowStart = (i >= 2176u) ? i - 2176u : 0u;
        unsigned int j;

        for (j = windowStart; j < i; j++) {
            unsigned int len = 0;
            while (i + len < inLength && len < 255u &&
                   srcData[j + len] == srcData[i + len])
                len++;
            if (len > bestLen) {
                bestLen = len;
                bestOff = i - j;
            }
        }

        if (outLen + 4 > outCap) {
            unsigned char *tmp;
            outCap *= 2;
            tmp = realloc(out, outCap);
            if (tmp == NULL) {
                free(out);
                *outData = NULL;
                return 0;
            }
            out = tmp;
        }

        if (flagMask == 0) {
            flagPos = outLen;
            out[outLen++] = 0;
            flagMask = 0x80;
        }

        if (bestLen >= 3) {
            out[flagPos] |= flagMask;            /* 1 = match */
            out[outLen++] = (unsigned char) (bestOff & 0xff);
            out[outLen++] = (unsigned char) ((bestOff >> 8) & 0xff);
            out[outLen++] = (unsigned char) bestLen;
            i += bestLen;
        } else {
            out[outLen++] = srcData[i];          /* 0 = literal */
            i++;
        }

        flagMask >>= 1;
    }

    *outData = out;
    return outLen;
}

static struct platform_device *
dfl_fme_create_region(struct dfl_feature_platform_data *pdata,
                      struct platform_device *mgr,
                      struct platform_device *br, int port_id)
{
    struct dfl_fme_region_pdata region_pdata = { 0 };
    struct platform_device *region;
    int ret;

    region_pdata.mgr = mgr;
    region_pdata.br = br;
    region_pdata.region_id = port_id;

    region = platform_device_alloc(DFL_FPGA_FME_REGION, PLATFORM_DEVID_AUTO);
    if (!region)
        return ERR_PTR(-ENOMEM);

    region->dev.parent = &pdata->dev->dev;

    ret = platform_device_add_data(region, &region_pdata,
                                   sizeof(region_pdata));
    if (ret)
        goto free_region_exit;

    ret = platform_device_add(region);
    if (ret)
        goto free_region_exit;

    return region;

free_region_exit:
    platform_device_put(region);
    return ERR_PTR(ret);
}

