int
copy_buffer(lame_internal_flags *gfc, unsigned char *buffer, int size,
            int mp3data)
{
    Bit_stream_struc *const bs = &gfc->bs;
    int minimum = bs->buf_byte_idx + 1;

    if (minimum <= 0)
        return 0;

    if (size != 0 && minimum > size)
        return -1;              /* supplied buffer is too small */

    memcpy(buffer, bs->buf, (size_t) minimum);
    bs->buf_byte_idx = -1;
    bs->buf_bit_idx = 0;

    if (mp3data) {
        /* Real mp3 frame data: keep the running CRC and byte count up
           to date so the VBR tags can be written correctly. */
        UpdateMusicCRC(&gfc->nMusicCRC, buffer, minimum);
        gfc->VBR_seek_table.nBytesWritten += minimum;
    }

    return minimum;
}

