extern int initialize_mem_bw_resctrl(struct resctrl_val_param *param,
                                     pid_t bm_pid);
extern int measure_vals(struct resctrl_val_param *param, pid_t bm_pid);

int resctrl_val(char **benchmark_cmd, struct resctrl_val_param *param)
{
    pid_t bm_pid;
    int ret;

    if (benchmark_cmd == NULL || benchmark_cmd[0] == NULL || param == NULL)
        return -1;

    bm_pid = fork();
    if (bm_pid < 0)
        return -1;

    if (bm_pid == 0) {
        /* Child: become the benchmark. */
        execvp(benchmark_cmd[0], benchmark_cmd);
        _exit(127);
    }

    /* Parent: set up the resource control group and take measurements. */
    ret = initialize_mem_bw_resctrl(param, bm_pid);
    if (ret)
        goto out;

    ret = measure_vals(param, bm_pid);

out:
    kill(bm_pid, SIGKILL);
    waitpid(bm_pid, NULL, 0);
    return ret;
}

