#define RAD_SEM_KEY_BASE 0x52414400  /* 'RAD\0' */

typedef struct rad_semaphore {
    int semid;
    int index;
} *SEM_ID;

SEM_ID
radSemCreate(int semIndex, int count)
{
    union semun {
        int val;
        struct semid_ds *buf;
        unsigned short *array;
    } arg;
    key_t key;
    int semid;
    SEM_ID sem;

    key = (key_t) (RAD_SEM_KEY_BASE + semIndex);

    /* Try to create the semaphore exclusively first. */
    semid = semget(key, 1, IPC_CREAT | IPC_EXCL | 0666);
    if (semid >= 0) {
        arg.val = count;
        if (semctl(semid, 0, SETVAL, arg) < 0)
            return NULL;
    } else if (errno == EEXIST) {
        /* Already exists: just attach to it. */
        semid = semget(key, 1, 0666);
        if (semid < 0)
            return NULL;
    } else {
        return NULL;
    }

    sem = malloc(sizeof(*sem));
    if (sem == NULL)
        return NULL;

    sem->semid = semid;
    sem->index = semIndex;
    return sem;
}

