ssize_t
jm_getenv_nonnegative_int_or_percent(const char *envvar, ssize_t base_amount)
{
    const char *value = getenv(envvar);
    char *end;
    long parsed;

    if (value == NULL || *value == '\0')
        return -1;

    errno = 0;
    parsed = strtol(value, &end, 10);
    if (end == value || parsed < 0 || errno != 0) {
        fprintf(stderr, "invalid value for %s: %s\n", envvar, value);
        exit(EXIT_FAILURE);
    }

    if (*end == '%') {
        if (*(end + 1) != '\0') {
            fprintf(stderr, "invalid percentage for %s: %s\n", envvar, value);
            exit(EXIT_FAILURE);
        }
        return (ssize_t) ((parsed * base_amount) / 100);
    }

    if (*end != '\0') {
        fprintf(stderr, "invalid value for %s: %s\n", envvar, value);
        exit(EXIT_FAILURE);
    }

    return (ssize_t) parsed;
}

