void
realloc_by_amount(const char *base_metric_name, size_t size,
                  ssize_t amount, bool amount_is_random)
{
    void *ptr, *tmp;
    size_t new_size;
    struct timespec start, end;
    double elapsed;
    char metric_name[256];

    ptr = malloc(size);
    if (ptr == NULL)
        return;

    if (amount_is_random) {
        ssize_t bound = (amount > 0) ? amount : 1;
        amount = (ssize_t) (rand() % bound);
    }

    if (amount < 0 && (size_t) (-amount) > size)
        new_size = 0;
    else
        new_size = (size_t) ((ssize_t) size + amount);

    clock_gettime(CLOCK_MONOTONIC, &start);
    tmp = realloc(ptr, new_size);
    clock_gettime(CLOCK_MONOTONIC, &end);

    if (tmp != NULL)
        ptr = tmp;

    elapsed = (double) (end.tv_sec - start.tv_sec) +
              (double) (end.tv_nsec - start.tv_nsec) / 1e9;

    snprintf(metric_name, sizeof(metric_name), "%s_size_%zu_amount_%zd",
             base_metric_name, size, amount);
    printf("%s: %.9f seconds\n", metric_name, elapsed);

    free(ptr);
}

struct div_result {
    unsigned long result_high;
    unsigned long result_low;
};

void div128_by_32(unsigned long dividend_high, unsigned long dividend_low,
                  unsigned divisor, struct div_result *dr)
{
    unsigned long a, b, c, d;
    unsigned long w, x, y, z;
    unsigned long ra, rb, rc;

    a = dividend_high >> 32;
    b = dividend_high & 0xffffffffUL;
    c = dividend_low >> 32;
    d = dividend_low & 0xffffffffUL;

    w = a / divisor;
    ra = a % divisor;

    x = ((ra << 32) + b) / divisor;
    rb = ((ra << 32) + b) % divisor;

    y = ((rb << 32) + c) / divisor;
    rc = ((rb << 32) + c) % divisor;

    z = ((rc << 32) + d) / divisor;

    dr->result_high = (w << 32) + x;
    dr->result_low = (y << 32) + z;
}

