typedef struct topic {
    char *text;
    int keylen;
} Topic;

void
AddLine(char *string, Topic *topic)
{
    size_t oldlen, addlen;
    char *newtext;

    if (topic->text == NULL) {
        /* First line: keylen is the distance to the first whitespace. */
        char *p = string;

        while (*p != '\0' && !isspace((unsigned char) *p))
            p++;
        topic->keylen = (int) (p - string);
        oldlen = 0;
    } else {
        oldlen = strlen(topic->text);
    }

    addlen = strlen(string);
    newtext = realloc(topic->text, oldlen + addlen + 1);
    if (newtext == NULL)
        return;

    memcpy(newtext + oldlen, string, addlen + 1);
    topic->text = newtext;
}

