#define KORE_RESULT_OK    1

int
http_request_read_url_encoded_values(struct http_request *req)
{
    char *body, *pair, *saveptr;

    if (req == NULL || req->http_body == NULL)
        return KORE_RESULT_ERROR;

    body = kore_strdup(req->http_body);
    if (body == NULL)
        return KORE_RESULT_ERROR;

    for (pair = strtok_r(body, "&", &saveptr);
         pair != NULL;
         pair = strtok_r(NULL, "&", &saveptr)) {
        char *eq, *name, *value;

        eq = strchr(pair, '=');
        if (eq == NULL)
            continue;

        *eq = '\0';
        name = pair;
        value = eq + 1;

        http_argument_urldecode(name);
        http_argument_urldecode(value);
        http_argument_add(req, name, value);
    }

    kore_free(body);
    return KORE_RESULT_OK;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

char *bitmap_to_bitstring(char name, unsigned long *bm, unsigned int min_bit,
                          unsigned int max_bit)
{
    const unsigned int bits_per_word = sizeof(unsigned long) * 8;
    size_t cap = 64, len = 0;
    char *out;
    char tmp[32];
    unsigned int bit;

    out = malloc(cap);
    if (out == NULL)
        return NULL;

    len = (size_t) snprintf(out, cap, "%c:", name);

    for (bit = min_bit; bit <= max_bit; bit++) {
        unsigned int word = bit / bits_per_word;
        unsigned int off = bit % bits_per_word;

        if (bm[word] & (1UL << off)) {
            int n = snprintf(tmp, sizeof(tmp), "%s%u",
                             (len > 2) ? "," : " ", bit);
            if (n < 0) {
                free(out);
                return NULL;
            }

            if (len + (size_t) n + 1 > cap) {
                char *nout;
                while (len + (size_t) n + 1 > cap)
                    cap *= 2;
                nout = realloc(out, cap);
                if (nout == NULL) {
                    free(out);
                    return NULL;
                }
                out = nout;
            }

            memcpy(out + len, tmp, (size_t) n + 1);
            len += (size_t) n;
        }
    }

    return out;
}

