krb5_error_code
strength_init(krb5_context ctx, const char *dictionary,
              krb5_pwqual_moddata *moddata)
{
    krb5_pwqual_moddata data;
    char *filename = NULL;
    int fd;

    (void) ctx;

    *moddata = NULL;

    data = calloc(1, sizeof(*data));
    if (data == NULL)
        return ENOMEM;

    /* The caller supplies the dictionary path without the .pwd suffix. */
    if (asprintf(&filename, "%s.pwd", dictionary) < 0) {
        free(data);
        return ENOMEM;
    }

    /* Ensure the dictionary file exists and is readable. */
    fd = open(filename, O_RDONLY);
    if (fd < 0) {
        krb5_error_code ret = errno;

        free(filename);
        free(data);
        return ret;
    }
    close(fd);

    data->dictionary = filename;
    *moddata = data;
    return 0;
}

static PyObject *
make_fielditem (struct type *type, int i, enum gdbpy_iter_kind kind)
{
    switch (kind) {
    case iter_items:
    {
        PyObject *key, *value, *item;

        key = field_name (type, i);
        if (key == NULL)
            return NULL;

        value = convert_field (type, i);
        if (value == NULL) {
            Py_DECREF (key);
            return NULL;
        }

        item = PyTuple_New (2);
        if (item == NULL) {
            Py_DECREF (key);
            Py_DECREF (value);
            return NULL;
        }

        PyTuple_SET_ITEM (item, 0, key);
        PyTuple_SET_ITEM (item, 1, value);
        return item;
    }

    case iter_keys:
        return field_name (type, i);

    case iter_values:
        return convert_field (type, i);

    default:
        return NULL;
    }
}

