FILE *
gp_open_scratch_file(const char *prefix, char *fname, const char *mode)
{
    const char *tmpdir;
    int fd;
    FILE *fp;

    tmpdir = getenv("TMPDIR");
    if (tmpdir == NULL || *tmpdir == '\0')
        tmpdir = "/tmp";

    if (snprintf(fname, gp_file_name_sizeof, "%s/%sXXXXXX",
                 tmpdir, prefix) >= gp_file_name_sizeof)
        return NULL;

    fd = mkstemp(fname);
    if (fd < 0)
        return NULL;

    fp = fdopen(fd, mode);
    if (fp == NULL) {
        close(fd);
        unlink(fname);
        return NULL;
    }

    return fp;
}

