#include <string.h>

typedef struct deark_struct deark;

#define DE_MOF_BASE_ONLY   0x1U
#define DE_MOF_NO_SEP      0x2U

static char *make_output_filename(deark *c, const char *dirname, const char *fn,
	const char *suffix, unsigned int flags)
{
	const char *base;
	size_t len;
	char *out;
	char *s;

	(void)c;

	if(!fn)
		return NULL;

	base = fn;

	/* 0x1: use base filename only, discard any leading directory. */
	if(flags & DE_MOF_BASE_ONLY) {
		const char *p1 = strrchr(fn, '/');
		const char *p2 = strrchr(fn, '\\');
		const char *p = (p2 > p1) ? p2 : p1;
		if(p)
			base = p + 1;
		dirname = NULL;
	}

	len = strlen(base) + 1;
	if(dirname)
		len += strlen(dirname) + 1;
	if(suffix)
		len += strlen(suffix);

	out = malloc(len);
	if(!out)
		return NULL;
	out[0] = '\0';

	if(dirname) {
		strcat(out, dirname);
		strcat(out, "/");
	}
	strcat(out, base);
	if(suffix)
		strcat(out, suffix);

	/* 0x2: sanitize away any path separators. */
	if(flags & DE_MOF_NO_SEP) {
		for(s = out; *s; s++) {
			if(*s == '/' || *s == '\\')
				*s = '_';
		}
	}

	if(out[0] == '\0') {
		free(out);
		return NULL;
	}
	return out;
}

