	if (!fn || !fn[0])
		return NULL;

	/* Absolute path is used verbatim, relative names live under /run. */
	if (fn[0] == '/')
		snprintf(path, sizeof(path), "%s", fn);
	else
		snprintf(path, sizeof(path), "/run/%s", fn);

	for (svc = svc_iterator(1); svc; svc = svc_iterator(0)) {
		if (!svc->pidfile[0])
