	struct tm *tm;
	int years_back;
	char *name;

	name = malloc(32);
	if (!name)
		return NULL;

	now = time(NULL);

	/* Shift the timestamp between 0 and 5 years into the past. */
	years_back = rand() % 6;
	now -= (time_t)years_back * 365 * 24 * 60 * 60;

	tm = localtime(&now);
	if (!tm) {
		free(name);
		return NULL;
	}

	snprintf(name, 32, "%04d-%02d-%02d.mp4",
		tm->tm_year + 1900, tm->tm_mon + 1, tm->tm_mday);

	return name;
}

