#include <sys/socket.h>
#include <linux/if_tun.h>

int opentunnel(const char *ifname, const char *ifdesc, int setflags)
{
	struct ifreq ifr;
	int fd;
	int sock;
	int saved;

	(void)ifdesc;

	fd = open("/dev/net/tun", O_RDWR);
	if (fd < 0)
		return -1;

	memset(&ifr, 0, sizeof(ifr));
	ifr.ifr_flags = IFF_TUN | IFF_NO_PI;
	if (ifname)
		strncpy(ifr.ifr_name, ifname, IFNAMSIZ - 1);

	if (ioctl(fd, TUNSETIFF, &ifr) < 0) {
		saved = errno;
		close(fd);
		errno = saved;
		return -1;
	}

	if (setflags) {
		sock = socket(AF_INET, SOCK_DGRAM, 0);
		if (sock < 0) {
			saved = errno;
			close(fd);
			errno = saved;
			return -1;
		}

		if (ioctl(sock, SIOCGIFFLAGS, &ifr) < 0) {
			saved = errno;
			close(sock);
			close(fd);
			errno = saved;
			return -1;
		}

		ifr.ifr_flags |= IFF_UP | IFF_RUNNING;
		if (ioctl(sock, SIOCSIFFLAGS, &ifr) < 0) {
			saved = errno;
			close(sock);
			close(fd);
			errno = saved;
			return -1;
		}

		close(sock);
	}

	return fd;
}

