typedef struct Col_Word_ *Col_Word;

int Col_StringBufferAppendChar(Col_Word strbuf, char c);

void WriteUInt(Col_Word strbuf, uintptr_t value, unsigned int radix)
{
	static const char digits[] = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ";
	char buf[sizeof(uintptr_t) * 8 + 1];
	int i = (int)sizeof(buf);

	if (radix < 2)
		radix = 10;
	else if (radix > 36)
		radix = 36;

	/* Emit digits least-significant first into a scratch buffer. */
	do {
		buf[--i] = digits[value % radix];
		value /= radix;
	} while (value != 0);

	/* Append them in canonical (most-significant first) order. */
	for (; i < (int)sizeof(buf); i++)
		Col_StringBufferAppendChar(strbuf, buf[i]);
}

#include <sys/types.h>
#include <stddef.h>

u_char *asn_parse_length(u_char *data, u_long *length)
{
	u_char lengthbyte;

	if (!data || !length)
		return NULL;

	lengthbyte = *data;

	if (lengthbyte & 0x80) {
		int nbytes = lengthbyte & 0x7f;

		/* Indefinite form and oversized lengths are rejected. */
		if (nbytes == 0 || nbytes > (int)sizeof(u_long))
			return NULL;

		data++;
		*length = 0;
		while (nbytes-- > 0) {
			*length = (*length << 8) | (u_long)*data;
			data++;
		}
	} else {
		/* Short form: length is the byte itself. */
		*length = (u_long)lengthbyte;
		data++;
	}

	return data;
}

