#include <linux/errno.h>
#include <linux/jiffies.h>
#include <linux/interrupt.h>

/* Provided by the NCR5380 core. */
struct Scsi_Host;
struct NCR5380_hostdata {
	unsigned int poll_loops;
};
#define shost_priv(h)       ((struct NCR5380_hostdata *)((h)->hostdata))
extern int NCR5380_read(int reg);

static int NCR5380_poll_politely2(struct Scsi_Host *instance,
	int reg1, int bit1, int val1,
	int reg2, int bit2, int val2, int wait)
{
	struct NCR5380_hostdata *hostdata = shost_priv(instance);
	unsigned long n = hostdata->poll_loops;
	unsigned long deadline = jiffies + wait;

	/* Fast path: a tight spin for the common quick response. */
	do {
		if ((NCR5380_read(reg1) & bit1) == val1)
			return 0;
		if ((NCR5380_read(reg2) & bit2) == val2)
			return 0;
		cpu_relax();
	} while (n--);

	/* Slow path: yield the CPU between checks until the deadline. */
	do {
		if ((NCR5380_read(reg1) & bit1) == val1)
			return 0;
		if ((NCR5380_read(reg2) & bit2) == val2)
			return 0;
		if (!in_interrupt())
			usleep_range(8, 10);
		else
			udelay(4);
	} while (time_is_after_jiffies(deadline));

	return -ETIMEDOUT;
}

typedef enum {
	ATMO_Operator_None = 0,
	ATMO_Operator_Set,
	ATMO_Operator_Add,
	ATMO_Operator_Subtract,
	ATMO_Operator_Multiply,
	ATMO_Operator_Divide
} ATMO_Operator_t;

char __ATMO_PerformOperationChar(char c, ATMO_Operator_t operation, float operand)
{
	switch (operation) {
	case ATMO_Operator_Set:
		return (char)operand;
	case ATMO_Operator_Add:
		return (char)(c + operand);
	case ATMO_Operator_Subtract:
		return (char)(c - operand);
	case ATMO_Operator_Multiply:
		return (char)(c * operand);
	case ATMO_Operator_Divide:
		if (operand == 0.0f)
			return c;
		return (char)(c / operand);
	case ATMO_Operator_None:
	default:
		return c;
	}
}

#include <stdint.h>

typedef struct {
	uint16_t r[8];
	uint16_t flags;
	int mask_interrupts;
	int icount;
} cp1610_state;

extern uint16_t cp1610_readmem16(uint16_t addr);

#define CP_S  0x80
#define CP_Z  0x40
#define CP_OV 0x20
#define CP_C  0x10

static void cp1610_sdbd_cmpi(cp1610_state *cpustate, int d)
{
	uint16_t data;
	uint32_t temp;

	/* SDBD: fetch the immediate as two successive bytes (low then high). */
	data = cp1610_readmem16(cpustate->r[7]) & 0xff;
	cpustate->r[7]++;
	data |= (cp1610_readmem16(cpustate->r[7]) & 0xff) << 8;
	cpustate->r[7]++;

	/* CMPI: compute Rd - data and set flags without storing the result. */
	temp = (uint32_t)cpustate->r[d] - (uint32_t)data;

	cpustate->flags &= ~(CP_S | CP_Z | CP_OV | CP_C);

	if ((temp & 0xffff) == 0)
		cpustate->flags |= CP_Z;
	if (temp & 0x8000)
		cpustate->flags |= CP_S;
	if (!(temp & 0x10000))
		cpustate->flags |= CP_C;
	if (((cpustate->r[d] ^ data) & (cpustate->r[d] ^ (uint16_t)temp)) & 0x8000)
		cpustate->flags |= CP_OV;

	cpustate->icount -= 10;
}

