typedef struct {
	char *dl_text;   /* formatted display text */
	int   dl_size;   /* allocated size */
} DLINE_S;

typedef struct {
	DLINE_S *dline;   /* array of formatted lines */
	int      dl_count;
} CONTEXT_S;

static int scroll_add_listmode(CONTEXT_S *context, int total)
{
	int i;
	int seen = 0;

	if (!context || !context->dline)
		return 1;

	for (i = 0; i < context->dl_count && seen < total; i++) {
		char *old = context->dline[i].dl_text;
		char *pos;
		char *newtext;
		size_t oldlen;
		size_t head;

		if (!old)
			continue;

		/* Look for the marker where a "[ ] " prefix must be inserted. */
		pos = strchr(old, '\001');
		if (!pos)
			continue;

		oldlen = strlen(old);
		newtext = malloc(oldlen + 5);
		if (!newtext)
			return 1;   /* out of memory: force a full reformat */

		head = (size_t)(pos - old);
		memcpy(newtext, old, head);
		memcpy(newtext + head, "[ ] ", 4);
		strcpy(newtext + head + 4, pos);

		free(context->dline[i].dl_text);
		context->dline[i].dl_text = newtext;
		context->dline[i].dl_size = (int)(oldlen + 5);
		seen++;
	}

	return 0;
}

