#define USER_API_MAX_CMDS   8
#define AT_OK               0
#define AT_ERROR            1

extern char _user_api_recv_buffer[];
extern char _user_api_send_buffer[];

/* Decode a single AT command; returns AT_OK/AT_ERROR. */
extern int user_api_decode_cmd(const char *cmd);

int user_api_decode_data(int length)
{
	int i = 0;
	int decoded = 0;
	char cmd[128];

	if (length <= 0)
		return AT_ERROR;

	while (i < length) {
		int j = 0;

		/* Gather characters up to a command terminator. */
		while (i < length &&
		       _user_api_recv_buffer[i] != '\r' &&
		       _user_api_recv_buffer[i] != '\n' &&
		       j < (int)sizeof(cmd) - 1) {
			cmd[j++] = _user_api_recv_buffer[i++];
		}
		cmd[j] = '\0';

		/* Skip the terminator(s). */
		while (i < length &&
		       (_user_api_recv_buffer[i] == '\r' ||
		        _user_api_recv_buffer[i] == '\n')) {
			i++;
		}

		if (j == 0)
			continue;

		if (user_api_decode_cmd(cmd) != AT_OK)
			return AT_ERROR;

		decoded++;
		if (decoded >= USER_API_MAX_CMDS)
			break;
	}

	return decoded;
}

