extern char *skip_spaces(char *);
extern char *xstrdup(const char *);
extern void error(const char *, ...);
extern struct symtab_and_line ada_exception_sal(void);

static struct symtab_and_line
ada_decode_assert_location(char *args, char **addr_string,
	char **cond_string, const struct breakpoint_ops **ops)
{
	/* Advance past any leading whitespace. */
	args = skip_spaces(args);

	/* An optional condition is introduced by the "if" keyword. */
	if (strncmp(args, "if", 2) == 0 &&
	    (isspace((unsigned char)args[2]) || args[2] == '\0')) {
		args += 2;
		args = skip_spaces(args);
		if (args[0] == '\0')
			error("Condition missing after `if' keyword");
		*cond_string = xstrdup(args);
	} else if (args[0] != '\0') {
		error("Junk at end of arguments.");
	} else {
		*cond_string = NULL;
	}

	/* The real breakpoint is placed on the assertion-failure handler. */
	*addr_string = xstrdup("__gnat_debug_raise_assert_failure");
	*ops = &catch_exception_breakpoint_ops;

	return ada_exception_sal();
}

#include <stdint.h>
#include <stddef.h>

void McuUtility_strcatNum32s(uint8_t *dst, size_t dstSize, int32_t val)
{
	uint8_t numbuf[12];
	size_t pos = sizeof(numbuf);
	size_t len = 0;
	uint32_t uval;
	int negative = 0;

	if (dstSize == 0)
		return;

	if (val < 0) {
		negative = 1;
		uval = (uint32_t)(-(val + 1)) + 1u;   /* safe negation of INT32_MIN */
	} else {
		uval = (uint32_t)val;
	}

	/* Build the decimal representation from least-significant digit up. */
	do {
		numbuf[--pos] = (uint8_t)('0' + (uval % 10u));
		uval /= 10u;
	} while (uval != 0u && pos > 0);

	if (negative && pos > 0)
		numbuf[--pos] = (uint8_t)'-';

	/* Find the current end of the destination string. */
	while (len < dstSize && dst[len] != '\0')
		len++;

	/* Append digits, leaving room for the terminator. */
	while (pos < sizeof(numbuf) && (len + 1) < dstSize)
		dst[len++] = numbuf[pos++];

	dst[len] = '\0';
}

