#include <string.h>

typedef struct {
	char *start;   /* delimiter string */
	int   len;     /* delimiter length */
} Delim;

/* Parse the ANSI escape codes in [str, end) updating state accordingly. */
extern int parse_ansi_state(const char *str, const char *end, int state);

int list2ansi(int *arr, int *prior_state, int maxlen, char *list, const Delim *sep)
{
	int count = 0;
	int state;
	char *p;

	if (!list || maxlen <= 0)
		return 0;

	state = prior_state ? *prior_state : 0;
	p = list;

	while (*p && count < maxlen) {
		char *word = p;
		char *next = strstr(p, sep->start);

		/* Record the ANSI state at the start of this word. */
		arr[count] = state;

		if (next) {
			state = parse_ansi_state(word, next, state);
			p = next + sep->len;
		} else {
			state = parse_ansi_state(word, word + strlen(word), state);
			p = word + strlen(word);
		}

		count++;
	}

	/* Trailing fencepost: ANSI state after the final word. */
	arr[count] = state;

	if (prior_state)
		*prior_state = state;

	return count;
}

