static int unobscure_hexval(int c){
  if( c>='0' && c<='9' ) return c - '0';
  if( c>='a' && c<='f' ) return c - 'a' + 10;
  if( c>='A' && c<='F' ) return c - 'A' + 10;
  return 0;
}

char *unobscure(const char *zIn){
  size_t i, n, j;
  unsigned char salt;
  char *zOut;

  if( zIn==0 ) return 0;
  n = strlen(zIn);

  /* Count leading hexadecimal digits. */
  for(i=0; i<n && isxdigit((unsigned char)zIn[i]); i++){}

  /* If the input is not entirely hexadecimal, has an odd number of
  ** digits, or is too short to have been produced by obscure(), just
  ** return a plain copy of the input (equivalent to strdup()). */
  if( i!=n || n<2 || (n & 1)!=0 ){
    zOut = malloc(n + 1);
    if( zOut ) memcpy(zOut, zIn, n + 1);
    return zOut;
  }

  zOut = malloc((n - 2)/2 + 1);
  if( zOut==0 ) return 0;

  salt = (unsigned char)(unobscure_hexval(zIn[0])*16 + unobscure_hexval(zIn[1]));
  for(i=2, j=0; i<n; i+=2, j++){
    unsigned char x = (unsigned char)(unobscure_hexval(zIn[i])*16
                                      + unobscure_hexval(zIn[i+1]));
    zOut[j] = (char)(x - salt - (unsigned char)j);
  }
  zOut[j] = 0;
  return zOut;
}

