struct hostent *Get_Hostbyname(const char *name){
  struct hostent *h;
  char *buf;
  size_t i, len;

  if( name==NULL ) return NULL;

  h = gethostbyname(name);
  if( h!=NULL ) return h;

  len = strlen(name);
  buf = malloc(len + 1);
  if( buf==NULL ) return NULL;

  /* Try an all lower case version of the name. */
  for(i=0; i<len; i++) buf[i] = (char)tolower((unsigned char)name[i]);
  buf[len] = '\0';
  h = gethostbyname(buf);

  /* Finally try an all upper case version. */
  if( h==NULL ){
    for(i=0; i<len; i++) buf[i] = (char)toupper((unsigned char)name[i]);
    buf[len] = '\0';
    h = gethostbyname(buf);
  }

  free(buf);
  return h;
}

struct value *
ada_array_bound (struct value *arr, int n, int which)
{
  struct type *arr_type = value_type (arr);

  if (TYPE_CODE (arr_type) == TYPE_CODE_PTR)
    {
      arr = value_ind (arr);
      arr_type = value_type (arr);
    }
  arr_type = check_typedef (arr_type);

  if (ada_is_packed_array_type (arr_type))
    return ada_array_bound (decode_packed_array (arr), n, which);
  else if (ada_is_simple_array_type (arr_type))
    {
      struct type *type = ada_index_type (arr_type, n);

      if (type == NULL)
        return value_from_longest (builtin_type_int, (LONGEST) 0);
      else
        return value_from_longest
          (type, ada_array_bound_from_type (arr_type, n, which));
    }
  else
    return desc_one_bound (desc_bounds (arr), n, which);
}

#include <stdlib.h>

void copy_brand(struct brand **dest, struct brand *source)
{
  struct brand *tail = NULL;
  struct brand *node;

  *dest = NULL;

  while (source != NULL) {
    node = malloc(sizeof(struct brand));
    if (node == NULL)
      return;

    *node = *source;          /* copy every field of the current brand */
    node->next = NULL;

    if (tail == NULL)
      *dest = node;           /* first element becomes the new head */
    else
      tail->next = node;

    tail = node;
    source = source->next;
  }
}

