#include <string.h>
#include <errno.h>
#include <stdbool.h>

typedef int (*check_association_t)(const char *value, const char *msg_obj,
                                   void *check_private);

static int _keystore_remove_association(struct properties *key_props,
                                        const char *property,
                                        const char *delvalue,
                                        const char *msg_obj,
                                        check_association_t check_func,
                                        void *check_private)
{
    char *value, *newvalue, *tok, *saveptr;
    bool removed = false;
    int rc = 0;

    value = properties_get(key_props, property);
    if (value == NULL)
        return 0;

    /* The rebuilt value can never be longer than the original one. */
    newvalue = malloc(strlen(value) + 1);
    if (newvalue == NULL) {
        free(value);
        return -ENOMEM;
    }
    newvalue[0] = '\0';

    tok = strtok_r(value, ",", &saveptr);
    while (tok != NULL) {
        if (strcmp(tok, delvalue) == 0) {
            removed = true;
            if (check_func != NULL) {
                rc = check_func(tok, msg_obj, check_private);
                if (rc != 0)
                    goto out;
            }
        } else {
            if (newvalue[0] != '\0')
                strcat(newvalue, ",");
            strcat(newvalue, tok);
        }
        tok = strtok_r(NULL, ",", &saveptr);
    }

    if (!removed) {
        rc = -ENOENT;
        goto out;
    }

    if (newvalue[0] == '\0')
        rc = properties_remove(key_props, property);
    else
        rc = properties_set(key_props, property, newvalue);

out:
    free(newvalue);
    free(value);
    return rc;
}

