static int
swim_uri_to_addr(const char *uri, struct sockaddr_in *addr,
                 const char *prefix)
{
    struct sockaddr_storage storage;

    if (sio_uri_to_addr(uri, (struct sockaddr *) &storage) != 0)
        return -1;

    /* SWIM only supports IPv4 addresses. */
    if (storage.ss_family != AF_INET) {
