    }

    memcpy(addr, &storage, sizeof(*addr));
    return 0;
}

#include <string.h>

extern void handleAction(const char *action, const char *requestID,
                         const char *arg, struct lws *wsi);

static void parseInput(char *input, size_t inputLen, struct lws *wsi)
{
    char *saveptr = NULL;
    char *action;
    char *requestID;
    char *arg;

    if (input == NULL || inputLen == 0)
        return;

    /* Guarantee NUL termination inside the provided buffer. */
    input[inputLen - 1] = '\0';

    /* Input is newline separated: action, requestID, then the payload. */
    action = strtok_r(input, "\n", &saveptr);
    if (action == NULL)
        return;

    requestID = strtok_r(NULL, "\n", &saveptr);
    if (requestID == NULL)
        return;

    arg = strtok_r(NULL, "\n", &saveptr);

    handleAction(action, requestID, arg, wsi);
}

