#include <string.h>

/* Base name of the input file, used to build output file names. */
extern char infilebasename[];

static char *outimage(char *img)
{
    char name[256];
    char filename[512];
    char *p;
    char *data;
    char *end;
    FILE *fp;

    /* Expect the line to start with "name=". */
    if (strncmp(img, "name=", 5) != 0)
        return img;
    img += 5;

    /* Read the image name up to end of line. */
    p = name;
    while (*img && *img != '\n' && (size_t)(p - name) < sizeof(name) - 1)
        *p++ = *img++;
    *p = '\0';

    /* The image data begins on the next line. */
    if (*img == '\n')
        img++;
    data = img;

    /* The image data extends to the following newline. */
    end = data;
    while (*end && *end != '\n')
        end++;

    snprintf(filename, sizeof(filename), "%s_%s.jpg", infilebasename, name);
    fp = fopen(filename, "wb");
    if (fp != NULL) {
        fwrite(data, 1, (size_t)(end - data), fp);
        fclose(fp);
    }

    /* Return a pointer to the following line. */
    if (*end == '\n')
        end++;
    return end;
}

