#include <stdlib.h>

#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif

Vector TwoPole()
{
    Vector v;
    double z, phi, r;

    /* Uniform in [-1, 1] then biased toward +/-1 (the poles) by cubing. */
    z = 2.0 * ((double) rand() / (double) RAND_MAX) - 1.0;
    z = z * z * z;

    phi = 2.0 * M_PI * ((double) rand() / (double) RAND_MAX);
    r = sqrt(1.0 - z * z);

    v.x = r * cos(phi);
    v.y = r * sin(phi);
    v.z = z;

    return v;
}

