int make_buildinfo2()
{
    struct _stat st;
    HKEY   hTortoise;
    char   command[500];
    DWORD  type, size;

    if (_stat(".svn", &st) < 0)
        /* Not a subversion checkout; nothing to do. */
        return 0;

    /* Locate the TortoiseSVN installation directory in the registry. */
    if (RegOpenKey(HKEY_LOCAL_MACHINE, "Software\\TortoiseSVN", &hTortoise) != ERROR_SUCCESS &&
        RegOpenKey(HKEY_CURRENT_USER, "Software\\TortoiseSVN", &hTortoise) != ERROR_SUCCESS)
        /* TortoiseSVN is not installed. */
        return 0;

    size = sizeof(command) - 10;
    if (RegQueryValueEx(hTortoise, "Directory", 0, &type,
                        (LPBYTE) command, &size) != ERROR_SUCCESS ||
        type != REG_SZ) {
        RegCloseKey(hTortoise);
        return 0;
    }
    RegCloseKey(hTortoise);

    if (strlen(command) + 60 >= sizeof(command))
        return 0;

    strcat(command, "bin\\subwcrev.exe");
    if (_stat(command, &st) < 0)
        /* subwcrev.exe is not part of this installation. */
        return 0;

    strcat(command, " ..\\.. ..\\..\\Modules\\getbuildinfo.c getbuildinfo.c");
    puts(command);
    fflush(stdout);
    if (system(command) < 0)
        return 0;

    return 1;
}

