/* Thread local hashtable of objects queued for deferred deletion. */
extern __thread ck_ht_t an_smr_ht;

static bool
an_smr_call_insert_into_hashtable(uintptr_t obj, uintptr_t data)
{
    ck_ht_hash_t  h;
    ck_ht_entry_t entry;

    ck_ht_hash_direct(&h, &an_smr_ht, obj);

    /* Bail out if the object is already queued for deletion. */
    ck_ht_entry_key_set_direct(&entry, obj);
    if (ck_ht_get_spmc(&an_smr_ht, h, &entry) == true)
        return false;

    /* Insert the object together with its deletion callback. */
    ck_ht_entry_set_direct(&entry, h, obj, data);
    return ck_ht_put_spmc(&an_smr_ht, h, &entry);
}

#include <stdlib.h>
#include <string.h>

struct word_node {
    const char       *word;
    struct word_node *next;
};

int app_password(bomb_t *bomb)
{
    /* Candidate five letter passwords for this module. */
    static const char *dictionary[] = {
        "about", "after", "again", "below", "could",
        "every", "first", "found", "great", "house",
        "large", "learn", "never", "other", "place",
        "plant", "point", "right", "small", "sound",
        "spell", "still", "study", "their", "there",
        "these", "thing", "think", "three", "water",
        "where", "which", "world", "would", "write",
        NULL
    };
    struct word_node *head = NULL, *prev, *cur;
    struct word_node *node;
    int i, pos;

    /* Load all the words into a linked list. */
    for (i = 0; dictionary[i] != NULL; i++) {
        node = malloc(sizeof(*node));
        if (node == NULL)
            goto fail;
        node->word = dictionary[i];
        node->next = head;
        head = node;
    }

    /* For each position, drop words whose letter is not selectable. */
    for (pos = 0; pos < 5; pos++) {
        const char *available = bomb->password[pos];

        prev = NULL;
        cur = head;
        while (cur != NULL) {
            if (strchr(available, cur->word[pos]) == NULL) {
                struct word_node *dead = cur;

                if (prev == NULL)
                    head = cur->next;
                else
                    prev->next = cur->next;
                cur = cur->next;
                free(dead);
            } else {
                prev = cur;
                cur = cur->next;
            }
        }
    }

    /* When a single word remains, it is the password. */
    if (head != NULL && head->next == NULL) {
        strncpy(bomb->solution, head->word, 5);
        free(head);
        return 0;
    }

fail:
    while (head != NULL) {
        node = head->next;
        free(head);
        head = node;
    }
    return -1;
}

#include <string.h>

static void padcFunc(sqlite3_context *context, int argc, sqlite3_value **argv){
  const char *zi;   /* input string */
  char *zo;         /* output string */
  int ilen;         /* requested output length in characters */
  int zl;           /* number of characters in the input string */
  int nbytes;       /* number of bytes in the input string */
  int total, left, right, i, j;

  assert(argc == 2);

  if( sqlite3_value_type(argv[0])==SQLITE_NULL ){
    sqlite3_result_null(context);
    return;
  }

  zi = (const char *) sqlite3_value_text(argv[0]);
  ilen = sqlite3_value_int(argv[1]);

  /* Count UTF-8 characters in the input string. */
  zl = 0;
  for(i=0; zi[i]; i++){
    if( (zi[i] & 0xc0)!=0x80 ) zl++;
  }

  /* NOP when the string is already long enough. */
  if( ilen<=zl ){
    sqlite3_result_text(context, zi, -1, SQLITE_TRANSIENT);
    return;
  }

  total = ilen - zl;            /* spaces to add */
  left  = total / 2;            /* balance left and right, left <= right */
  right = total - left;

  nbytes = (int) strlen(zi);
  zo = sqlite3_malloc(nbytes + total + 1);
  if( zo==0 ){
    sqlite3_result_error_nomem(context);
    return;
  }

  j = 0;
  for(i=0; i<left; i++)  zo[j++] = ' ';
  memcpy(zo + j, zi, nbytes);
  j += nbytes;
  for(i=0; i<right; i++) zo[j++] = ' ';
  zo[j] = '\0';

  sqlite3_result_text(context, zo, -1, SQLITE_TRANSIENT);
  sqlite3_free(zo);
}

static MI_Boolean _ProcessAuthMessageWaitingConnectRequest(
    ProtocolSocket* handler, BinProtocolNotification* binMsg)
{
    /* While waiting for a connect request only that message is valid. */
    if (binMsg == NULL ||
        binMsg->base.type != BinNotificationConnectRequest)
    {
        trace_ProtocolSocket_UnexpectedAuthMessage();
        return MI_FALSE;
    }

    /* Refuse protocol versions we do not understand. */
    if (binMsg->version > PROTOCOLSOCKET_SUPPORTED_VERSION)
    {
        _SendConnectResponse(handler, MI_RESULT_NOT_SUPPORTED);
        return MI_FALSE;
    }

    /* Authenticate the peer using the supplied credentials. */
    if (_AuthenticateConnection(handler, binMsg) != MI_RESULT_OK)
    {
        _SendConnectResponse(handler, MI_RESULT_ACCESS_DENIED);
        return MI_FALSE;
    }

    handler->authState = PRT_AUTH_STATE_AUTHENTICATED;

    if (_SendConnectResponse(handler, MI_RESULT_OK) != MI_RESULT_OK)
        return MI_FALSE;

    return MI_TRUE;
}

#include <errno.h>
#include <string.h>

static void
readRecoveryCommandFile(void)
{
    FILE           *fd;
    TimeLineID      rtli = 0;
    bool            rtliGiven = false;
    ConfigVariable *item,
                   *head = NULL,
                   *tail = NULL;

    fd = AllocateFile(RECOVERY_COMMAND_FILE, "r");
    if (fd == NULL)
    {
        if (errno == ENOENT)
            return;             /* not there, so no archive recovery */
        ereport(FATAL,
                (errcode_for_file_access(),
                 errmsg("could not open recovery command file \"%s\": %m",
                        RECOVERY_COMMAND_FILE)));
    }

    /*
     * Since ParseConfigFp() is asked to report errors as FATAL, there is no
     * need to check its return value.
     */
    (void) ParseConfigFp(fd, RECOVERY_COMMAND_FILE, 0, FATAL, &head, &tail);

    FreeFile(fd);

    for (item = head; item; item = item->next)
    {
        if (strcmp(item->name, "restore_command") == 0)
        {
            recoveryRestoreCommand = pstrdup(item->value);
            ereport(DEBUG2,
                    (errmsg_internal("restore_command = '%s'",
                                     recoveryRestoreCommand)));
        }
        else if (strcmp(item->name, "recovery_end_command") == 0)
        {
            recoveryEndCommand = pstrdup(item->value);
        }
        else if (strcmp(item->name, "recovery_target_timeline") == 0)
        {
            rtliGiven = true;
            if (strcmp(item->value, "latest") == 0)
                rtli = 0;
            else
            {
                errno = 0;
                rtli = (TimeLineID) strtoul(item->value, NULL, 0);
                if (errno == EINVAL || errno == ERANGE)
                    ereport(FATAL,
                            (errmsg("recovery_target_timeline is not a valid number: \"%s\"",
                                    item->value)));
            }
        }
        else if (strcmp(item->name, "recovery_target_xid") == 0)
        {
            errno = 0;
            recoveryTargetXid = (TransactionId) strtoul(item->value, NULL, 0);
            if (errno == EINVAL || errno == ERANGE)
                ereport(FATAL,
                        (errmsg("recovery_target_xid is not a valid number: \"%s\"",
                                item->value)));
            recoveryTarget = RECOVERY_TARGET_XID;
        }
        else
            ereport(FATAL,
                    (errmsg("unrecognized recovery parameter \"%s\"",
                            item->name)));
    }

    if (rtliGiven)
    {
        if (rtli)
            recoveryTargetTLI = rtli;
        else
            recoveryTargetIsLatest = true;
    }

    FreeConfigVariables(head);
}

