char *
tempfile_in_same_dir(char *filename, char *prefix, char **ret_dir)
{
    char   *dir;
    char   *tmpl;
    char   *slash;
    size_t  dlen;
    int     fd;

    /* Work out the directory that contains filename. */
    slash = strrchr(filename, '/');
    if (slash != NULL) {
        dlen = (size_t)(slash - filename);
        dir = malloc(dlen + 1);
        if (dir == NULL)
            return NULL;
        memcpy(dir, filename, dlen);
        dir[dlen] = '\0';
    } else {
        dir = strdup(".");
        if (dir == NULL)
            return NULL;
    }

    /* Build a mkstemp() template inside that directory. */
    tmpl = malloc(strlen(dir) + 1 + strlen(prefix) + 6 + 1);
    if (tmpl == NULL) {
        free(dir);
        return NULL;
    }
    sprintf(tmpl, "%s/%sXXXXXX", dir, prefix);

    fd = mkstemp(tmpl);
    if (fd < 0) {
        free(tmpl);
        free(dir);
        return NULL;
    }
    close(fd);

    if (ret_dir != NULL)
        *ret_dir = dir;
    else
        free(dir);

    return tmpl;
}

