#include <stdlib.h>
#include <string.h>

void replace (char **s, const char *m, const char *r)
{
    char   *src = *s;
    size_t  mlen = strlen(m);
    size_t  rlen = strlen(r);
    size_t  count = 0;
    char   *p, *cur, *dst, *out;
    size_t  newlen;

    if (src == NULL || mlen == 0)
        return;

    /* Count the occurrences of the match string. */
    for (p = strstr(src, m); p != NULL; p = strstr(p + mlen, m))
        count++;

    if (count == 0)
        return;

    newlen = strlen(src) + count * rlen - count * mlen;
    out = malloc(newlen + 1);
    if (out == NULL)
        return;

    cur = src;
    dst = out;
    while ((p = strstr(cur, m)) != NULL) {
        size_t seg = (size_t)(p - cur);

        memcpy(dst, cur, seg);
        dst += seg;
        memcpy(dst, r, rlen);
        dst += rlen;
        cur = p + mlen;
    }
    strcpy(dst, cur);

    free(src);
    *s = out;
}

VALUE
Image_encipher(VALUE self, VALUE passphrase)
{
    Image         *image, *new_image;
    char          *pf;
    ExceptionInfo *exception;
    unsigned int   okay;

    image = rm_check_destroyed(self);
    pf = StringValuePtr(passphrase);

    new_image = rm_clone_image(image);

    exception = AcquireExceptionInfo();
    okay = EncipherImage(new_image, pf, exception);
    rm_check_exception(exception, new_image, DestroyOnError);
    (void) DestroyExceptionInfo(exception);

    if (!okay)
    {
        (void) DestroyImage(new_image);
        rb_raise(rb_eRuntimeError, "EncipherImage failed for unknown reason");
    }

    RB_GC_GUARD(passphrase);

    return rm_image_new(new_image);
}

#include <asm/io.h>

#define INTDEF(base)  ((base) + 0x9)
#define RESV1(base)   ((base) + 0xa)

static void aha1740_getconfig(unsigned int base, unsigned int *irq_level,
                              unsigned int *irq_type, unsigned int *translation)
{
    static const int intab[] = { 9, 10, 11, 12, 0, 14, 15, 0 };
    unsigned char intdef = inb(INTDEF(base));

    *irq_level   = intab[intdef & 0x7];
    *irq_type    = (intdef & 0x8) >> 3;
    *translation = inb(RESV1(base)) & 0x1;

    /* Set the "edge/level triggered" and enable bits back. */
    outb(intdef | 0x10, INTDEF(base));
}

void VM_buf_implode (prvm_prog_t *prog)
{
    prvm_stringbuffer_t *stringbuffer;
    char string[VM_STRINGTEMP_LENGTH];
    const char *glue;
    size_t glue_len, pos = 0;
    int i;

    VM_SAFEPARMCOUNT(2, VM_buf_implode);

    stringbuffer = (prvm_stringbuffer_t *)Mem_ExpandableArray_RecordAtIndex(&prog->stringbuffersarray, (int)PRVM_G_FLOAT(OFS_PARM0));
    PRVM_G_INT(OFS_RETURN) = OFS_NULL;
    if (!stringbuffer)
    {
        VM_Warning(prog, "VM_buf_implode: invalid buffer %i used in %s\n", (int)PRVM_G_FLOAT(OFS_PARM0), prog->name);
        return;
    }
    if (!stringbuffer->num_strings)
        return;

    glue = PRVM_G_STRING(OFS_PARM1);
    glue_len = strlen(glue);

    string[0] = '\0';
    for (i = 0; i < stringbuffer->num_strings; i++)
    {
        const char *s = stringbuffer->strings[i];
        size_t s_len;

        if (i && glue_len)
        {
            if (pos + glue_len >= sizeof(string))
                break;
            memcpy(string + pos, glue, glue_len);
            pos += glue_len;
        }
        if (!s)
            continue;
        s_len = strlen(s);
        if (pos + s_len >= sizeof(string))
            s_len = sizeof(string) - 1 - pos;
        memcpy(string + pos, s, s_len);
        pos += s_len;
        string[pos] = '\0';
    }
    string[pos] = '\0';

    PRVM_G_INT(OFS_RETURN) = PRVM_SetTempString(prog, string);
}

#include <math.h>

static void compressData(float *y, char *x, int xSize, int xType, int nSamples,
                         int reqPoints, float xMin, float xMax, int *retPoints,
                         float *retResolution)
{
    double resolution;
    int i, out;
    double lastBin;

    /* No compression needed: fewer samples than requested points. */
    if (nSamples <= reqPoints || reqPoints <= 0) {
        *retPoints = nSamples;
        *retResolution = (nSamples > 1 && xMax > xMin) ?
                         (float)((xMax - xMin) / (nSamples - 1)) : 0.0f;
        return;
    }

    /* Width in X units represented by a single output point. */
    resolution = (double)(xMax - xMin) / (double)reqPoints;
    if (resolution <= 0.0) {
        *retPoints = nSamples;
        *retResolution = 0.0f;
        return;
    }

    out = 0;
    lastBin = -HUGE_VAL;
    for (i = 0; i < nSamples; i++) {
        double xv;
        char *xp = x + (size_t)i * xSize;
        double bin;

        switch (xType) {
        case sizeof(double):
            xv = *(double *)xp;
            break;
        case sizeof(int):
            xv = (double)(*(int *)xp);
            break;
        default:
            xv = (double)(*(float *)xp);
            break;
        }

        bin = floor((xv - xMin) / resolution);
        if (bin != lastBin) {
            /* Keep the first sample of each bin (compress in place). */
            if (out != i) {
                y[out] = y[i];
                memmove(x + (size_t)out * xSize, xp, xSize);
            }
            out++;
            lastBin = bin;
        }
    }

    *retPoints = out;
    *retResolution = (float)resolution;
}

static int _update_journal_header_block(struct super_block *p_s_sb,
                                        unsigned long offset,
                                        unsigned long trans_id)
{
    struct reiserfs_journal_header *jh;
    struct reiserfs_journal *journal = SB_JOURNAL(p_s_sb);
    struct buffer_head *bh = journal->j_header_bh;

    if (trans_id >= journal->j_last_flush_trans_id) {
        if (buffer_locked(bh)) {
            wait_on_buffer(bh);
            if (!buffer_uptodate(bh)) {
                reiserfs_panic(p_s_sb, "journal-699: buffer write failed\n");
            }
        }
        journal->j_last_flush_trans_id = trans_id;
        journal->j_first_unflushed_offset = offset;
        jh = (struct reiserfs_journal_header *)(bh->b_data);
        jh->j_last_flush_trans_id = cpu_to_le32(trans_id);
        jh->j_first_unflushed_offset = cpu_to_le32(offset);
        jh->j_mount_id = cpu_to_le32(journal->j_mount_id);

        set_buffer_dirty(bh);
        sync_dirty_buffer(bh);
        if (!buffer_uptodate(bh)) {
            reiserfs_warning(p_s_sb,
                "reiserfs-837: IO error during journal replay\n");
            return -EIO;
        }
    }
    return 0;
}

void
WS_Init(struct ws *ws, const char *id, void *space, unsigned len)
{
    unsigned l;

    assert(space != NULL);
    assert(id != NULL);
    /* id must be at most 3 chars and lower-case. */
    assert(strlen(id) < sizeof(ws->id));
    assert(id[0] & 0x20);   /* cheesy islower() */

    memset(ws, 0, sizeof *ws);
    ws->magic = WS_MAGIC;
    strncpy(ws->id, id, sizeof(ws->id) - 1);
    ws->id[sizeof(ws->id) - 1] = '\0';

    ws->s = space;
    assert(PAOK(space));
    l = PRNDDN(len);
    ws->e = ws->s + l;
    ws->f = ws->s;

    WS_Assert(ws);
}

static void __dma_cache_wback_inv_slc(phys_addr_t start, unsigned long sz)
{
    /* L1 write-back and invalidate, then do the same on the SLC (L2). */
    __dc_line_op_k(start, sz, OP_FLUSH_N_INV);
    slc_op(start, sz, OP_FLUSH_N_INV);
}

bool write_marked_file(const char *name, FILE *f_open, bool tmp, append_type append)
{
    bool retval;
    bool old_modified = openfile->modified;
    partition *part;

    /* Adjust the mark and cursor so that the marked region is what
     * will be written, then partition the buffer around it. */
    if (!openfile->mark_set)
        return FALSE;

    /* Put the marked region into its own partition. */
    part = partition_filestruct(openfile->mark_begin,
                                openfile->mark_begin_x,
                                openfile->current,
                                openfile->current_x);

    /* Write the current (partitioned) buffer to disk. */
    retval = write_file(name, f_open, tmp, append, TRUE);

    /* Restore the buffer to its original, unpartitioned state. */
    unpartition_filestruct(&part);

    /* Writing a marked selection must not clear the modified flag. */
    if (old_modified)
        set_modified();

    return retval;
}

#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int handle_migration_key_options(char *options)
{
    char *opt, *val, *saveptr;

    if (options == NULL)
        return 0;

    for (opt = strtok_r(options, ",", &saveptr); opt != NULL;
         opt = strtok_r(NULL, ",", &saveptr)) {

        val = strchr(opt, '=');
        if (val != NULL)
            *val++ = '\0';

        if (strcmp(opt, "keyid") == 0) {
            if (val == NULL)
                goto missing_value;
            migration_key_id = strdup(val);
        } else if (strcmp(opt, "keyname") == 0) {
            if (val == NULL)
                goto missing_value;
            migration_key_name = strdup(val);
        } else if (strcmp(opt, "keyformat") == 0) {
            if (val == NULL)
                goto missing_value;
            migration_key_format = strdup(val);
        } else {
            fprintf(stderr, "Unknown migration key option '%s'\n", opt);
            return -1;
        }
        continue;

missing_value:
        fprintf(stderr, "Migration key option '%s' requires a value\n", opt);
        return -1;
    }

    return 0;
}

static void GetTokenInner(void)
{
    int c;
    char *p = TokenText;
    char *end = TokenText + sizeof(TokenText) - 1;

    /* Skip whitespace between tokens. */
    do {
        c = getc(InputFile);
    } while (c == ' ' || c == '\t' || c == '\n' || c == '\r');

    if (c == EOF) {
        Token = TOKEN_EOF;
        *p = '\0';
        return;
    }

    /* An identifier or keyword: [A-Za-z_][A-Za-z0-9_]* */
    if (isalpha(c) || c == '_') {
        while (isalnum(c) || c == '_') {
            if (p < end)
                *p++ = (char)c;
            c = getc(InputFile);
        }
        ungetc(c, InputFile);
        *p = '\0';
        Token = TOKEN_IDENTIFIER;
        return;
    }

    /* A number: a run of digits. */
    if (isdigit(c)) {
        while (isdigit(c)) {
            if (p < end)
                *p++ = (char)c;
            c = getc(InputFile);
        }
        ungetc(c, InputFile);
        *p = '\0';
        Token = TOKEN_NUMBER;
        return;
    }

    /* Otherwise a single-character punctuation token. */
    *p++ = (char)c;
    *p = '\0';
    Token = c;
}

#include <stdlib.h>
#include <string.h>

char *str_msjoin(char **L, int n, char *sep)
{
    size_t seplen, total = 0;
    char *buf, *p;
    int i;

    if (L == NULL || n <= 0)
        return NULL;

    seplen = (sep != NULL) ? strlen(sep) : 0;

    for (i = 0; i < n; i++)
        total += strlen(L[i]);
    total += seplen * (size_t)(n - 1);

    buf = malloc(total + 1);
    if (buf == NULL)
        return NULL;

    p = buf;
    for (i = 0; i < n; i++) {
        size_t len;

        if (i != 0 && seplen != 0) {
            memcpy(p, sep, seplen);
            p += seplen;
        }
        len = strlen(L[i]);
        memcpy(p, L[i], len);
        p += len;
    }
    *p = '\0';

    return buf;
}

