void verifyBitness(JNIEnv *env, const char *binaryName)
{
    int fd;
    unsigned char ident[EI_NIDENT];
    int expected;

    fd = open(binaryName, O_RDONLY);
    if (fd < 0) {
        (*env)->ThrowNew(env,
            (*env)->FindClass(env, "sun/jvm/hotspot/debugger/DebuggerException"),
            "Can't open binary file");
        return;
    }

    if (read(fd, ident, sizeof(ident)) != (ssize_t)sizeof(ident)) {
        close(fd);
        (*env)->ThrowNew(env,
            (*env)->FindClass(env, "sun/jvm/hotspot/debugger/DebuggerException"),
            "Can't read ELF header");
        return;
    }
    close(fd);

    if (memcmp(ident, ELFMAG, SELFMAG) != 0) {
        (*env)->ThrowNew(env,
            (*env)->FindClass(env, "sun/jvm/hotspot/debugger/DebuggerException"),
            "Not an ELF file");
        return;
    }

    /* Our own bitness is determined by the size of a pointer. */
    expected = (sizeof(void *) == 8) ? ELFCLASS64 : ELFCLASS32;

    if (ident[EI_CLASS] != expected) {
        (*env)->ThrowNew(env,
            (*env)->FindClass(env, "sun/jvm/hotspot/debugger/DebuggerException"),
            "debugger and debuggee have different bitness");
        return;
    }
}

