void list_item_verbose(struct cpio *cpio, struct archive_entry *entry)
{
    char size[32];
    char date[32];
    const char *uname, *gname;
    mode_t mode;
    time_t mtime;
    struct tm *ltime;
    static const char *months[] = {
        "Jan", "Feb", "Mar", "Apr", "May", "Jun",
        "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"
    };
    char modestr[11];

    mode = archive_entry_mode(entry);

    /* Build the "ls -l" style permission string. */
    if (S_ISDIR(mode))       modestr[0] = 'd';
    else if (S_ISLNK(mode))  modestr[0] = 'l';
    else if (S_ISCHR(mode))  modestr[0] = 'c';
    else if (S_ISBLK(mode))  modestr[0] = 'b';
    else if (S_ISFIFO(mode)) modestr[0] = 'p';
    else if (S_ISSOCK(mode)) modestr[0] = 's';
    else                     modestr[0] = '-';

    modestr[1] = (mode & 0400) ? 'r' : '-';
    modestr[2] = (mode & 0200) ? 'w' : '-';
    modestr[3] = (mode & 0100) ? 'x' : '-';
    modestr[4] = (mode & 0040) ? 'r' : '-';
    modestr[5] = (mode & 0020) ? 'w' : '-';
    modestr[6] = (mode & 0010) ? 'x' : '-';
    modestr[7] = (mode & 0004) ? 'r' : '-';
    modestr[8] = (mode & 0002) ? 'w' : '-';
    modestr[9] = (mode & 0001) ? 'x' : '-';
    modestr[10] = '\0';

    uname = archive_entry_uname(entry);
    gname = archive_entry_gname(entry);

    snprintf(size, sizeof(size), "%ju",
             (uintmax_t)archive_entry_size(entry));

    mtime = archive_entry_mtime(entry);
    ltime = localtime(&mtime);
    if (ltime != NULL)
        snprintf(date, sizeof(date), "%s %2d %02d:%02d",
                 months[ltime->tm_mon], ltime->tm_mday,
                 ltime->tm_hour, ltime->tm_min);
    else
        snprintf(date, sizeof(date), "%s", "?");

    fprintf(stdout, "%s %3u %-8s %-8s %8s %s %s",
            modestr,
            (unsigned)archive_entry_nlink(entry),
            uname ? uname : "",
            gname ? gname : "",
            size, date,
            archive_entry_pathname(entry));

    /* For symlinks, show the target. */
    if (archive_entry_hardlink(entry))
        fprintf(stdout, " link to %s", archive_entry_hardlink(entry));
    else if (S_ISLNK(mode) && archive_entry_symlink(entry))
        fprintf(stdout, " -> %s", archive_entry_symlink(entry));

    fprintf(stdout, "\n");
}

#include <stdbool.h>
#include <stddef.h>

char decode_color_name(bool isRed, bool isGreen, bool isBlue)
{
    static char color_name_buffer[3];
    static size_t count = 0;
    char result = '\0';

    /* Encode this color's components into one nibble and buffer it. */
    color_name_buffer[count++] = (char)((isRed ? 4 : 0) |
                                        (isGreen ? 2 : 0) |
                                        (isBlue ? 1 : 0));

    /* Once the buffer is full, decode it to a single name and recycle. */
    if (count == sizeof(color_name_buffer)) {
        int code = 0;
        size_t i;

        for (i = 0; i < count; i++)
            code = (code << 3) | color_name_buffer[i];

        result = (char)('A' + (code % 26));
        count = 0;
    }

    return result;
}

#include <string.h>

void _xml_content(void *data, const char *el, const int len)
{
    PAPI_xml_parse_t *parse = (PAPI_xml_parse_t *)data;
    int space;

    (void)data;

    /* Only accumulate text while we are inside a tag that expects it. */
    if (parse == NULL || !parse->capture)
        return;

    /* Append the text to the current buffer, guarding against overflow. */
    space = (int)sizeof(parse->buffer) - parse->buffer_len - 1;
    if (space <= 0)
        return;

    if (len < space)
        space = len;

    memcpy(parse->buffer + parse->buffer_len, el, space);
    parse->buffer_len += space;
    parse->buffer[parse->buffer_len] = '\0';
}

