#include <string.h>
#include <limits.h>

int accessok(char *path)
{
    char checkpath[PATH_MAX];
    struct stat sb;
    size_t len;
    char *slash;

    if (path == NULL)
        return 1;

    if (strlen(path) >= sizeof(checkpath))
        return 0;
    strcpy(checkpath, path);

    /* If the path names a file, start from its directory. */
    slash = strrchr(checkpath, '/');
    if (slash != NULL)
        slash[1] = '\0';
    else
        checkpath[0] = '\0';

    /* Walk each directory level, looking for a ".httplogin" guard file. */
    for (;;) {
        len = strlen(checkpath);
        if (len + sizeof(".httplogin") >= sizeof(checkpath))
            return 0;
        strcpy(checkpath + len, ".httplogin");

        if (stat(checkpath, &sb) == 0)
            return 0;   /* protected: access is not automatically ok */

        /* Strip the ".httplogin" and the trailing slash to go up a level. */
        checkpath[len] = '\0';
        if (len == 0)
            break;
        checkpath[len - 1] = '\0';          /* remove trailing '/' */
        slash = strrchr(checkpath, '/');
        if (slash == NULL)
            break;
        slash[1] = '\0';
    }

    return 1;
}

enum disir_status
dx_query_resolve_parent_context(struct disir_context *parent,
                                struct disir_context **out,
                                char *keyval_name,
                                const char *query,
                                va_list args)
{
    enum disir_status status;
    struct disir_context *section = NULL;
    const char *leaf;
    char *dot;
    size_t parent_len;
    char section_query[2048];

    if (parent == NULL || out == NULL || keyval_name == NULL || query == NULL)
        return DISIR_STATUS_INVALID_ARGUMENT;

    *out = NULL;

    /* Split the query into "<parent section path>.<leaf name>". */
    dot = strrchr(query, '.');
    if (dot == NULL) {
        /* No parent section in the query: the leaf lives directly here. */
        leaf = query;
        section = parent;
        dx_context_incref(section);
    } else {
        parent_len = (size_t)(dot - query);
        if (parent_len >= sizeof(section_query))
            return DISIR_STATUS_INSUFFICIENT_RESOURCES;
        memcpy(section_query, query, parent_len);
        section_query[parent_len] = '\0';
        leaf = dot + 1;

        status = dx_query_resolve_context(parent, &section, section_query, args);
        if (status != DISIR_STATUS_OK)
            return status;

        if (dc_context_type(section) != DISIR_CONTEXT_SECTION) {
            dx_context_decref(&section);
            return DISIR_STATUS_WRONG_CONTEXT;
        }
    }

    /* Record the leaf name for the caller and hand back the parent section. */
    if (strlen(leaf) >= (size_t)keyval_name_max_length()) {
        dx_context_decref(&section);
        return DISIR_STATUS_INSUFFICIENT_RESOURCES;
    }
    strcpy(keyval_name, leaf);

    *out = section;
    return DISIR_STATUS_OK;
}

