static char* expand_environ_var(char* arg)
{
    /* Only tokens that begin with '$' are subject to expansion. */
    if (arg != NULL && arg[0] == '$') {
        char *value = getenv(arg + 1);

        if (value != NULL) {
            /* Copy the environment value back into 'arg'. */
            memmove(arg, value, strlen(value) + 1);
        } else {
            /* Undefined variable expands to the empty string. */
            arg[0] = '\0';
        }
    }

    return arg;
}

BOOL ads_try_connect(ADS_STRUCT *ads, const char *server)
{
    char *srv;
    struct sockaddr_in addr;
    struct in_addr ip;

    if (server == NULL || *server == '\0')
        return False;

    DEBUG(5, ("ads_try_connect: trying ldap server '%s'\n", server));

    /* Resolve the server name to an IP address. */
    if (!resolve_name(server, &ip, 0x20)) {
        DEBUG(3, ("ads_try_connect: unable to resolve name %s\n", server));
        return False;
    }

    /* Attempt to open an LDAP connection on the standard port. */
    ads->ldap.ld = ldap_open(server, ads->ldap.port ? ads->ldap.port : LDAP_PORT);
    if (ads->ldap.ld == NULL) {
        DEBUG(3, ("ads_try_connect: ldap_open failed for %s\n", server));
        return False;
    }

    /* Success: record the server's IP in the ads struct. */
    memset(&addr, 0, sizeof(addr));
    addr.sin_family = AF_INET;
    addr.sin_addr = ip;
    ads->ldap.ip = ip;
    SAFE_FREE(ads->config.ldap_server_name);
    ads->config.ldap_server_name = SMB_STRDUP(server);

    DEBUG(3, ("Connected to LDAP server %s\n", server));
    return True;
}

#include <stdlib.h>
#include <string.h>
#include <unistd.h>

void *listen_uart_channel_dev(void *arg)
{
    struct uart_channel *channel = (struct uart_channel *)arg;
    char buf[256];
    ssize_t n;

    for (;;) {
        /* Wait for a sync message from a slave channel device. */
        n = read(channel->fd, buf, sizeof(buf) - 1);
        if (n <= 0) {
            if (n < 0 && (errno == EINTR || errno == EAGAIN))
                continue;
            break;
        }
        buf[n] = '\0';

        /* A valid sync message carries the device identifier. */
        if (strncmp(buf, SYNC_MSG_PREFIX, strlen(SYNC_MSG_PREFIX)) == 0) {
            const char *id = buf + strlen(SYNC_MSG_PREFIX);
            struct channel_dev *dev;

            /* Parse the identifier and register the device in the list. */
            dev = calloc(1, sizeof(*dev));
            if (dev == NULL)
                continue;

            strncpy(dev->id, id, sizeof(dev->id) - 1);
            dev->id[sizeof(dev->id) - 1] = '\0';
            dev->channel = channel;

            pthread_mutex_lock(&channel->lock);
            list_add_tail(&dev->node, &channel->dev_list);
            pthread_mutex_unlock(&channel->lock);
        }
    }

    return NULL;
}

