int valid_utf8(const char *c)
{
    const unsigned char *s = (const unsigned char *)c;

    /* ASCII */
    if (s[0] < 0x80)
        return 1;

    /* 2-byte sequence: 110xxxxx 10xxxxxx */
    if ((s[0] & 0xE0) == 0xC0) {
        if ((s[1] & 0xC0) != 0x80)
            return 0;
        if ((s[0] & 0xFE) == 0xC0)      /* overlong encoding */
            return 0;
        return 2;
    }

    /* 3-byte sequence: 1110xxxx 10xxxxxx 10xxxxxx */
    if ((s[0] & 0xF0) == 0xE0) {
        if ((s[1] & 0xC0) != 0x80 || (s[2] & 0xC0) != 0x80)
            return 0;
        if (s[0] == 0xE0 && (s[1] & 0xE0) == 0x80)   /* overlong */
            return 0;
        if (s[0] == 0xED && (s[1] & 0xE0) == 0xA0)   /* UTF-16 surrogate */
            return 0;
        return 3;
    }

    /* 4-byte sequence: 11110xxx 10xxxxxx 10xxxxxx 10xxxxxx */
    if ((s[0] & 0xF8) == 0xF0) {
        if ((s[1] & 0xC0) != 0x80 || (s[2] & 0xC0) != 0x80 ||
            (s[3] & 0xC0) != 0x80)
            return 0;
        if (s[0] == 0xF0 && (s[1] & 0xF0) == 0x80)   /* overlong */
            return 0;
        if (s[0] == 0xF4 && s[1] > 0x8F)             /* > U+10FFFF */
            return 0;
        if (s[0] > 0xF4)
            return 0;
        return 4;
    }

    return 0;
}

int translate_to_user(struct dmabuf *db, char* userbuf, char* dmabuf, int dmacount)
{
    int fmt = db->fmt;
    int stereo = (fmt & ES1371_FMT_STEREO) ? 1 : 0;
    int is16bit = (fmt & ES1371_FMT_S16) ? 1 : 0;
    int src_factor = db->src_factor > 0 ? db->src_factor : 1;
    int usercount = 0;

    /* Number of bytes per source (hardware) frame: always 16-bit stereo. */
    const int hw_framesize = 4;
    int frames = dmacount / hw_framesize;
    int i;
    short *src = (short *)dmabuf;

    for (i = 0; i < frames; i += src_factor) {
        short left = src[i * 2];
        short right = src[i * 2 + 1];

        if (is16bit) {
            *((short *)(userbuf + usercount)) = left;
            usercount += 2;
            if (stereo) {
                *((short *)(userbuf + usercount)) = right;
                usercount += 2;
            }
        } else {
            /* Convert signed 16-bit to unsigned 8-bit. */
            userbuf[usercount++] = (char)(((left >> 8) & 0xff) ^ 0x80);
            if (stereo)
                userbuf[usercount++] = (char)(((right >> 8) & 0xff) ^ 0x80);
        }
    }

    return usercount;
}

#include <stdlib.h>
#include <string.h>

static int
evhttp_parse_query_impl(const char *str, struct evkeyvalq *headers,
                        int is_whole_uri, unsigned flags)
{
    char *line = NULL;
    const char *query_part;
    char *argument;
    char *p;
    int result = -1;

    TAILQ_INIT(headers);

    if (is_whole_uri) {
        /* Skip everything up to and including the first '?'. */
        query_part = strchr(str, '?');
        if (query_part == NULL)
            return 0;
        query_part++;
    } else {
        query_part = str;
    }

    line = strdup(query_part);
    if (line == NULL)
        goto error;

    p = line;
    while (p != NULL && *p != '\0') {
        char *key, *value;

        argument = p;
        p = strchr(p, '&');
        if (p != NULL)
            *p++ = '\0';

        if (*argument == '\0')
            continue;

        key = argument;
        value = strchr(argument, '=');
        if (value != NULL)
            *value++ = '\0';
        else
            value = (char *)"";

        /* URL-decode key and value in place unless caller opts out. */
        if (!(flags & EVHTTP_URI_QUERY_NONCONFORMANT)) {
            if (evhttp_decode_uri_internal(key, strlen(key), key, 1) < 0)
                goto error;
            if (evhttp_decode_uri_internal(value, strlen(value), value, 1) < 0)
                goto error;
        }

        if (evhttp_add_header_internal(headers, key, value) < 0)
            goto error;
    }

    result = 0;

error:
    free(line);
    return result;
}

void recBitonicSort(int lo, int cnt, int dir)
{
    if (cnt > 1) {
        int k = cnt / 2;

        /* Sort the first half ascending and the second half descending
         * to build a bitonic sequence. */
        recBitonicSort(lo, k, ASCENDING);
        recBitonicSort(lo + k, cnt - k, DESCENDING);

        /* Merge the whole bitonic sequence into the requested order. */
        bitonicMerge(lo, cnt, dir);
    }
}

