#include <stdlib.h>
#include <string.h>

static char *cgetent_read_record(FILE *fp)
{
    char line[1024];
    char *rec = NULL;
    size_t len = 0;

    while (fgets(line, sizeof(line), fp) != NULL) {
        size_t llen = strlen(line);
        char *tmp;

        /* Skip comments and blank lines that appear between records. */
        if (rec == NULL && (line[0] == '#' || line[0] == '\n' || line[0] == '\r'))
            continue;

        tmp = realloc(rec, len + llen + 1);
        if (tmp == NULL) {
            free(rec);
            return NULL;
        }
        rec = tmp;
        memcpy(rec + len, line, llen + 1);
        len += llen;

        /* A logical record continues while a physical line ends in a backslash. */
        if (len >= 2 && rec[len - 1] == '\n' && rec[len - 2] == '\\') {
            len -= 2;
            rec[len] = '\0';
            continue;
        }
        if (len >= 1 && rec[len - 1] == '\n') {
            rec[len - 1] = '\0';
            len--;
        }
        break;
    }

    return rec;
}

int cgetent(char **buf, char **db_array, const char *name)
{
    int i;
    size_t namelen;

    if (buf == NULL || db_array == NULL || name == NULL)
        return -2;

    namelen = strlen(name);
    *buf = NULL;

    for (i = 0; db_array[i] != NULL; i++) {
        FILE *fp;
        char *rec;

        fp = fopen(db_array[i], "r");
        if (fp == NULL)
            return -2;

        while ((rec = cgetent_read_record(fp)) != NULL) {
            const char *p = rec;

            /* The record names precede the first ':' and are '|' separated. */
            while (*p != '\0' && *p != ':') {
                const char *end = p;

                while (*end != '\0' && *end != ':' && *end != '|')
                    end++;

                if ((size_t)(end - p) == namelen &&
                    strncmp(p, name, namelen) == 0) {
                    *buf = rec;
                    fclose(fp);
                    return 0;
                }

                p = end;
                if (*p == '|')
                    p++;
            }
            free(rec);
        }

        if (ferror(fp)) {
            fclose(fp);
            return -2;
        }
        fclose(fp);
    }

    return -1;
}

