int parse_cmd(int sid, char *buf)
{
    static const char keyword[] = "scribble";
    char cmd[64];
    int consumed = 0;

    if (buf == NULL)
        return 0;

    if (sscanf(buf, "%63s%n", cmd, &consumed) != 1)
        return 0;

    if (strcmp(cmd, keyword) != 0)
        return 0;

    /* Everything after the leading keyword is the command's arguments. */
    exec_scribble(sid, buf + consumed);
    return 1;
}

