static int min3(int a, int b, int c)
{
    int m = a;

    if (b < m)
        m = b;
    if (c < m)
        m = c;
    return m;
}

int calc_ld(char *sandy, char *cima)
{
    int cost;

    /* If either string is empty, the distance is the length of the other. */
    if (*sandy == '\0')
        return (int)strlen(cima);
    if (*cima == '\0')
        return (int)strlen(sandy);

    cost = (*sandy == *cima) ? 0 : 1;

    return min3(calc_ld(sandy + 1, cima) + 1,
                calc_ld(sandy, cima + 1) + 1,
                calc_ld(sandy + 1, cima + 1) + cost);
}

