#include <stdint.h>

#define BACNET_OBJECT_ID_TAG   12
#define BACNET_MAX_OBJECT      0x3FF
#define BACNET_MAX_INSTANCE    0x3FFFFF
#define BACNET_INSTANCE_BITS   22

int encode_application_object_id(uint8_t *apdu, int object_type, uint32_t instance)
{
    uint32_t value;
    int len = 0;

    if (apdu == NULL)
        return 0;

    value = (((uint32_t)object_type & BACNET_MAX_OBJECT) << BACNET_INSTANCE_BITS)
            | (instance & BACNET_MAX_INSTANCE);

    /* Tag byte: application tag 12 (object identifier), fixed length of 4. */
    apdu[len++] = (uint8_t)((BACNET_OBJECT_ID_TAG << 4) | 4);
    apdu[len++] = (uint8_t)((value >> 24) & 0xFF);
    apdu[len++] = (uint8_t)((value >> 16) & 0xFF);
    apdu[len++] = (uint8_t)((value >> 8) & 0xFF);
    apdu[len++] = (uint8_t)(value & 0xFF);

    return len;
}

