extern void *dictget2(Dict *dict, const char *name1, const char *name2)
{
    char stackbuf[256];
    char *buf;
    size_t len1 = strlen(name1);
    size_t len2 = strlen(name2);
    void *result;

    if (len1 + len2 + 1 <= sizeof(stackbuf)) {
        buf = stackbuf;
    } else {
        buf = malloc(len1 + len2 + 1);
        if (buf == NULL)
            return NULL;
    }

    memcpy(buf, name1, len1);
    memcpy(buf + len1, name2, len2 + 1);

    result = dictget(dict, buf);

    if (buf != stackbuf)
        free(buf);

    return result;
}

