FILE *fopenmask(const char *filename, const char *mode, mode_t perms)
{
    FILE *fp;
    mode_t mask;

    /* Determine the current umask without permanently changing it. */
    mask = umask(0);
    umask(mask);

    fp = fopen(filename, mode);
    if (fp == NULL)
        return NULL;

    /* Apply the requested permissions minus the umask.  When executable bits
       are requested they are honoured explicitly via fchmod(). */
    if (fchmod(fileno(fp), perms & ~mask) != 0) {
        fclose(fp);
        return NULL;
    }

    return fp;
}

#include <stdbool.h>
#include <stdint.h>
#include <pthread.h>

typedef struct _stritem item;

extern pthread_mutex_t lru_locks[];
extern item *tails[];
extern volatile unsigned int current_time;

#define TAIL_REPAIR_TIME (3 * 3600)

uint32_t hash(const void *key, size_t length);
void *item_trylock(uint32_t hv);
void item_trylock_unlock(void *lock);
unsigned short refcount_incr(item *it);
unsigned short refcount_decr(item *it);
void do_item_unlink_nolock(item *it, const uint32_t hv);
void do_item_remove(item *it);
bool item_is_flushed(item *it);
const char *ITEM_key(const item *it);

static int lru_pull_tail(const int orig_id, const int cur_lru, const unsigned int total_chunks, const bool do_evict, const uint32_t cur_hv)
{
    item *search;
    item *next_it;
    void *hold_lock;
    int id = orig_id;
    int removed = 0;
    unsigned int tries = 5;

    if (id == 0)
        return 0;

    id |= cur_lru;

    pthread_mutex_lock(&lru_locks[id]);
    search = tails[id];
    for (; tries > 0 && search != NULL; tries--, search = next_it) {
        uint32_t hv;

        next_it = search->prev;

        /* Skip crawler placeholder items without consuming a try. */
        if (search->nbytes == 0 && search->nkey == 0) {
            tries++;
            continue;
        }

        hv = hash(ITEM_key(search), search->nkey);
        hold_lock = NULL;
        if (hv != cur_hv) {
            hold_lock = item_trylock(hv);
            if (hold_lock == NULL)
                continue;
        }

        /* If another thread holds a reference we cannot reclaim it now. */
        if (refcount_incr(search) != 2) {
            if ((search->time + TAIL_REPAIR_TIME) < current_time) {
                do_item_unlink_nolock(search, hv);
                removed++;
            }
            refcount_decr(search);
            if (hold_lock != NULL)
                item_trylock_unlock(hold_lock);
            continue;
        }

        if ((search->exptime != 0 && search->exptime < (long)current_time) ||
            item_is_flushed(search)) {
            do_item_unlink_nolock(search, hv);
            do_item_remove(search);
            removed++;
            if (hold_lock != NULL)
                item_trylock_unlock(hold_lock);
            break;
        }

        if (do_evict && total_chunks > 0) {
            do_item_unlink_nolock(search, hv);
            do_item_remove(search);
            removed++;
        } else {
            refcount_decr(search);
        }

        if (hold_lock != NULL)
            item_trylock_unlock(hold_lock);
        break;
    }
    pthread_mutex_unlock(&lru_locks[id]);

    return removed;
}

#include <ctype.h>
#include <string.h>

typedef char Char;

extern Char *InputBuf;
extern Char *LastChar;

int spell_word(Char *start, Char *end, int is_command);

int SpellLine(int cmdonly)
{
    Char *word_start = NULL;
    Char *cp;
    int result = 0;
    int is_command = 1;
    int any_wrong = 0;

    for (cp = InputBuf; cp <= LastChar; cp++) {
        int at_end = (cp == LastChar);
        int c = at_end ? ' ' : (int)(*cp & 0xFF);

        if (isspace(c) || at_end) {
            if (word_start != NULL) {
                if (!cmdonly || is_command) {
                    int r = spell_word(word_start, cp, is_command);

                    if (r < 0)
                        any_wrong = 1;
                    else if (r > 0)
                        result = 1;
                }
                word_start = NULL;
                is_command = 0;
            }
            if (!at_end && (*cp == ';' || *cp == '|' || *cp == '&'))
                is_command = 1;
        } else if (word_start == NULL) {
            word_start = cp;
        }
    }

    if (result == 0 && any_wrong)
        return -1;

    return result;
}

#include <stdlib.h>
#include <string.h>

typedef struct {
    char name[64];
    long value;
    double scale;
} ProcessArguments_t;

static int ProcessLine(char *textRow, ProcessArguments_t *procArg)
{
    static const char *const seps = " \t\r\n";
    char *saveptr = NULL;
    char *token;
    int count = 0;

    if (textRow == NULL || procArg == NULL)
        return 0;

    token = strtok_r(textRow, seps, &saveptr);

    /* Ignore blank lines and comments. */
    if (token == NULL || token[0] == '#')
        return 0;

    strncpy(procArg->name, token, sizeof(procArg->name) - 1);
    procArg->name[sizeof(procArg->name) - 1] = '\0';
    count++;

    token = strtok_r(NULL, seps, &saveptr);
    if (token == NULL)
        return count;
    procArg->value = strtol(token, NULL, 0);
    count++;

    token = strtok_r(NULL, seps, &saveptr);
    if (token != NULL) {
        procArg->scale = strtod(token, NULL);
        count++;
    }

    return count;
}

