#include <linux/io.h>

extern void __iomem *cpuidle_base;

void cpu_pm_enter(void);
void cpu_pm_exit(void);
int cpu_do_idle(void);
void set_boot_flag(unsigned int cpu, unsigned int mode);
void clear_boot_flag(unsigned int cpu, unsigned int mode);

#define C2_STATE (1 << 0)

int enter_c2(unsigned int cpu, int index)
{
    unsigned int offset = cpu * 0x4;

    /* Notify the PM core that this CPU is about to lose power state. */
    cpu_pm_enter();

    /* Flag the boot rom that the CPU is entering the C2 power-down mode. */
    set_boot_flag(cpu, C2_STATE);

    /* Request the CPU power domain to power off on WFI. */
    __raw_writel(0, cpuidle_base + offset);

    /* Enter WFI; execution resumes here after wakeup. */
    cpu_do_idle();

    /* Undo the C2 configuration on the wakeup path. */
    __raw_writel(1, cpuidle_base + offset);
    clear_boot_flag(cpu, C2_STATE);
    cpu_pm_exit();

    return index;
}

#include <errno.h>
#include <stdlib.h>

typedef unsigned int tileset;

#define TILE_COUNT 32

int tileset_parse(tileset *ts, const char *str)
{
    tileset result = 0;

    if (str == NULL || *str == '\0')
        return -1;

    for (;;) {
        char *end;
        long tile;

        errno = 0;
        tile = strtol(str, &end, 10);
        if (end == str || errno != 0 || tile < 0 || tile >= TILE_COUNT)
            return -1;

        result |= (tileset)1 << tile;

        str = end;
        if (*str == '\0')
            break;
        if (*str != ',')
            return -1;
        str++;
    }

    *ts = result;
    return 0;
}

