#define MERGE_DONT_ALLOW_INSERT 0

int myrg_create(const char *name, const char **table_names, uint insert_method, my_bool fix_names)
{
    int fd;
    int save_errno;

    (void)fix_names;

    fd = open(name, O_WRONLY | O_CREAT | O_TRUNC, 0660);
    if (fd < 0)
        return errno;

    if (table_names != NULL) {
        for (; *table_names != NULL; table_names++) {
            size_t len = strlen(*table_names);

            if (write(fd, *table_names, len) != (ssize_t)len ||
                write(fd, "\n", 1) != 1) {
                save_errno = errno;
                close(fd);
                return save_errno;
            }
        }
    }

    if (insert_method != MERGE_DONT_ALLOW_INSERT) {
        char buff[32];
        int n = snprintf(buff, sizeof(buff), "#INSERT_METHOD=%u\n", insert_method);

        if (n < 0 || write(fd, buff, (size_t)n) != n) {
            save_errno = errno;
            close(fd);
            return save_errno;
        }
    }

    if (close(fd) != 0)
        return errno;

    return 0;
}

#include <string.h>

typedef unsigned char byte;

extern byte rand_range(byte low, byte high);
extern int rand_int(int m);

/* Probability tables built at game start:  the chance of each following
   letter given the two preceding letters (0 == word boundary). */
extern byte name_freq[28][28][28];

#define S_BOUND 27

static char *make_word(byte min_length, byte max_length)
{
    static char word[64];
    int tries;

    for (tries = 0; tries < 100; tries++) {
        int prev = S_BOUND;
        int cur = S_BOUND;
        int len = 0;
        int ok = 1;

        while (len < (int)max_length) {
            int total = 0;
            int next;
            int roll;

            for (next = 0; next < 28; next++)
                total += name_freq[prev][cur][next];

            if (total <= 0) {
                ok = 0;
                break;
            }

            roll = rand_int(total);
            for (next = 0; next < 28; next++) {
                roll -= name_freq[prev][cur][next];
                if (roll < 0)
                    break;
            }

            if (next == S_BOUND) {
                /* Natural end of word. */
                break;
            }

            word[len++] = (char)('a' + next);
            prev = cur;
            cur = next;
        }

        if (ok && len >= (int)min_length && len <= (int)max_length) {
            word[len] = '\0';
            return word;
        }
    }

    /* Fallback should the tables fail to produce a valid word. */
    strcpy(word, "grond");
    return word;
}

#include <arpa/inet.h>
#include <string.h>

typedef struct {
    char *name;
    unsigned short type;
    unsigned short tclass;
    unsigned int ttl;
    unsigned short rdlength;
    char *rdata;
} rfc1035_rr;

static size_t rfc1035NamePack(char *buf, size_t sz, const char *name)
{
    size_t off = 0;
    const char *p = name;

    while (*p != '\0') {
        const char *dot = strchr(p, '.');
        size_t label = dot ? (size_t)(dot - p) : strlen(p);

        if (label == 0 || label > 63)
            return 0;
        if (off + label + 1 > sz)
            return 0;

        buf[off++] = (char)label;
        memcpy(buf + off, p, label);
        off += label;

        p += label;
        if (*p == '.')
            p++;
    }

    if (off + 1 > sz)
        return 0;
    buf[off++] = '\0'; /* root label terminates the name */

    return off;
}

size_t rfc1035RRPack(char *buf, const size_t sz, const rfc1035_rr *RR)
{
    size_t off;
    unsigned short s;
    unsigned int i;
    size_t namelen;

    namelen = rfc1035NamePack(buf, sz, RR->name);
    if (namelen == 0)
        return 0;
    off = namelen;

    if (off + 2 + 2 + 4 + 2 + RR->rdlength > sz)
        return 0;

    s = htons(RR->type);
    memcpy(buf + off, &s, sizeof(s));
    off += sizeof(s);

    s = htons(RR->tclass);
    memcpy(buf + off, &s, sizeof(s));
    off += sizeof(s);

    i = htonl(RR->ttl);
    memcpy(buf + off, &i, sizeof(i));
    off += sizeof(i);

    s = htons(RR->rdlength);
    memcpy(buf + off, &s, sizeof(s));
    off += sizeof(s);

    memcpy(buf + off, RR->rdata, RR->rdlength);
    off += RR->rdlength;

    return off;
}

#include <stddef.h>
#include <stdint.h>

extern void *ich_spibar;

uint32_t mmio_readl(const void *addr);
void mmio_writel(uint32_t val, void *addr);

#define PR_RP_OFF 15
#define PR_WP_OFF 31

static void ich9_set_pr(const size_t reg_pr0, int i, int read_prot, int write_prot)
{
    void *addr = (uint8_t *)ich_spibar + reg_pr0 + (size_t)i * 4;
    uint32_t old, new;

    old = mmio_readl(addr);
    new = old;

    if (read_prot)
        new |= (1u << PR_RP_OFF);
    else
        new &= ~(1u << PR_RP_OFF);

    if (write_prot)
        new |= (1u << PR_WP_OFF);
    else
        new &= ~(1u << PR_WP_OFF);

    if (new != old)
        mmio_writel(new, addr);
}

