int jm_getenv_positive_int(const char *envvar)
{
    const char *value = getenv(envvar);
    char *end;
    long n;

    if (value == NULL)
        return 0;

    errno = 0;
    n = strtol(value, &end, 10);

    if (end == value || *end != '\0' || errno != 0 || n <= 0 || n > INT_MAX) {
        fprintf(stderr, "%s: expected a positive integer, got \"%s\"\n",
                envvar, value);
        exit(EXIT_FAILURE);
    }

    return (int)n;
}

