enum dev_status {
    DEV_ONLINE,
    DEV_OFFLINE,
    DEV_NOT_DEFINED,
    DEV_ERROR
};

static enum dev_status dev_from_busid(char *bus_id, dev_t *dev)
{
    char path[512];
    FILE *fp;
    int online;
    unsigned int major, minor;

    /* A device is only "defined" if its sysfs directory exists. */
    snprintf(path, sizeof(path), "/sys/bus/ccw/devices/%s/online", bus_id);
    fp = fopen(path, "r");
    if (fp == NULL)
        return DEV_NOT_DEFINED;

    if (fscanf(fp, "%d", &online) != 1) {
        fclose(fp);
        return DEV_ERROR;
    }
    fclose(fp);

    if (!online)
        return DEV_OFFLINE;

    /* Read the associated dev_t (major:minor). */
    snprintf(path, sizeof(path), "/sys/bus/ccw/devices/%s/block/dev", bus_id);
    fp = fopen(path, "r");
    if (fp == NULL) {
        snprintf(path, sizeof(path), "/sys/bus/ccw/devices/%s/dev", bus_id);
        fp = fopen(path, "r");
    }
    if (fp == NULL)
        return DEV_ERROR;

    if (fscanf(fp, "%u:%u", &major, &minor) != 2) {
        fclose(fp);
        return DEV_ERROR;
    }
    fclose(fp);

    if (dev != NULL)
        *dev = makedev(major, minor);

    return DEV_ONLINE;
}

