public static void copyParamsToAttributes(final HttpServletRequest servletRequest,
        final boolean treatEmptyParamsAsNull, final boolean ignoreEmptyRequestParams) {
    final Enumeration<String> paramNames = servletRequest.getParameterNames();
    while (paramNames.hasMoreElements()) {
        final String paramName = paramNames.nextElement();
        final String[] paramValues = servletRequest.getParameterValues(paramName);
        final Object attributeValue;
        if (paramValues.length == 1) {
            final String paramValue = paramValues[0];
            if (paramValue.isEmpty()) {
                if (ignoreEmptyRequestParams) {
                    continue;
                }
                attributeValue = treatEmptyParamsAsNull ? null : paramValue;
            } else {
                attributeValue = paramValue;
            }
        } else {
            attributeValue = paramValues;
        }
        servletRequest.setAttribute(paramName, attributeValue);
    }
}

private javax.naming.Binding mapBinding(org.omg.CosNaming.Binding bndg) throws NamingException {
    java.lang.Object obj = callResolve(bndg.binding_name);

    Name cname = CNNameParser.cosNameToName(bndg.binding_name);

    try {
        obj = NamingManager.getObjectInstance(obj, cname, this, _env);
    } catch (NamingException e) {
        throw e;
    } catch (Exception e) {
        NamingException ne = new NamingException(
                "problem generating object using object factory");
        ne.setRootCause(e);
        throw ne;
    }

    // Use cname.toString() instead of the raw name because the string form
    // is affected by the syntax of the naming context.
    javax.naming.Binding jbndg = new javax.naming.Binding(cname.toString(), obj);

    NameComponent[] comps = bndg.binding_name;
    StringBuilder buf = new StringBuilder();
    for (int i = 0; i < comps.length; i++) {
        buf.append("(" + comps[i].id + "," + comps[i].kind + ")");
    }
    jbndg.setNameInNamespace(buf.toString());
    return jbndg;
}

