public static void copyRecursively(File src, File dest) throws IOException {
    if (src == null || dest == null) {
        throw new IllegalArgumentException("Source and destination must not be null");
    }
    if (!src.exists()) {
        throw new IOException("Source '" + src + "' does not exist");
    }
    if (src.isDirectory()) {
        if (!dest.exists() && !dest.mkdirs()) {
            throw new IOException("Failed to create directory '" + dest + "'");
        }
        String[] children = src.list();
        if (children != null) {
            for (String child : children) {
                copyRecursively(new File(src, child), new File(dest, child));
            }
        }
    } else {
        File parent = dest.getParentFile();
        if (parent != null && !parent.exists() && !parent.mkdirs()) {
            throw new IOException("Failed to create directory '" + parent + "'");
        }
        Files.copy(src.toPath(), dest.toPath(),
                StandardCopyOption.REPLACE_EXISTING, StandardCopyOption.COPY_ATTRIBUTES);
    }
}

