private static SSLContext createRestSSLContext(Configuration config, RestSSLContextConfigMode configMode) throws Exception {
    checkNotNull(config, "config");

    if (!SecurityOptions.isRestSSLEnabled(config)) {
        return null;
    }

    String sslProtocolVersion = config.getString(SecurityOptions.SSL_PROTOCOL);

    KeyManager[] keyManagers = null;
    if (configMode == RestSSLContextConfigMode.SERVER || configMode == RestSSLContextConfigMode.MUTUAL) {
        String keystoreFilePath = getAndCheckOption(
                config, SecurityOptions.SSL_REST_KEYSTORE, SecurityOptions.SSL_KEYSTORE);
        String keystorePassword = getAndCheckOption(
                config, SecurityOptions.SSL_REST_KEYSTORE_PASSWORD, SecurityOptions.SSL_KEYSTORE_PASSWORD);
        String keyPassword = getAndCheckOption(
                config, SecurityOptions.SSL_REST_KEY_PASSWORD, SecurityOptions.SSL_KEY_PASSWORD);

        KeyStore keyStore = KeyStore.getInstance(KeyStore.getDefaultType());
        try (InputStream keyStoreFile = Files.newInputStream(new File(keystoreFilePath).toPath())) {
            keyStore.load(keyStoreFile, keystorePassword.toCharArray());
        }

        KeyManagerFactory kmf = KeyManagerFactory.getInstance(KeyManagerFactory.getDefaultAlgorithm());
        kmf.init(keyStore, keyPassword.toCharArray());
        keyManagers = kmf.getKeyManagers();
    }

    TrustManager[] trustManagers = null;
    if (configMode == RestSSLContextConfigMode.CLIENT || configMode == RestSSLContextConfigMode.MUTUAL) {
        String truststoreFilePath = getAndCheckOption(
                config, SecurityOptions.SSL_REST_TRUSTSTORE, SecurityOptions.SSL_TRUSTSTORE);
        String truststorePassword = getAndCheckOption(
                config, SecurityOptions.SSL_REST_TRUSTSTORE_PASSWORD, SecurityOptions.SSL_TRUSTSTORE_PASSWORD);

        KeyStore trustStore = KeyStore.getInstance(KeyStore.getDefaultType());
        try (InputStream trustStoreFile = Files.newInputStream(new File(truststoreFilePath).toPath())) {
            trustStore.load(trustStoreFile, truststorePassword.toCharArray());
        }

        TrustManagerFactory tmf = TrustManagerFactory.getInstance(TrustManagerFactory.getDefaultAlgorithm());
        tmf.init(trustStore);
        trustManagers = tmf.getTrustManagers();
    }

    SSLContext sslContext = SSLContext.getInstance(sslProtocolVersion);
    sslContext.init(keyManagers, trustManagers, null);
    return sslContext;
}

private void register(final G gateway, final int attempt, final long timeoutMillis) {
    // eager check for cancellation to avoid unnecessary work
    if (canceled) {
        return;
    }

    try {
        log.debug("Registration at {} attempt {} (timeout={}ms)", targetName, attempt, timeoutMillis);
        CompletableFuture<RegistrationResponse> registrationFuture =
                invokeRegistration(gateway, fencingToken, timeoutMillis);

        // if the registration was successful, let the caller know
        CompletableFuture<Void> registrationAcceptFuture = registrationFuture.thenAcceptAsync(
                (RegistrationResponse result) -> {
                    if (!isCanceled()) {
                        if (result instanceof RegistrationResponse.Success) {
                            // registration was successful
                            log.debug("Registration with {} at {} was successful.", targetName, targetAddress);
                            @SuppressWarnings("unchecked")
                            S success = (S) result;
                            completionFuture.complete(retrieveConnection(gateway, success));
                        } else {
                            // registration refused or unknown
                            if (result instanceof RegistrationResponse.Decline) {
                                RegistrationResponse.Decline decline = (RegistrationResponse.Decline) result;
                                log.info("Registration with {} at {} was declined: {}",
                                        targetName, targetAddress, decline.getReason());
                            } else {
                                log.error("Received unknown response to registration attempt: {}", result);
                            }
                            log.info("Pausing and re-attempting registration in {} ms", delayOnRefusedRegistration);
                            registerLater(gateway, 1, initialRegistrationTimeoutMillis, delayOnRefusedRegistration);
                        }
                    }
                },
                rpcService.getExecutor());

        // upon failure, retry
        registrationAcceptFuture.whenCompleteAsync(
                (Void v, Throwable failure) -> {
                    if (failure != null && !isCanceled()) {
                        if (ExceptionUtils.stripCompletionException(failure) instanceof TimeoutException) {
                            // we ran into a timeout, retry immediately with a longer timeout
                            if (log.isDebugEnabled()) {
                                log.debug("Registration with {} at {} timed out after {} ms. Retrying.",
                                        targetName, targetAddress, timeoutMillis);
                            }
                            long newTimeoutMillis = Math.min(2 * timeoutMillis, maxRegistrationTimeoutMillis);
                            register(gateway, attempt + 1, newTimeoutMillis);
                        } else {
                            // a serious failure, retry after a pause
                            log.warn("Registration with {} at {} failed due to an error after {} ms.",
                                    targetName, targetAddress, timeoutMillis, failure);
                            registerLater(gateway, 1, initialRegistrationTimeoutMillis, delayOnError);
                        }
                    }
                },
                rpcService.getExecutor());
    } catch (Throwable t) {
        completionFuture.completeExceptionally(t);
        cancel();
    }
}

