public void prepareToConnect(Request request) {
    if (route != null) {
        // Already have a route from a previous connect; reuse it if it still matches.
        if (sameHostAndPort(route.address().url(), request.url()) && route.address().equals(createAddress(request.url()))) {
            return;
        }
        if (transmitter.hasExchange()) {
            throw new IllegalStateException("Cannot make a new request because the previous response is still open: please call response.close()");
        }
        route = null;
    }

    // Create the address for the new request.
    this.address = createAddress(request.url());

    // Prefer to reuse an existing connection if one is available.
    try {
        this.routeSelection = null;
        this.routeSelector = new RouteSelector(address, connectionPool.routeDatabase, call, eventListener);
    } catch (IOException e) {
        throw new RuntimeException(e);
    }
}

