public boolean putFilter(File file) throws Exception {
    String sName = file.getAbsolutePath() + file.getName();
    if (filterClassLastModified.get(sName) != null
            && (file.lastModified() != filterClassLastModified.get(sName))) {
        LOG.debug("reloading filter " + sName);
        filterRegistry.remove(sName);
    }
    ZuulFilter filter = filterRegistry.get(sName);
    if (filter == null) {
        Class clazz = COMPILER.compile(file);
        if (!Modifier.isAbstract(clazz.getModifiers())) {
            filter = (ZuulFilter) FILTER_FACTORY.newInstance(clazz);
            List<ZuulFilter> list = hashFiltersByType.get(filter.filterType());
            if (list != null) {
                hashFiltersByType.remove(filter.filterType()); // rebuild this list
            }
            filterRegistry.put(file.getAbsolutePath() + file.getName(), filter);
            filterClassLastModified.put(sName, file.lastModified());
            return true;
        }
    }
    return false;
}

public static boolean isKali() {
    if (kali == null) {
        kali = Boolean.FALSE;
        File osReleaseFile = new File("/etc/os-release");
        if (isLinux() && osReleaseFile.exists()) {
            try (BufferedReader reader = new BufferedReader(new FileReader(osReleaseFile))) {
                String line;
                boolean isKaliId = false;
                boolean isDaily = false;
                while ((line = reader.readLine()) != null) {
                    if (line.startsWith("ID=") && line.substring(3).replace("\"", "").trim().equals("kali")) {
                        isKaliId = true;
                    } else if (line.contains("kali-dev") || line.contains("kali-rolling")) {
                        isDaily = true;
                    }
                }
                kali = isKaliId && !isDaily;
            } catch (IOException e) {
                LOGGER.warn("Failed to read \"" + osReleaseFile.getAbsolutePath() + "\" file:", e);
            }
        }
    }
    return kali;
}

