public static void waitForOrKill(Process self, long numberOfMillis) {
    Thread thread = new Thread(() -> {
        try {
            self.waitFor();
        } catch (InterruptedException ignore) {
            // interrupted while waiting; fall through to the kill check
        }
    });
    thread.start();
    try {
        thread.join(numberOfMillis);
    } catch (InterruptedException ignore) {
        Thread.currentThread().interrupt();
    }
    if (thread.isAlive()) {
        thread.interrupt();
        self.destroy();
    }
}

