private E unlinkLast() {
    final Node<E> l = last;
    if (l == null) {
        return null;
    }
    final E element = l.item;
    final Node<E> prev = l.prev;
    l.item = null;
    l.prev = null; // help GC
    last = prev;
    if (prev == null) {
        first = null;
    } else {
        prev.next = null;
    }
    size--;
    modCount++;
    return element;
}

public Metadata readMetadata(InputStream stream, Charset encoding, String filePath, @Nullable CharHandler otherHandler) {
    Metadata result;
    try (Reader reader = new BufferedReader(new InputStreamReader(stream, encoding))) {
        LineCounter lineCounter = new LineCounter(filePath);
        FileHashComputer hashComputer = new FileHashComputer();
        CharHandler[] handlers;
        if (otherHandler == null) {
            handlers = new CharHandler[] {lineCounter, hashComputer};
        } else {
            handlers = new CharHandler[] {lineCounter, hashComputer, otherHandler};
        }
        for (CharHandler handler : handlers) {
            handler.init();
        }
        int c = reader.read();
        boolean afterCR = false;
        while (c != -1) {
            char ch = (char) c;
            if (ch == '\r') {
                afterCR = true;
                for (CharHandler handler : handlers) {
                    handler.newLine();
                }
            } else if (ch == '\n') {
                if (!afterCR) {
                    for (CharHandler handler : handlers) {
                        handler.newLine();
                    }
                }
                afterCR = false;
            } else {
                afterCR = false;
                for (CharHandler handler : handlers) {
                    handler.handleChar(ch);
                }
            }
            c = reader.read();
        }
        for (CharHandler handler : handlers) {
            handler.eof();
        }
        result = new Metadata(lineCounter.lines(), lineCounter.nonBlankLines(), hashComputer.getHash(),
                lineCounter.getLineHashes());
    } catch (IOException e) {
        throw new IllegalStateException("Unable to read file " + filePath, e);
    }
    return result;
}

InputStream execute(String cmd, Object ... args) throws AgentLoadException, IOException {
    if (cmd == null) {
        throw new NullPointerException("Command cannot be null");
    }
    // Write the command and its arguments to the target VM
    try (DataOutputStream out = new DataOutputStream(socket.getOutputStream())) {
        writeString(out, PROTOCOL_VERSION);
        writeString(out, cmd);
        // The protocol requires exactly three argument slots
        for (int i = 0; i < 3; i++) {
            if (args != null && i < args.length && args[i] != null) {
                writeString(out, args[i].toString());
            } else {
                writeString(out, "");
            }
        }
        out.flush();

        InputStream in = socket.getInputStream();
        // Read the completion status (a number followed by '\n')
        int completionStatus = readInt(in);
        if (completionStatus != 0) {
            // Read the error message
            String message = readErrorMessage(in);
            in.close();
            if (completionStatus == ATTACH_ERROR_BADVERSION) {
                throw new IOException("Protocol mismatch with target VM");
            }
            throw new AgentLoadException(message);
        }
        return in;
    }
}

