private void deleteStaleBackups() throws Exception {
    File[] backups = backupDir.listFiles();
    if (backups == null || backups.length <= maxBackups) {
        return;
    }
    // Sort by last modified time, oldest first
    Arrays.sort(backups, new Comparator<File>() {
        @Override
        public int compare(File a, File b) {
            return Long.compare(a.lastModified(), b.lastModified());
        }
    });
    int toDelete = backups.length - maxBackups;
    for (int i = 0; i < toDelete; i++) {
        File backup = backups[i];
        if (!backup.delete()) {
            throw new IOException("Unable to delete stale backup file: " + backup.getAbsolutePath());
        }
    }
}

