    try (InputStream in = new FileInputStream(from);
         OutputStream out = new FileOutputStream(to)) {
        byte[] buffer = new byte[4096];
        int read;
        while ((read = in.read(buffer)) != -1) {
            out.write(buffer, 0, read);
            totalBytes += read;
        }
        out.flush();
    } catch (IOException e) {
        e.printStackTrace();
        return 0;
    }
    return totalBytes;
}

