private void triggerRSyncSynchronization() {
    List<String> command = new ArrayList<>();
    command.add("rsync");
    command.add("-avz");
    command.add("--delete");
    command.add(sourcePath);
    command.add(destinationPath);
    try {
        ProcessBuilder processBuilder = new ProcessBuilder(command);
        processBuilder.redirectErrorStream(true);
        Process process = processBuilder.start();
        int exitCode = process.waitFor();
        if (exitCode != 0) {
            LOGGER.error("RSync synchronization failed with exit code {}", exitCode);
        } else {
            LOGGER.info("RSync synchronization completed successfully");
        }
    } catch (IOException e) {
        LOGGER.error("Unable to run RSync binary", e);
    } catch (InterruptedException e) {
        Thread.currentThread().interrupt();
        LOGGER.error("RSync synchronization was interrupted", e);
    }
}

