public static void reproject( CoordinateReferenceSystem from, CoordinateReferenceSystem to, Coordinate[] coordinates ) throws Exception {
    MathTransform transform = CRS.findMathTransform(from, to, true);
    for (int i = 0; i < coordinates.length; i++) {
        Coordinate coordinate = coordinates[i];
        double[] srcPts = new double[]{coordinate.x, coordinate.y};
        double[] dstPts = new double[2];
