private static boolean serialDocInclude(Utils utils, Element element) {
    if (utils.isPrimitive(element.asType())) {
        return false;
    }
    Name qualifiedName = utils.getFullyQualifiedName(element);
    boolean include = false;
    if (utils.isClass(element)) {
        Element te = element;
        if (utils.isSerializable(te)) {
            if (!utils.getSerialTrees(te).isEmpty()) {
                include = serialDocInclude(utils, te);
            } else if (utils.isPublic(te) || utils.isProtected(te)) {
                include = true;
            } else {
                include = false;
            }
        }
    } else if (utils.matches(element, "serial")) {
        String serial = utils.getAnnotationValue(element, "serial");
        if ("exclude".equalsIgnoreCase(serial)) {
            include = false;
        } else if ("include".equalsIgnoreCase(serial)) {
            include = true;
        }
    }
    return include;
}

private boolean handleEvent(SnippetEvent ste) {
    Snippet sn = ste.snippet();
    if (sn == null) {
        return true;
    }
    switch (ste.status()) {
        case VALID:
        case RECOVERABLE_DEFINED:
        case RECOVERABLE_NOT_DEFINED:
            if (ste.exception() != null) {
                System.err.println("Exception: " + ste.exception().getMessage());
                return true;
            }
            if (ste.value() != null) {
                System.out.println(ste.value());
            }
            return false;
        case REJECTED:
            for (Diag diag : state.diagnostics(sn).collect(java.util.stream.Collectors.toList())) {
                System.err.println(diag.getMessage(null));
            }
            return true;
        default:
            return false;
    }
}

