private StringBuffer readDWRScript(String classpath) {
    StringBuffer script = new StringBuffer();
    InputStream in = getClass().getResourceAsStream(classpath);
    if (in == null) {
        in = Thread.currentThread().getContextClassLoader().getResourceAsStream(classpath);
    }
    if (in == null) {
        throw new IllegalArgumentException("Unable to find DWR script on classpath: " + classpath);
    }
    BufferedReader reader = null;
    try {
        reader = new BufferedReader(new InputStreamReader(in, "UTF-8"));
        String line;
        while ((line = reader.readLine()) != null) {
            script.append(line).append('\n');
        }
    } catch (IOException e) {
        throw new RuntimeException("Error reading DWR script: " + classpath, e);
    } finally {
        try {
            if (reader != null) {
                reader.close();
            } else {
                in.close();
            }
        } catch (IOException ignored) {
        }
    }
    return script;
}

