public static ImmutableList<File> loadPossiblyCompressedFileList(File fileList) throws IOException {
    final String name = fileList.getName().toLowerCase();
    if (name.endsWith(".gz") || name.endsWith(".tgz")) {
        InputStream in = new GZIPInputStream(new FileInputStream(fileList));
        BufferedReader reader = new BufferedReader(new InputStreamReader(in, Charsets.UTF_8));
        try {
            final ImmutableList.Builder<File> ret = ImmutableList.builder();
            String line;
            while ((line = reader.readLine()) != null) {
                line = line.trim();
                if (!line.isEmpty()) {
                    ret.add(new File(line));
                }
            }
            return ret.build();
        } finally {
            reader.close();
        }
    } else {
        return loadFileList(fileList);
    }
}

