}

public void writeDocument(String filename, Document document) {
    int dot = filename.lastIndexOf('.');
    String extension = dot >= 0 ? filename.substring(dot + 1).toLowerCase() : "";
    DocumentSerializer serializer = serializers.get(extension);
    if (serializer == null) {
        throw new IllegalArgumentException("No serializer registered for extension: " + extension);
    }
    try (OutputStream out = new BufferedOutputStream(new FileOutputStream(filename))) {
        serializer.serialize(document, out);
    } catch (IOException e) {
        throw new RuntimeException("Unable to write document to " + filename, e);
    }
}

private void setValueFromObject(org.w3c.dom.Node n) {
    if (n == null) {
        this.value = null;
        return;
    }
    n.normalize();
    try {
        Transformer transformer = TransformerFactory.newInstance().newTransformer();
        transformer.setOutputProperty(OutputKeys.OMIT_XML_DECLARATION, "yes");
        StringWriter sw = new StringWriter();
        transformer.transform(new DOMSource(n), new StreamResult(sw));
        this.value = sw.toString();
    } catch (TransformerException e) {
        throw new RuntimeException("Unable to serialize DOM node", e);
    }
}

