public int read(byte []buf, int offset, int length) throws IOException {
    if (buf == null) {
        throw new NullPointerException();
    }
    if (offset < 0 || length < 0 || offset + length > buf.length) {
        throw new IndexOutOfBoundsException();
    }
    if (length == 0) {
