    }
    return _is.read(buf, offset, length);
}

public static BedRecord valueOf(final String value) {
    if (value == null) {
        throw new NullPointerException("value must not be null");
    }
    String[] tokens = value.split("\t");
    int format = tokens.length;
    switch (format) {
        case 3:
        case 4:
        case 5:
        case 6:
        case 12:
            break;
        default:
            throw new IllegalArgumentException(
                    "value is not valid BED[3,4,5,6,12] format, found " + format + " fields");
    }
    String chrom = tokens[0];
    long chromStart = Long.parseLong(tokens[1]);
    long chromEnd = Long.parseLong(tokens[2]);
    if (format == 3) {
        return new BedRecord(chrom, chromStart, chromEnd);
    }
    String name = tokens[3];
    if (format == 4) {
        return new BedRecord(chrom, chromStart, chromEnd, name);
    }
    String score = tokens[4];
    if (format == 5) {
        return new BedRecord(chrom, chromStart, chromEnd, name, score);
    }
    String strand = tokens[5];
    if (format == 6) {
        return new BedRecord(chrom, chromStart, chromEnd, name, score, strand);
    }
    long thickStart = Long.parseLong(tokens[6]);
    long thickEnd = Long.parseLong(tokens[7]);
    String itemRgb = tokens[8];
    long blockCount = Long.parseLong(tokens[9]);
    String blockSizes = tokens[10];
    String blockStarts = tokens[11];
    return new BedRecord(chrom, chromStart, chromEnd, name, score, strand,
            thickStart, thickEnd, itemRgb, blockCount, blockSizes, blockStarts);
}

