public boolean readBoolean(String message, Boolean defaultValue) throws IOException {
    StringBuilder prompt = new StringBuilder(message);
    if (defaultValue != null) {
        prompt.append(defaultValue ? " [Y/n] " : " [y/N] ");
    }
    System.out.print(prompt.toString());
    BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
    String line = reader.readLine();
    if (line == null || line.trim().isEmpty()) {
        return defaultValue != null && defaultValue;
    }
    line = line.trim().toLowerCase();
    return line.equals("y") || line.equals("yes") || line.equals("true") || line.equals("1");
}

protected String cleanSurt(String surt) {
    if (surt == null) {
        return null;
    }
    String result = surt;
    if (!result.startsWith("(")) {
        result = SURT.fromURI(result);
    }
    if (result.endsWith(")")) {
        result = result + "/";
    }
    return result;
}

public void visitCode() {
    mv.visitCode();
    mv.visitVarInsn(Opcodes.ALOAD, 0);
    mv.visitMethodInsn(Opcodes.INVOKESPECIAL, superName, "<init>", "()V", false);
    for (Map.Entry<String, Object> field : fields.entrySet()) {
        mv.visitVarInsn(Opcodes.ALOAD, 0);
        mv.visitLdcInsn(field.getValue());
        mv.visitFieldInsn(Opcodes.PUTFIELD, className, field.getKey(),
                Type.getDescriptor(field.getValue().getClass()));
    }
    mv.visitInsn(Opcodes.RETURN);
    mv.visitMaxs(0, 0);
    mv.visitEnd();
}

