public static Object convertObjectToDatatype(Object objData, Class<?> classData, Object objDefault) throws Exception {
    if (objData == null) {
        return objDefault;
    }
    if (classData.isInstance(objData)) {
        return objData;
    }
    String str = objData.toString();
    if (classData == String.class) {
        return str;
    } else if (classData == Integer.class || classData == int.class) {
        return Integer.valueOf(str);
    } else if (classData == Long.class || classData == long.class) {
        return Long.valueOf(str);
    } else if (classData == Short.class || classData == short.class) {
        return Short.valueOf(str);
    } else if (classData == Double.class || classData == double.class) {
        return Double.valueOf(str);
    } else if (classData == Float.class || classData == float.class) {
        return Float.valueOf(str);
    } else if (classData == Boolean.class || classData == boolean.class) {
        return Boolean.valueOf(str);
    } else if (classData == BigDecimal.class) {
        return new BigDecimal(str);
    } else if (classData == BigInteger.class) {
        return new BigInteger(str);
    }
    return objDefault;
}

public static <V> Callable<V> buildCallableWithLogging(String name, Callable<V> callable, Object... params) {
    return () -> {
        long start = System.currentTimeMillis();
        if (LOGGER.isDebugEnabled()) {
            LOGGER.debug("Starting '{}' with params {}", name, Arrays.toString(params));
        }
        try {
            V result = callable.call();
            LOGGER.debug("Finished '{}' in {} ms", name, System.currentTimeMillis() - start);
            return result;
        } catch (Exception e) {
            LOGGER.error("Error while executing '{}'", name, e);
            throw e;
        }
    };
}

private NodeList getNodeList(final String xmlString, final String tagName) throws ParserConfigurationException, SAXException, IOException {
    final DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
    factory.setNamespaceAware(true);
    final DocumentBuilder builder = factory.newDocumentBuilder();
    final Document document = builder.parse(new InputSource(new StringReader(xmlString)));
    document.getDocumentElement().normalize();
    return document.getElementsByTagName(tagName);
}

void connect(SocketAddress socketAddress, boolean useSSL) {
    try {
        Socket plainSocket = new Socket();
        plainSocket.connect(socketAddress, connectTimeout);
        if (useSSL) {
            SSLSocketFactory factory = (SSLSocketFactory) SSLSocketFactory.getDefault();
            InetSocketAddress inetAddress = (InetSocketAddress) socketAddress;
            SSLSocket sslSocket = (SSLSocket) factory.createSocket(plainSocket,
                    inetAddress.getHostString(), inetAddress.getPort(), true);
            sslSocket.startHandshake();
            this.socket = sslSocket;
        } else {
            this.socket = plainSocket;
        }
        this.input = new DataInputStream(new BufferedInputStream(socket.getInputStream()));
        this.output = new DataOutputStream(new BufferedOutputStream(socket.getOutputStream()));
    } catch (IOException e) {
        throw new IllegalStateException("Unable to connect to " + socketAddress, e);
    }
}

public static PrefixedProperties createCascadingPrefixProperties(final String[] prefixes) {
    PrefixedProperties current = null;
    for (int i = prefixes.length - 1; i >= 0; i--) {
        current = new PrefixedProperties(current, prefixes[i]);
    }
    if (current == null) {
        current = new PrefixedProperties();
    }
    return current;
}

public static int unsignedIntersect2by2(final short[] set1, final int length1, final short[] set2, final int length2, final short[] buffer) {
    if (length1 == 0 || length2 == 0) {
        return 0;
    }
    int pos = 0;
    int k1 = 0;
    int k2 = 0;
    int s1 = set1[k1] & 0xFFFF;
    int s2 = set2[k2] & 0xFFFF;
    while (true) {
        if (s1 < s2) {
            do {
                if (++k1 == length1) {
                    return pos;
                }
                s1 = set1[k1] & 0xFFFF;
            } while (s1 < s2);
        } else if (s2 < s1) {
            do {
                if (++k2 == length2) {
                    return pos;
                }
                s2 = set2[k2] & 0xFFFF;
            } while (s2 < s1);
        } else {
            buffer[pos++] = (short) s1;
            if (++k1 == length1 || ++k2 == length2) {
                return pos;
            }
            s1 = set1[k1] & 0xFFFF;
            s2 = set2[k2] & 0xFFFF;
        }
    }
}

