private void step(String command, Socket socket, DataInputStream din) throws IOException {
    int option = command.charAt(command.indexOf('_') + 1) - '0';
    boolean includeTurnkey = (option & 0x1) != 0;
    boolean includeInfo = (option & 0x2) != 0;
    String turnkey = includeTurnkey ? din.readUTF() : null;
    String info = includeInfo ? din.readUTF() : null;
    engine.step(turnkey, info);
    DataOutputStream dout = new DataOutputStream(socket.getOutputStream());
    dout.writeUTF("OK");
    dout.flush();
}

