Map<String, String> parseJsStringMap(String input) throws ParseException {
    Map<String, String> result = new LinkedHashMap<>();
    int n = input.length();
    int pos = skipWhitespace(input, 0);
    if (pos >= n || input.charAt(pos) != '{') {
        throw new ParseException("Expected '{' at start of map: " + input, pos);
    }
    pos = skipWhitespace(input, pos + 1);
    if (pos < n && input.charAt(pos) == '}') {
        return result;
    }
    while (true) {
        pos = skipWhitespace(input, pos);
        if (pos >= n || (input.charAt(pos) != '\'' && input.charAt(pos) != '"')) {
            throw new ParseException("Expected a string literal key: " + input, pos);
        }
        StringBuilder key = new StringBuilder();
        pos = readStringLiteral(input, pos, key);

        pos = skipWhitespace(input, pos);
        if (pos >= n || input.charAt(pos) != ':') {
            throw new ParseException("Expected ':' after key: " + input, pos);
        }
        pos = skipWhitespace(input, pos + 1);
        if (pos >= n || (input.charAt(pos) != '\'' && input.charAt(pos) != '"')) {
            throw new ParseException("Expected a string literal value: " + input, pos);
        }
        StringBuilder value = new StringBuilder();
        pos = readStringLiteral(input, pos, value);
        result.put(key.toString(), value.toString());

        pos = skipWhitespace(input, pos);
        if (pos >= n) {
            throw new ParseException("Unterminated map: " + input, pos);
        }
        char c = input.charAt(pos);
        if (c == '}') {
            break;
        }
        if (c != ',') {
            throw new ParseException("Expected ',' or '}': " + input, pos);
        }
        pos++;
    }
    return result;
}

private static boolean matchesPrototypeInstanceVar(Node node, NodeMetadata metadata, String name) {
    int protoIndex = name.indexOf(".prototype.");
    if (protoIndex < 0) {
        return false;
    }
    String typeName = name.substring(0, protoIndex);
    String propertyName = name.substring(protoIndex + ".prototype.".length());

    if (!node.isGetProp() || !node.getLastChild().getString().equals(propertyName)) {
        return false;
    }

    Node owner = node.getFirstChild();
    if (owner.isThis()) {
        String enclosingType = metadata.getEnclosingType();
        return typeName.equals(enclosingType);
    }
    if (owner.isName() || owner.isGetProp()) {
        String ownerType = metadata.getType(owner);
        return typeName.equals(ownerType);
    }
    return false;
}

