public static void actionCopy(PageContext pageContext, lucee.runtime.security.SecurityManager securityManager, Resource source, String strDestination, int nameconflict, String serverPassword, Object acl, int mode, String attributes) throws PageException {
    if (!source.exists()) {
        throw new ApplicationException("source file [" + source + "] doesn't exist");
    }
    if (source.isDirectory()) {
        throw new ApplicationException("source [" + source + "] is a directory, only files can be copied");
    }

    Resource destination = toDestination(pageContext, strDestination, source);
    securityManager.checkFileLocation(pageContext.getConfig(), destination, serverPassword);

    if (destination.isDirectory()) {
        destination = destination.getRealResource(source.getName());
    }

    if (destination.exists()) {
        if (nameconflict == NAMECONFLICT_ERROR) {
            throw new ApplicationException("destination file [" + destination + "] already exists");
        } else if (nameconflict == NAMECONFLICT_SKIP) {
            return;
        }
    }

    try {
        Resource parent = destination.getParentResource();
        if (parent != null && !parent.exists()) {
            parent.mkdirs();
        }
        IOUtil.copy(source, destination);
        if (mode != -1) {
            destination.setMode(mode);
        }
    } catch (IOException e) {
        throw Caster.toPageException(e);
    }
}

public static void compress(int format, Resource source, Resource target, boolean includeBaseFolder, int mode) throws IOException {
    switch (format) {
        case FORMAT_GZIP:
            compressGZip(source, target);
            break;
        case FORMAT_BZIP2:
            compressBZip2(source, target);
            break;
        case FORMAT_TAR:
            compressTar(source, target, includeBaseFolder, mode);
            break;
        case FORMAT_TGZ:
            compressTGZ(source, target, includeBaseFolder, mode);
            break;
        case FORMAT_ZIP:
            compressZip(source, target, includeBaseFolder, mode);
            break;
        default:
            throw new IOException("Unsupported compression format [" + format + "]");
    }
}

public OHLCSeries updateOHLCSeries(String seriesName, double[] newXData, double[] newOpenData, double[] newHighData, double[] newLowData, double[] newCloseData) {
    Map<String, OHLCSeries> seriesMap = getSeriesMap();
    OHLCSeries series = seriesMap.get(seriesName);
    if (series == null) {
        throw new IllegalArgumentException("Series name >" + seriesName + "< not found!");
    }

    if (newXData == null) {
        double[] generatedXData = new double[newCloseData.length];
        for (int i = 0; i < newCloseData.length; i++) {
            generatedXData[i] = i + 1;
        }
        series.replaceData(generatedXData, newOpenData, newHighData, newLowData, newCloseData);
    } else {
        series.replaceData(newXData, newOpenData, newHighData, newLowData, newCloseData);
    }

    return series;
}

