private boolean matchesTime(TimeRestrictedAccess filter) {
    if (filter == null) {
        return true;
    }

    LocalTime start = filter.getStartTime();
    LocalTime end = filter.getEndTime();
    if (start == null || end == null) {
        return true;
    }

    LocalTime current = new DateTime().toLocalTime();
    if (start.isBefore(end)) {
        return !current.isBefore(start) && !current.isAfter(end);
    }

    // The range wraps around midnight.
    return !current.isBefore(start) || !current.isAfter(end);
}

public <T> T callWithTimeout(Callable<T> callable, long duration, TimeUnit unit) throws Exception {
    if (callable == null) {
        throw new NullPointerException("callable must not be null");
    }
    if (duration <= 0) {
        throw new IllegalArgumentException("bad duration: " + duration);
    }

    Future<T> future = executor.submit(callable);
    try {
        return future.get(duration, unit);
    } catch (InterruptedException e) {
        future.cancel(true);
        Thread.currentThread().interrupt();
        throw e;
    } catch (TimeoutException e) {
        future.cancel(true);
        throw new UncheckedTimeoutException(e);
    } catch (ExecutionException e) {
        Throwable cause = e.getCause();
        if (cause instanceof Exception) {
            throw (Exception) cause;
        }
        if (cause instanceof Error) {
            throw (Error) cause;
        }
        throw e;
    }
}

public void connectWithoutProxy() throws SQLException {
    if (!isMasterHostFail()) {
        return;
    }

    resetMasterFailoverData();
    List<HostAddress> hostAddresses = new ArrayList<>(urlParser.getHostAddresses());
    if (isConnectionSequential()) {
        // Nothing to shuffle, keep the declared order.
    } else {
        Collections.shuffle(hostAddresses);
    }

    SQLException lastException = null;
    for (HostAddress hostAddress : hostAddresses) {
        try {
            Protocol protocol = getNewProtocol(getProxy(), urlParser);
            protocol.setHostAddress(hostAddress);
            protocol.connect();
            if (protocol.isConnected()) {
                setMasterHostFail(false);
                setCurrentConnection(protocol);
                return;
            }
        } catch (SQLException e) {
            lastException = e;
        }
    }

    throw (lastException != null) ? lastException
            : new SQLException("No active connection found for master");
}

public void reconnectFailedConnection(SearchFilter searchFilter) throws SQLException {
    if (!searchFilter.isInitialConnection()
            && (isExplicitClosed() || !isMasterHostFail())) {
        return;
    }

    List<HostAddress> hostAddresses = new ArrayList<>(urlParser.getHostAddresses());
    if (!isConnectionSequential()) {
        Collections.shuffle(hostAddresses);
    }

    SQLException lastException = null;
    for (HostAddress hostAddress : hostAddresses) {
        try {
            Protocol protocol = getNewProtocol(getProxy(), urlParser);
            protocol.setHostAddress(hostAddress);
            protocol.connect();
            if (protocol.isConnected()) {
                foundActiveMaster(protocol);
                return;
            }
        } catch (SQLException e) {
            lastException = e;
        }
    }

    if (searchFilter.isInitialConnection()) {
        throw (lastException != null) ? lastException
                : new SQLException("Unable to connect to any host");
    }
}

