protected long parseLong( String value ) {
    if ( value == null ) {
        throw new NumberFormatException( "Cannot parse a null value" );
    }
    String trimmed = value.trim();
    if ( trimmed.isEmpty() ) {
        throw new NumberFormatException( "Cannot parse an empty value" );
    }
    long multiplier = 1L;
    char suffix = Character.toUpperCase( trimmed.charAt( trimmed.length() - 1 ) );
    switch ( suffix ) {
        case 'K':
            multiplier = 1024L;
            break;
        case 'M':
            multiplier = 1024L * 1024L;
            break;
        case 'G':
            multiplier = 1024L * 1024L * 1024L;
            break;
        default:
            break;
    }
    if ( multiplier != 1L ) {
        trimmed = trimmed.substring( 0, trimmed.length() - 1 ).trim();
    }
    return Long.parseLong( trimmed ) * multiplier;
}

public SortedSet<String> getSkinNames(PortletRequest request) {
    SortedSet<String> skinNames = new TreeSet<String>();
    InputStream input = null;
    try {
        input = getClass().getResourceAsStream("/skinList.xml");
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document document = builder.parse(input);
        NodeList nodes = document.getElementsByTagName("skin-key");
        for (int i = 0; i < nodes.getLength(); i++) {
            Node node = nodes.item(i);
            if (node == null) {
                continue;
            }
            String value = node.getTextContent();
            if (value != null) {
                value = value.trim();
                if (!value.isEmpty()) {
                    skinNames.add(value);
                }
            }
        }
    } catch (Exception e) {
        return new TreeSet<String>();
    } finally {
        if (input != null) {
            try {
                input.close();
            } catch (IOException e) {
                // ignore
            }
        }
    }
    return skinNames;
}

