public static UUID makeDeploymentHashForConfig(byte[] deploymentBytes) {
    MessageDigest md;
    try {
        md = MessageDigest.getInstance("MD5");
    } catch (NoSuchAlgorithmException e) {
        throw new RuntimeException("Unable to compute deployment hash", e);
    }
    byte[] digest = md.digest(deploymentBytes);
    assert digest.length == 16;
    ByteBuffer buffer = ByteBuffer.wrap(digest);
    long msb = buffer.getLong();
    long lsb = buffer.getLong();
    return new UUID(msb, lsb);
}

public static void verifySnapshots( final List<String> directories, final Set<String> snapshotNames) {
    if (directories == null || directories.isEmpty()) {
        return;
    }
    for (String directory : directories) {
        File dir = new File(directory);
        if (!dir.exists() || !dir.isDirectory()) {
            continue;
        }
        File[] files = dir.listFiles();
        if (files == null) {
            continue;
        }
        for (File file : files) {
            if (!file.isFile()) {
                continue;
            }
            for (String snapshotName : snapshotNames) {
                if (file.getName().contains(snapshotName)) {
                    verifySnapshot(file);
                }
            }
        }
    }
}

