public Class<Object> matchCaller(String className) {
    if (className == null) {
        return null;
    }
    StackTraceElement[] stack = Thread.currentThread().getStackTrace();
    for (StackTraceElement element : stack) {
        if (className.equals(element.getClassName())) {
            try {
                @SuppressWarnings("unchecked")
                Class<Object> clazz = (Class<Object>) Class.forName(className);
                return clazz;
            } catch (ClassNotFoundException e) {
                return null;
            }
        }
    }
    return null;
}

public void uploadAttachment(RepositoryResourceImpl resource, AttachmentResourceImpl attachment, RepositoryResourceImpl matchingResource) throws RepositoryResourceCreationException, RepositoryBadDataException, RepositoryResourceUpdateException, RepositoryBackendException, RepositoryResourceException {
    AttachmentResourceImpl matchingAttachment = null;
    if (matchingResource != null) {
        matchingAttachment = (AttachmentResourceImpl) matchingResource.getAttachment(attachment.getName());
    }
    if (matchingAttachment == null) {
        // No matching attachment, add a brand new one
        attachment.uploadToMassive(new AddThenDeleteStrategy());
    } else if (!attachment.equivalent(matchingAttachment)) {
        // An attachment with this name exists but differs, update it in place
        attachment.setId(matchingAttachment.getId());
        attachment.uploadToMassive(new UpdateInPlaceStrategy());
    }
}

