AtomSymbol generatePeriodicSymbol(final int number, final int hydrogens, final int mass, final int charge, final int unpaired, HydrogenPosition position) {
    TextOutline element = new TextOutline(Elements.ofNumber(number).symbol(), font);
    TextOutline hydrogenAdjunct = null;
    TextOutline hydrogenCount = null;
    TextOutline chargeAdjunct = null;
    TextOutline massAdjunct = null;

    if (hydrogens > 0) {
        hydrogenAdjunct = new TextOutline("H", font);
        if (hydrogens > 1) {
            hydrogenCount = new TextOutline(Integer.toString(hydrogens), font).resize(scriptSize, scriptSize);
        }
    }
    if (charge != 0) {
        chargeAdjunct = new TextOutline(chargeAdjunctText(charge, unpaired), font).resize(scriptSize, scriptSize);
    }
    if (mass > 0) {
        massAdjunct = new TextOutline(Integer.toString(mass), font).resize(scriptSize, scriptSize);
    }

    final List<TextOutline> adjuncts = new ArrayList<TextOutline>();
    if (massAdjunct != null) {
        adjuncts.add(massAdjunct);
    }
    if (hydrogenAdjunct != null) {
        adjuncts.add(hydrogenAdjunct);
    }
    if (hydrogenCount != null) {
        adjuncts.add(hydrogenCount);
    }
    if (chargeAdjunct != null) {
        adjuncts.add(chargeAdjunct);
    }

    return new AtomSymbol(element, adjuncts);
}

public void process() {
    try {
        ZipEntry entry;
        while ((entry = zipIn.getNextEntry()) != null) {
            String name = entry.getName();
            if (isRemoved(name)) {
                zipIn.closeEntry();
                continue;
            }
            String newName = rename(name);
            zipOut.putNextEntry(new ZipEntry(newName));
            byte[] buffer = new byte[4096];
            int read;
            while ((read = zipIn.read(buffer)) != -1) {
                zipOut.write(buffer, 0, read);
            }
            zipOut.closeEntry();
            zipIn.closeEntry();
        }
        zipOut.finish();
    } catch (IOException e) {
        throw new RuntimeException("Failed to process Zip stream", e);
    }
}

