private void extractFilesFromDependencies(Collection<Artifact> dependencies, File destFolder) throws IOException, MojoExecutionException {
    for (Artifact artifact : dependencies) {
        File dependency = artifact.getFile();
        if (dependency == null || !dependency.isFile() || !dependency.getName().endsWith(".jar")) {
            continue;
        }
        try (JarFile jar = new JarFile(dependency)) {
            Enumeration<JarEntry> entries = jar.entries();
            while (entries.hasMoreElements()) {
                JarEntry entry = entries.nextElement();
                String name = entry.getName();
                if (entry.isDirectory() || !name.endsWith(THRIFT_FILE_SUFFIX)) {
                    continue;
                }
                File destination = new File(destFolder, name);
                if (destination.isFile() && dependency.lastModified() <= destination.lastModified()) {
                    continue;
                }
                File parent = destination.getParentFile();
                if (parent != null && !parent.exists() && !parent.mkdirs()) {
                    throw new MojoExecutionException("Could not create directory " + parent);
                }
                try (InputStream in = jar.getInputStream(entry)) {
                    Files.copy(in, destination.toPath(), StandardCopyOption.REPLACE_EXISTING);
                }
            }
        }
    }
}

