private SwingBackgroundTask<Sudoku> createTask(final String[] puzzle, final int populationSize, final int eliteCount) {
    return new SwingBackgroundTask<Sudoku>() {
        @Override
        protected Sudoku performTask() {
            Random rng = new MersenneTwisterRNG();

            List<EvolutionaryOperator<Sudoku>> operators = new ArrayList<>(2);
            operators.add(new SudokuRowMutation(new PoissonGenerator(2, rng),
                    new DiscreteUniformGenerator(1, 8, rng)));
            operators.add(new SudokuVerticalCrossover());

            EvolutionEngine<Sudoku> engine = new GenerationalEvolutionEngine<>(
                    new SudokuFactory(puzzle),
                    new EvolutionPipeline<>(operators),
                    new SudokuEvaluator(),
                    new TournamentSelection(new Probability(0.85d)),
                    rng);
            engine.addEvolutionObserver(evolutionMonitor.getGUIObserver());

            return engine.evolve(populationSize, eliteCount, new TargetFitness(0, false));
        }

        @Override
        protected void postProcessing(Sudoku result) {
            // Evolution has finished; the GUI has already been updated by the observer.
        }
    };
}

