    } catch (UnsupportedEncodingException e) {
        throw new RuntimeException(e);
    }
}

public synchronized String doLayout(ILoggingEvent event) {
    StringBuilder sb = new StringBuilder(256);
    sb.append("<log4j:event logger=\"");
    sb.append(Transform.escapeTags(event.getLoggerName()));
    sb.append("\" timestamp=\"");
    sb.append(event.getTimeStamp());
    sb.append("\" level=\"");
    sb.append(Transform.escapeTags(String.valueOf(event.getLevel())));
    sb.append("\" thread=\"");
    sb.append(Transform.escapeTags(event.getThreadName()));
    sb.append("\">\r\n");

    sb.append("  <log4j:message>");
    sb.append(Transform.escapeTags(event.getFormattedMessage()));
    sb.append("</log4j:message>\r\n");

    IThrowableProxy tp = event.getThrowableProxy();
    if (tp != null) {
        StringBuilder throwable = new StringBuilder();
        while (tp != null) {
            throwable.append(tp.getClassName()).append(": ").append(tp.getMessage()).append(LINE_SEPARATOR);
            for (StackTraceElementProxy step : tp.getStackTraceElementProxyArray()) {
                throwable.append('\t').append(step.toString()).append(LINE_SEPARATOR);
            }
            tp = tp.getCause();
        }
        sb.append("  <log4j:throwable><![CDATA[");
        sb.append(throwable);
        sb.append("]]></log4j:throwable>\r\n");
    }

    sb.append("</log4j:event>\r\n\r\n");
    return sb.toString();
}

