public static Map<String, AttributeValueUpdate> toUpdateItem(final Object entity) {
    if (entity == null) {
        throw new IllegalArgumentException("entity cannot be null");
    }

    final Map<String, AttributeValueUpdate> updateItem = new LinkedHashMap<>();

    if (entity instanceof DirtyMarker) {
        final DirtyMarker dirtyMarker = (DirtyMarker) entity;

        for (final String propName : dirtyMarker.dirtyPropNames()) {
            final Object propValue = ClassUtil.getPropValue(entity, propName);
            updateItem.put(propName,
                    new AttributeValueUpdate(attr(propValue), AttributeAction.PUT));
        }
    } else {
        for (final Map.Entry<String, Method> entry : ClassUtil.getPropGetMethodList(entity.getClass()).entrySet()) {
            final Object propValue = ClassUtil.invokeMethod(entity, entry.getValue());
            updateItem.put(entry.getKey(),
                    new AttributeValueUpdate(attr(propValue), AttributeAction.PUT));
        }
    }

    return updateItem;
}

protected static String getHumanReadableXml(final Node node) {
    try {
        final Transformer transformer = TransformerFactory.newInstance().newTransformer();
        transformer.setOutputProperty(OutputKeys.OMIT_XML_DECLARATION, "yes");
        transformer.setOutputProperty(OutputKeys.INDENT, "yes");
        transformer.setOutputProperty("{http://xml.apache.org/xslt}indent-amount", "2");

        final StringWriter writer = new StringWriter();
        final NodeList children = node.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            transformer.transform(new DOMSource(children.item(i)), new StreamResult(writer));
        }
        return writer.toString();
    } catch (final TransformerException e) {
        throw new RuntimeException("Failed to convert node to human readable XML", e);
    }
