private void processToken(String tokenData) throws JSONException, LoginException {
    final JSONObject token = new JSONObject(tokenData);

    if (!token.has("username")) {
        throw new LoginException("Token does not contain a username");
    }

    final String username = token.getString("username");
    if (username == null || username.isEmpty()) {
        throw new LoginException("Token contains an empty username");
    }

    if (token.has("tokenExpires")) {
        final String expires = token.getString("tokenExpires");
        final Date expiryDate = javax.xml.bind.DatatypeConverter.parseDateTime(expires).getTime();
        if (expiryDate.before(new Date())) {
            throw new LoginException("Token has expired");
        }
    }

    sharedState.put("javax.security.auth.login.name", username);
}

