public synchronized long read(long offset, final ByteBuffer buf) {
    try {
        final ByteBuffer header = ByteBuffer.allocate(HEADER_LENGTH);
        channel.read(header, offset);
        header.flip();

        final int dataLen = header.getInt();

        buf.clear();
        buf.limit(dataLen);
        channel.read(buf, offset + HEADER_LENGTH);
        buf.flip();

        return offset + HEADER_LENGTH + dataLen + FOOTER_LENGTH;
    } catch (final IOException e) {
        throw new RuntimeException("Unable to read block at offset " + offset, e);
    }
}

private void parseQueryError(boolean lastChunk) {
    while (true) {
        final int index = findSectionClose(responseContent);
        if (index < 0) {
            if (lastChunk && responseContent.readableBytes() > 0) {
                throw new IllegalStateException("Incomplete error section in response");
            }
            return;
        }

        final String section = responseContent.readCharSequence(index, CharsetUtil.UTF_8).toString();
        responseContent.skipBytes(1);

        if (section.trim().isEmpty()) {
            continue;
        }

        errors.add(section);
    }
}

