private void printAlignedBlock(String separator, String terminator) {
    final int columns = alignments.size();
    final int[] widths = new int[columns];

    for (final String[] row : rows) {
        for (int col = 0; col < columns && col < row.length; col++) {
            if (row[col] != null) {
                widths[col] = Math.max(widths[col], row[col].length());
            }
        }
    }

    for (int r = 0; r < rows.size(); r++) {
        final String[] row = rows.get(r);
        final StringBuilder line = new StringBuilder();
        for (int col = 0; col < columns; col++) {
            final String value = col < row.length && row[col] != null ? row[col] : "";
            final int padding = widths[col] - value.length();
            if (alignments.get(col) == Alignment.RIGHT) {
                for (int p = 0; p < padding; p++) {
                    line.append(' ');
                }
                line.append(value);
            } else {
                line.append(value);
                for (int p = 0; p < padding; p++) {
                    line.append(' ');
                }
            }
        }
        line.append(r == rows.size() - 1 ? terminator : separator);
        out.println(line.toString());
    }
}

public ActivityInfo addReceiverIfNotPresent(ComponentName componentName) {
    final String packageName = componentName.getPackageName();
    PackageInfo packageInfo = packageInfos.get(packageName);
    if (packageInfo == null) {
        packageInfo = addPackage(packageName);
    }
    if (packageInfo.applicationInfo == null) {
        packageInfo.applicationInfo = new ApplicationInfo();
        packageInfo.applicationInfo.packageName = packageName;
    }

    if (packageInfo.receivers != null) {
        for (final ActivityInfo receiver : packageInfo.receivers) {
            if (receiver.name.equals(componentName.getClassName())) {
                return receiver;
            }
        }
    }

    final ActivityInfo receiverInfo = new ActivityInfo();
    receiverInfo.packageName = packageName;
    receiverInfo.name = componentName.getClassName();
    receiverInfo.applicationInfo = packageInfo.applicationInfo;

    final List<ActivityInfo> receivers = new ArrayList<>();
    if (packageInfo.receivers != null) {
        Collections.addAll(receivers, packageInfo.receivers);
    }
    receivers.add(receiverInfo);
    packageInfo.receivers = receivers.toArray(new ActivityInfo[0]);

    return receiverInfo;
}

