public static List<weka.core.Attribute> buildAttributes(DataDictionary dataDict) {
    final List<weka.core.Attribute> attributes = new ArrayList<>();

    for (final DataField dataField : dataDict.getDataFields()) {
        final String name = dataField.getName().getValue();

        switch (dataField.getOptype()) {
            case CATEGORICAL:
            case ORDINAL:
                final List<String> values = new ArrayList<>();
                for (final Value value : dataField.getValues()) {
                    values.add(value.getValue());
                }
                attributes.add(new weka.core.Attribute(name, values));
                break;
            case CONTINUOUS:
            default:
                attributes.add(new weka.core.Attribute(name));
                break;
        }
    }

    return Collections.unmodifiableList(attributes);
}

