def random_expr(depth, vlist, ops):
    """Generate a random expression tree.

    Args:
        depth: At least one leaf will be this many levels down from the top.
        vlist: A list of chars. These chars are randomly selected as leaf
            values.
        ops: A list of ExprOp instances.

    Returns:
        An ExprNode instance which is the root of the generated expression
        tree.
    """
    import random

    if depth <= 0:
        return random.choice(vlist)

    max_depth_for_leaf = random.randint(0, depth - 1)

    def get_children(child_depth):
        if child_depth == max_depth_for_leaf:
            return random_expr(depth - 1, vlist, ops)
        return random_expr(random.randint(0, depth - 1), vlist, ops)

    op = random.choice(ops)
    return ExprNode(get_children(0), get_children(1), op)

