import subprocess


def _execute_install_command(cmd, parse_output, errors, parsed_packages):
    """Execute a command for the install operation.

    On failure the command's error output is appended to ``errors``.
    On success, when ``parse_output`` is true, the parsed packages are
    added to the ``parsed_packages`` dictionary.
    """
    proc = subprocess.run(
        cmd,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        universal_newlines=True,
    )
    if proc.returncode != 0:
        message = (proc.stderr or proc.stdout or "").strip()
        errors.append(message)
        return

    if not parse_output:
        return

    for line in proc.stdout.splitlines():
        line = line.strip()
        if not line:
            continue
        if "==" in line:
            name, _, version = line.partition("==")
            parsed_packages[name.strip()] = version.strip()
        else:
            parts = line.split()
            if len(parts) >= 2:
                parsed_packages[parts[0]] = parts[1]

