try:
    import urllib.request as _urllib_request
except ImportError:  # pragma: no cover
    import urllib2 as _urllib_request


def download(self, url, filename, resume=False):
    """Download the given url to the given file.

    When the download is aborted by the user the partially downloaded
    file is removed again.
    """
    headers = {}
    mode = "wb"
    if resume and os.path.exists(filename):
        offset = os.path.getsize(filename)
        if offset:
            headers["Range"] = "bytes=%d-" % offset
            mode = "ab"

    request = _urllib_request.Request(url, headers=headers)
    try:
        response = _urllib_request.urlopen(request)
        with open(filename, mode) as fp:
            shutil.copyfileobj(response, fp)
    except (KeyboardInterrupt, Exception):
        if os.path.exists(filename):
            try:
                os.remove(filename)
            except OSError:
                pass
        raise
    return filename

def timeline(self):
    """
    >>> Cluster(0, 0, 0, 0, 0, 0, 0, 0).timeline
    0
    >>> Cluster(0, 0, 0, 0, 0, 0, 0, TimelineHistory.from_node(1, '[]')).timeline
    1
    >>> Cluster(0, 0, 0, 0, 0, 0, 0, TimelineHistory.from_node(1, '[["a"]]')).timeline
    0
    """
    if self.history:
        if self.history.lines:
            try:
                return int(self.history.lines[-1][0]) + 1
            except (TypeError, ValueError, IndexError):
                return 0
        elif self.history.value == '[]':
            return 1
    return 0

import os
import socket
import subprocess
import time


def launch_minecraft(ports=[], wait_timeout=360):
    """Launch Malmo Minecraft Mod in one or more clients on the given ports."""
    if not ports:
        ports = [10000]

    malmo_dir = os.environ.get("MALMO_MINECRAFT_ROOT")
    if not malmo_dir:
        raise RuntimeError("MALMO_MINECRAFT_ROOT environment variable not set.")

    launcher = os.path.join(malmo_dir, "launchClient.sh")
    processes = []
    for port in ports:
        proc = subprocess.Popen(
            [launcher, "-port", str(port)], cwd=malmo_dir
        )
        processes.append((port, proc))

    deadline = time.time() + wait_timeout
    for port, proc in processes:
        while time.time() < deadline:
            sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            sock.settimeout(1)
            try:
                if sock.connect_ex(("127.0.0.1", port)) == 0:
                    break
            finally:
                sock.close()
            time.sleep(1)
        else:
            raise RuntimeError(
                "Timed out waiting for Minecraft client on port %d" % port
            )
    return processes

import random


def random_walk(self, path_length, alpha=0, rand=random.Random(), start=None):
    """Returns a truncated random walk.

    path_length: Length of the random walk.
    alpha: probability of restarts.
    start: the start node of the random walk.
    """
    G = self
    if start is not None:
        path = [start]
    else:
        path = [rand.choice(list(G.keys()))]

    while len(path) < path_length:
        cur = path[-1]
        if len(G[cur]) > 0:
            if rand.random() >= alpha:
                path.append(rand.choice(G[cur]))
            else:
                path.append(path[0])
        else:
            break

    return [str(node) for node in path]

