from collections import defaultdict


def _traverse_options(cls, obj, opt_type, opts, specs=None, keyfn=None,
                      defaults=True):
    """Traverses the supplied object getting all options in opts for the
    specified opt_type and specs, including plotting class defaults, and
    optionally grouping the result by ``keyfn``.
    """
    def lookup(x):
        options = cls.lookup_options(x, opt_type)
        selected = {o: options.options[o]
                    for o in opts if o in options.options}
        if opt_type == "plot" and defaults:
            plot = Store.registry[cls.current_backend].get(type(x))
            selected["defaults"] = {
                o: getattr(plot, o) for o in opts
                if o not in selected and plot is not None and hasattr(plot, o)
            }
        key = keyfn(x) if keyfn else None
        return (key, selected)

    traversed = obj.traverse(lookup, specs)
    options = defaultdict(lambda: defaultdict(list))
    default_opts = defaultdict(lambda: defaultdict(list))
    for key, opt_group in traversed:
        defaults_group = opt_group.pop("defaults", {})
        for opt, v in opt_group.items():
            options[key][opt].append(v)
        for opt, v in defaults_group.items():
            default_opts[key][opt].append(v)

    for key in default_opts:
        for opt, v in default_opts[key].items():
            if opt not in options[key]:
                options[key][opt] = v

    return {key: dict(value) for key, value in options.items()}

import time


def validate_resource(self, value):
    """Validate the network resource with exponential backoff."""
    max_retries = 5
    delay = 1
    last_error = None
    for attempt in range(max_retries):
        try:
            return self._validate_resource(value)
        except Exception as error:  # noqa: BLE001
            last_error = error
            if attempt == max_retries - 1:
                break
            time.sleep(delay)
            delay *= 2
    raise last_error

