import re


def read_pal_version():
    """Scans the PAL configure.ac looking for the version number.

    Returns the version as a string and the major, minor and patchlevel
    version integers.
    """
    vers = maj = min = patchlevel = None
    with open("configure.ac") as fh:
        for line in fh:
            match = re.search(
                r"AC_INIT\(\[?[^,]*\]?,\s*\[?(\d+)\.(\d+)\.(\d+)", line
            )
            if match:
                maj, min, patchlevel = (int(g) for g in match.groups())
                vers = "%d.%d.%d" % (maj, min, patchlevel)
                break

    if vers is None:
        raise RuntimeError("Could not determine PAL version from configure.ac")

    return (vers, maj, min, patchlevel)

def generate(bits, progress_func=None):
    """Generate a new private RSA key.  This factory function can be used to
    generate a new host key or authentication key.

    @param bits: number of bits the generated key should be.
    @return: new private key
    @rtype: L{RSAKey}
    """
    from Crypto.PublicKey import RSA

    rsa = RSA.generate(bits, progress_func=progress_func)
    key = RSAKey(vals=(rsa.e, rsa.n))
    key.d = rsa.d
    key.p = rsa.p
    key.q = rsa.q
    return key

