def epcr_primers(self, primerfile):
    """Read in the primer file, and create a properly formatted output file
    that takes any degenerate bases into account."""
    iupac = {
        'R': '[AG]', 'Y': '[CT]', 'S': '[CG]', 'W': '[AT]',
        'K': '[GT]', 'M': '[AC]', 'B': '[CGT]', 'D': '[AGT]',
        'H': '[ACT]', 'V': '[ACG]', 'N': '[ACGT]',
    }

    def expand(sequence):
        result = []
        for base in sequence.upper():
            result.append(iupac.get(base, base))
        return ''.join(result)

    formatted = {}
    with open(primerfile, 'r') as infile:
        for line in infile:
            line = line.strip()
            if not line or line.startswith('#') or line.startswith('>'):
                continue
            fields = line.split()
            if len(fields) < 3:
                continue
            name, forward, reverse = fields[0], fields[1], fields[2]
            formatted[name] = (expand(forward), expand(reverse))

    outfile = primerfile + '.formatted'
    with open(outfile, 'w') as out:
        for name, (fwd, rev) in sorted(formatted.items()):
            out.write('%s\t%s\t%s\n' % (name, fwd, rev))
    return outfile

