import math


def impact_parameter(a, R, inc, ecc=0, w=0, return_occ=False):
    """a in AU, R in Rsun, inc & w in radians."""
    AU_IN_RSUN = 215.032
    a_rsun = a * AU_IN_RSUN
    ratio = a_rsun / R

    if ecc:
        ecc_factor_transit = (1 - ecc ** 2) / (1 + ecc * math.sin(w))
    else:
        ecc_factor_transit = 1.0

    b_transit = ratio * math.cos(inc) * ecc_factor_transit

    if return_occ:
        if ecc:
            ecc_factor_occ = (1 - ecc ** 2) / (1 - ecc * math.sin(w))
        else:
            ecc_factor_occ = 1.0
        b_occ = ratio * math.cos(inc) * ecc_factor_occ
        return b_transit, b_occ

    return b_transit

