def authorizeClientRequest(self, request):
    """Checks the authorization permissions of the bearer token passed, and
    determines whether the sender is permitted to make the request housed in
    the payload."""
    try:
        header = request.get('header', request)
        auth = header.get('Authorization', '')
    except AttributeError:
        auth = getattr(request, 'Authorization', '')

    if not auth:
        return False, "No authorization header provided"

    parts = auth.split()
    if len(parts) != 2 or parts[0].lower() != 'bearer':
        return False, "Malformed authorization header"

    token = parts[1]
    if token in self._validTokens:
        return True, "Authorized"
    return False, "Invalid token"

def wrap_multipart_params(func):
    """A middleware that parses the multipart request body and adds the
    parsed content to the `multipart_params` attribute.

    This middleware also merges the parsed value with the existing
    `params` attribute.
    """
    import functools
    try:
        import cgi
        from io import BytesIO
    except ImportError:
        cgi = None

    @functools.wraps(func)
    def wrapper(request, *args, **kwargs):
        content_type = ""
        headers = getattr(request, "headers", {}) or {}
        for key, value in dict(headers).items():
            if key.lower() == "content-type":
                content_type = value or ""
                break

        multipart_params = {}
        if content_type.startswith("multipart/form-data") and cgi is not None:
            body = getattr(request, "body", b"") or b""
            if isinstance(body, str):
                body = body.encode("utf-8")
            environ = {
                "REQUEST_METHOD": "POST",
                "CONTENT_TYPE": content_type,
                "CONTENT_LENGTH": str(len(body)),
            }
            form = cgi.FieldStorage(
                fp=BytesIO(body), environ=environ, keep_blank_values=True
            )
            for key in form.keys():
                item = form[key]
                if isinstance(item, list):
                    multipart_params[key] = [i.value for i in item]
                else:
                    multipart_params[key] = item.value

        setattr(request, "multipart_params", multipart_params)
        params = dict(getattr(request, "params", {}) or {})
        params.update(multipart_params)
        setattr(request, "params", params)
        return func(request, *args, **kwargs)

    return wrapper

import subprocess

def branch(options=False, *args, **kwargs):
    """Run "$ git branch" with those options.

    If not options then return name of the branch currently checked out.
    """
    if not options:
        out = subprocess.check_output(
            ["git", "rev-parse", "--abbrev-ref", "HEAD"]
        )
        return out.decode("utf-8").strip()

    cmd = ["git", "branch"]
    if isinstance(options, str):
        cmd.append(options)
    elif isinstance(options, (list, tuple)):
        cmd.extend(options)
    cmd.extend(args)
    return subprocess.check_output(cmd).decode("utf-8")

def get_element(text_or_tree_or_element):
    """Get back an ET.Element for several possible input formats."""
    from xml.etree import ElementTree as ET

    obj = text_or_tree_or_element
    if isinstance(obj, ET.ElementTree):
        return obj.getroot()
    if hasattr(obj, "tag") and hasattr(obj, "attrib"):
        return obj
    if isinstance(obj, bytes):
        obj = obj.decode("utf-8")
    if isinstance(obj, str):
        return ET.fromstring(obj)
    raise TypeError("Cannot convert %r to an Element" % (type(obj),))

def __parse_xml_response(self, response):
    """Parse response and get text result."""
    from xml.etree import ElementTree as ET

    text = getattr(response, "text", response)
    if isinstance(text, bytes):
        text = text.decode("utf-8")
    root = ET.fromstring(text)
    results = []
    for elem in root.iter():
        if elem.text and elem.text.strip():
            results.append(elem.text.strip())
    return "".join(results)

