import os
import ast

def find_modules_with_decorators(path, decorator_module, decorator_name):
    """Finds all the modules decorated with the specified decorator in the
    path, file or module specified.
    """
    matches = []

    def _scan(filepath):
        try:
            with open(filepath, "r") as fh:
                source = fh.read()
            tree = ast.parse(source, filepath)
        except (OSError, SyntaxError):
            return
        for node in ast.walk(tree):
            decorators = getattr(node, "decorator_list", None)
            if not decorators:
                continue
            for dec in decorators:
                target = dec.func if isinstance(dec, ast.Call) else dec
                if isinstance(target, ast.Attribute):
                    dec_name = target.attr
                elif isinstance(target, ast.Name):
                    dec_name = target.id
                else:
                    continue
                if dec_name == decorator_name:
                    matches.append(filepath)
                    return

    if os.path.isfile(path):
        _scan(path)
    else:
        for root, _dirs, files in os.walk(path):
            for name in files:
                if name.endswith(".py"):
                    _scan(os.path.join(root, name))
    return matches

import hashlib

def hash(value, arg):
    """Returns a hex-digest of the passed in value for the hash algorithm
    given.
    """
    try:
        hasher = hashlib.new(arg)
    except ValueError:
        raise ValueError("%r is not a valid hash algorithm." % arg)
    data = value
    if isinstance(data, str):
        data = data.encode("utf-8")
    hasher.update(data)
    return hasher.hexdigest()

def ParseExcelXMLFile(filename):
    """Parse an excel file (SpreadsheetML XML format)."""
    from xml.etree import ElementTree as ET

    NS = "urn:schemas-microsoft-com:office:spreadsheet"

    class _Worksheet(object):
        def __init__(self, name, rows):
            self.name = name
            self._rows = rows

        def GetCellValue(self, row, col):
            try:
                return self._rows[row - 1][col - 1]
            except (IndexError, KeyError):
                return None

    class _Workbook(object):
        def __init__(self, worksheets):
            self._worksheets = worksheets

        def GetWorksheets(self, index):
            return self._worksheets[index]

    tree = ET.parse(filename)
    root = tree.getroot()
    worksheets = []
    for ws in root.findall("{%s}Worksheet" % NS):
        name = ws.get("{%s}Name" % NS)
        rows = []
        table = ws.find("{%s}Table" % NS)
        if table is None:
            worksheets.append(_Worksheet(name, rows))
            continue
        for row in table.findall("{%s}Row" % NS):
            cells = []
            col = 0
            for cell in row.findall("{%s}Cell" % NS):
                idx = cell.get("{%s}Index" % NS)
                if idx is not None:
                    col = int(idx) - 1
                while len(cells) < col:
                    cells.append(None)
                data = cell.find("{%s}Data" % NS)
                cells.append(data.text if data is not None else None)
                col += 1
            rows.append(cells)
        worksheets.append(_Worksheet(name, rows))
    return _Workbook(worksheets)

import importlib

def __load_class_from_name(self, class_name):
    """Load the class from the ``class_name`` provided."""
    try:
        if "." in class_name:
            module_name, _, cls_name = class_name.rpartition(".")
            module = importlib.import_module(module_name)
            return getattr(module, cls_name)
        import sys
        for module in list(sys.modules.values()):
            if module and hasattr(module, class_name):
                return getattr(module, class_name)
        raise AttributeError(class_name)
    except (ImportError, AttributeError, ValueError) as e:
        raise SerializationException(
            "Unable to load class: {}. Error: {}".format(class_name, str(e))
        )

