def _torque_queue_nodes(queue):
    """Retrieve the nodes available for a queue.

    Parses out nodes from `acl_hosts` in qstat -Qf and extracts the initial
    names of nodes used in pbsnodes.
    """
    nodes = []
    out = subprocess.check_output(["qstat", "-Qf", queue])
    if isinstance(out, bytes):
        out = out.decode("utf-8")

    lines = out.replace("\n\t", "").splitlines()
    for line in lines:
        if "acl_hosts" in line:
            hosts = line.split("=", 1)[1].strip()
            for host in hosts.split(","):
                host = host.strip()
                if host:
                    nodes.append(host.split(".")[0])
    return nodes

