def read_map(fo, writer_schema, reader_schema=None):
    """Maps are encoded as a series of blocks. Each block consists of a long
    count value, followed by that many key/value pairs. A block with count
    zero indicates the end of the map.
    """
    read_map_out = {}
    block_count = read_long(fo)
    while block_count != 0:
        if block_count < 0:
            block_count = -block_count
            read_long(fo)  # block size in bytes, ignored
        for _ in range(block_count):
            key = read_utf8(fo)
            read_map_out[key] = read_data(
                fo, writer_schema["values"],
                reader_schema["values"] if reader_schema else None,
            )
        block_count = read_long(fo)
    return read_map_out

