import xml.etree.ElementTree as ElementTree


def parse_results_file(resultFile, run_set_id=None, ignore_errors=False):
    """Parse an XML results file and return the top-level ``result`` element."""
    try:
        tree = ElementTree.parse(resultFile)
    except (ElementTree.ParseError, OSError):
        if ignore_errors:
            return None
        raise

    result_elem = tree.getroot()
    if result_elem.tag not in ("result", "test"):
        message = "XML file '{}' is not a valid benchmark result file.".format(resultFile)
        if ignore_errors:
            return None
        raise ValueError(message)

    if run_set_id is not None:
        for run in result_elem.findall("run"):
            run.set("runset", run_set_id)

    return result_elem

def run_pygal(data, options=[], format='svg'):
    """Run a pygal program contained in ``data`` and return the rendered image."""
    import pygal

    namespace = {'pygal': pygal}
    exec(compile(data, '<pygal>', 'exec'), namespace)

    chart = namespace.get('chart')
    if chart is None:
        raise ValueError("pygal source must assign the resulting chart to 'chart'")

    fmt = (format or 'svg').lower()
    if fmt == 'svg':
        return chart.render()
    if fmt == 'png':
        return chart.render_to_png()
    if fmt == 'etree':
        return chart.render_tree()
    raise ValueError("unsupported pygal output format: {!r}".format(format))

import time


def master_main(painter, router, select, delay):
    """Loop until interrupted, consuming results and repainting on ``delay``."""
    last_paint = 0.0
    try:
        while True:
            try:
                msg = select.get(timeout=delay)
            except TimeoutError:
                msg = None
            if msg is not None:
                painter.parse_output(msg.unpickle())
            now = time.time()
            if now - last_paint >= delay:
                painter.repaint()
                last_paint = now
    except KeyboardInterrupt:
        pass

