def _ParseRelationshipsXMLFile(self, xml_data):
    """Parse the relationships XML file (``_rels/.rels``).

    Returns a list of property file paths relative to the root of the ZIP file.
    """
    try:
        xml_root = ElementTree.fromstring(xml_data)
    except ElementTree.ParseError as exception:
        raise zipfile.BadZipfile(
            'Unable to parse relationships XML file with error: {0!s}'.format(
                exception))

    property_files = []
    for xml_element in xml_root.iter():
        type_attribute = xml_element.get('Type')
        if type_attribute and type_attribute.endswith('/metadata/core-properties'):
            target = xml_element.get('Target')
            if target:
                property_files.append(target)

    return property_files

