def babel_compile(source, **kwargs):
    """Compiles the given ``source`` from ES6 to ES5 using Babeljs."""
    from subprocess import Popen, PIPE

    presets = kwargs.pop("presets", "es2015")
    command = ["babel", "--presets", presets]
    for key, value in kwargs.items():
        command.append("--%s" % key.replace("_", "-"))
        if value is not True:
            command.append(str(value))

    proc = Popen(command, stdin=PIPE, stdout=PIPE, stderr=PIPE)
    out, err = proc.communicate(source.encode("utf-8"))
    if proc.returncode != 0:
        raise RuntimeError(
            "Babel compilation failed: %s"
            % err.decode("utf-8", "replace").strip()
        )
    return out.decode("utf-8")

def send_until(self,
               send,
               regexps,
               not_there=False,
               cadence=2,
               retries=100,
               echo=None,
               note=None,
               debug_command=None,
               pause_point_on_fail=True,
               nonewline=False,
               loglevel=logging.INFO):
    """Send string on a regular cadence until a string is either seen, or
    the timeout is triggered.
    """
    import re
    import time

    if note is not None:
        self.log(note, level=loglevel)

    if isinstance(regexps, str):
        regexps = [regexps]

    for _attempt in range(retries):
        self.send(send, echo=echo, nonewline=nonewline, loglevel=loglevel)
        output = self.recv()
        if output is None:
            output = ""

        matched = any(re.search(regexp, output) for regexp in regexps)

        if not_there:
            if not matched:
                return True
        else:
            if matched:
                return True

        if debug_command is not None:
            self.send(debug_command, echo=echo, loglevel=loglevel)

        time.sleep(cadence)

    if pause_point_on_fail:
        self.pause_point(
            "send_until failed for: %s" % send, colour="31"
        )
    return False

def _tabulate(self, info_dict, col_widths, changed, order, bounds_dict):
    """Returns the supplied information as a table suitable for
    printing or paging.
    """
    lines = []

    # Header row.
    header = "".join(
        str(col).ljust(col_widths[col]) for col in order
    )
    lines.append(header)
    lines.append("=" * len(header))

    for name in sorted(info_dict):
        info = info_dict[name]
        cells = []
        for col in order:
            if col == "name":
                value = name
            elif col == "bounds":
                value = bounds_dict.get(name, "")
            else:
                value = info.get(col, "")
            cell = str(value).ljust(col_widths[col])
            cells.append(cell)
        row = "".join(cells)
        if name in changed:
            row += " *"
        lines.append(row)

    return "\n".join(lines)

