def from_json(cls, json_data):
    """Tries to convert a JSON representation to an object of the same
    type as self.
    """
    import json

    try:
        data = json.loads(json_data)
    except (ValueError, TypeError) as err:
        raise ValueError("Invalid JSON: %s" % str(err))

    if hasattr(cls, "_fromJSON"):
        return cls._fromJSON(data)

    if not isinstance(data, dict):
        raise TypeError(
            "Expected a JSON object to build %s, got %r"
            % (cls.__name__, type(data))
        )

    return cls(**data)

