def for_instances(cls, data, multi=None):
    """Return a Capabilities object describing the given Instances.

    The minimum number of instances is not set. When ``multi`` is provided the
    multi-instance structure of the data is taken into account as well.
    """
    capabilities = cls(data)

    for index in range(data.num_attributes):
        attribute = data.attribute(index)
        if attribute.is_nominal:
            capabilities.enable("NOMINAL_ATTRIBUTES")
        elif attribute.is_numeric:
            capabilities.enable("NUMERIC_ATTRIBUTES")
        elif attribute.is_date:
            capabilities.enable("DATE_ATTRIBUTES")
        elif attribute.is_string:
            capabilities.enable("STRING_ATTRIBUTES")

    if data.class_index >= 0:
        class_attribute = data.class_attribute
        if class_attribute.is_nominal:
            capabilities.enable("NOMINAL_CLASS")
        elif class_attribute.is_numeric:
            capabilities.enable("NUMERIC_CLASS")
        elif class_attribute.is_date:
            capabilities.enable("DATE_CLASS")
        elif class_attribute.is_string:
            capabilities.enable("STRING_CLASS")

    if multi:
        capabilities.enable("ONLY_MULTIINSTANCE")

    return capabilities

from itertools import chain


def pipe_union(context=None, _INPUT=None, conf=None, **kwargs):
    """Merge ``_INPUT`` with any ``_OTHER*`` sources into one stream.

    This operator is not loopable; it simply chains the primary input together
    with every additional source pipe passed as a keyword argument.
    """
    others = [
        value for key, value in sorted(kwargs.items())
        if key.startswith("_OTHER") and value is not None
    ]

    def _generate():
        for item in chain(_INPUT or [], *others):
            yield item

    return _generate()

def save_task(self, task):
    """Save a task into the TaskWarrior database.

    Existing tasks (those carrying a ``uuid``) are updated with a ``modify``
    call, while new tasks are created with an ``add`` call.
    """
    uuid = task.get("uuid")
    if uuid:
        command = [uuid, "modify"]
    else:
        command = ["add"]

    for key, value in task.items():
        if key in ("id", "uuid") or value is None:
            continue
        command.append("{0}:{1}".format(key, value))

    return self.execute_command(command)

