def validate(self, instance, value):
    """Check that the value is a valid file open in the correct mode.

    If ``value`` is a string it is treated as a path and opened with the mode
    configured on this property.
    """
    if isinstance(value, str):
        try:
            value = open(value, self.mode)
        except (IOError, OSError) as error:
            self.error(instance, value, extra=str(error))
            return value

    if not (hasattr(value, "read") or hasattr(value, "write")):
        self.error(instance, value)
        return value

    file_mode = getattr(value, "mode", None)
    if file_mode is not None and self.mode not in file_mode:
        self.error(instance, value)

    return value

