        },
    }
    return self._post("/files", data)

import requests


def _get_json_obj(self, endpoint, query, is_post=False):
    """Query an endpoint and return the decoded JSON response.

    Returns ``False`` if the connection could not be made.
    """
    url = self.base_url + endpoint
    try:
        if is_post:
            response = self.session.post(url, data=query, timeout=30)
        else:
            response = self.session.get(url, params=query, timeout=30)
        response.raise_for_status()
    except requests.exceptions.RequestException:
        return False
    return response.json()

def rna_transcript_expression_dict_from_args(args):
    """Return a dict mapping Ensembl transcript IDs to FPKM expression values.

    Returns ``None`` if neither a Cufflinks tracking file nor a StringTie GTF
    file was specified on ``args``.
    """
    cufflinks_file = getattr(args, "rna_transcript_fpkm_tracking_file", None)
    if cufflinks_file:
        from isovar.cufflinks import cufflinks_transcript_expression_dict
        return cufflinks_transcript_expression_dict(cufflinks_file)

    stringtie_file = getattr(args, "rna_transcript_fpkm_gtf_file", None)
