        return stringtie_transcript_expression_dict(stringtie_file)

    return None

import subprocess


def get_dvcs_info():
    """Get information about the current git repository."""
    def _git(*command):
        return subprocess.check_output(
            ("git",) + command,
            stderr=subprocess.DEVNULL,
        ).decode("utf-8", "replace").strip()

    try:
        return {
            "branch": _git("rev-parse", "--abbrev-ref", "HEAD"),
            "commit": _git("rev-parse", "HEAD"),
            "remote": _git("config", "--get", "remote.origin.url"),
        }
    except (subprocess.CalledProcessError, OSError):
        return {}

import os
import subprocess


def system_model():
    """Get the manufacturer and model number of the machine.

    On older Linux kernels without ``/sys/class/dmi/id`` this falls back to
    ``dmidecode``, which requires root access.
    """
    def _read_dmi(name):
        try:
            with open(os.path.join("/sys/class/dmi/id", name)) as handle:
                return handle.read().strip()
        except (IOError, OSError):
            return None

    manufacturer = _read_dmi("sys_vendor")
    model = _read_dmi("product_name")

    if not manufacturer or not model:
        try:
            manufacturer = subprocess.check_output(
                ["dmidecode", "-s", "system-manufacturer"]).decode().strip()
            model = subprocess.check_output(
                ["dmidecode", "-s", "system-product-name"]).decode().strip()
        except (OSError, subprocess.CalledProcessError):
            pass

    return manufacturer, model

