    return output

def match_gpus(available_devices, requirements):
    """Determines sufficient GPUs for the given requirements and returns a
    list of GPUDevices. If there aren't sufficient GPUs an
    InsufficientGPUException is thrown."""
    if not requirements:
        return []

    available = list(available_devices)
    used = []

    for requirement in requirements:
        match = None
        for device in available:
            if requirement.is_satisfied_by(device) if hasattr(requirement, "is_satisfied_by") else True:
                match = device
                break
        if match is None:
            raise InsufficientGPUException(
                "Could not find a GPU satisfying requirement: {}".format(requirement)
            )
        available.remove(match)
        used.append(match)

    return used


class InsufficientGPUException(Exception):
    pass

