import json
import subprocess


def _find_conda_env_paths_from_conda(mgr):
    """Returns a list of paths as given by `conda env list --json`.

    Returns empty list, if conda couldn't be called.
    """
    conda_exe = getattr(mgr, "conda_exe", "conda")
    try:
        output = subprocess.check_output(
            [conda_exe, "env", "list", "--json"],
            stderr=subprocess.DEVNULL,
        )
    except (OSError, subprocess.CalledProcessError):
        return []
    try:
        data = json.loads(output.decode("utf-8"))
    except (ValueError, UnicodeDecodeError):
        return []
    return data.get("envs", [])

def render_template(request, app, template_name, context=None, subdir="templates", def_name=None):
    """Convenience method that directly renders a template, given the app and
    template names."""
    from mako.template import Template
    from mako.lookup import TemplateLookup
    import os

    if context is None:
        context = {}

    directories = [os.path.join(app, subdir)]
    lookup = TemplateLookup(directories=directories, input_encoding="utf-8")
    template = lookup.get_template(template_name)

    if def_name:
        template = template.get_def(def_name)

    return template.render(request=request, **context)

