def _show_warning(message, category, filename, lineno, file=None, line=None):
    """Hook to write a warning to a file; replace if you like."""
    if file is None:
        file = sys.stderr
        if file is None:
            return
    text = "{}:{}: {}: {}\n".format(
        filename, lineno, category.__name__, str(message)
    )
