def plot(self, pcs=[1, 2], ax=None, cmap=None, cdict=None, legend=True, title=None, outfile=None):
    """Do the PCA and plot it."""
    import matplotlib.pyplot as plt

    coords = self.pca(max(pcs)) if hasattr(self, "pca") else self.coords
    x_idx = pcs[0] - 1
    y_idx = pcs[1] - 1

    if ax is None:
        fig, ax = plt.subplots()

    populations = getattr(self, "populations", None)
    if populations is not None:
        for i, pop in enumerate(sorted(set(populations))):
            mask = [p == pop for p in populations]
            xs = [coords[j][x_idx] for j, m in enumerate(mask) if m]
            ys = [coords[j][y_idx] for j, m in enumerate(mask) if m]
            color = None
            if cdict is not None:
                color = cdict.get(pop)
            elif cmap is not None:
                color = cmap(i)
            ax.scatter(xs, ys, label=str(pop), color=color)
    else:
        xs = [row[x_idx] for row in coords]
        ys = [row[y_idx] for row in coords]
        ax.scatter(xs, ys)

    ax.set_xlabel("PC{}".format(pcs[0]))
    ax.set_ylabel("PC{}".format(pcs[1]))
    if title:
        ax.set_title(title)
    if legend and populations is not None:
        ax.legend()
    if outfile:
        ax.figure.savefig(outfile)
    return ax

def compute_tree_stats(self, ipyclient):
    """compute stats for stats file and NHX tree features"""
    lbview = ipyclient.load_balanced_view()

    jobs = {}
    for idx, tree in enumerate(self.treelist):
        jobs[idx] = lbview.apply(self._compute_stats_worker, tree)

    ipyclient.wait()

    results = {}
    for idx, async_result in jobs.items():
        if async_result.successful():
            results[idx] = async_result.get()
        else:
            raise async_result.exception()

    self.tree_stats = results
    return results

def reload_functions(self):
    """Replace functions in namespace with functions from edited_source."""
    import types

    new_namespace = {}
    exec(compile(self.edited_source, "<edited_source>", "exec"),
         new_namespace)

    for name, obj in new_namespace.items():
        if isinstance(obj, types.FunctionType):
            self.namespace[name] = obj

import numpy as np


def integral(A=None, dF=None, F=None, axis=0, trapez=False, cumulative=False):
    """Turns an array A of length N (the function values in N points) and an
    array dF of length N-1 (the masses of the N-1 intervals) into an array of
    length N (the integral \\int A dF at N points, with first entry 0)."""
    if F is not None and dF is None:
        F = np.asarray(F)
        dF = np.diff(F, axis=axis)

    if A is None and dF is not None:
        N = np.asarray(dF).shape[axis] + 1
    elif A is not None:
        N = np.asarray(A).shape[axis]
    else:
        raise ValueError("Provide at least one of A, dF or F")

    if A is None:
        A = np.ones(N)
    else:
        A = np.asarray(A, dtype=float)

    if dF is None:
        dF = np.ones(N - 1)
    else:
        dF = np.asarray(dF, dtype=float)

    A = np.moveaxis(A, axis, 0)
    dF = np.moveaxis(dF, axis, 0) if dF.ndim > 1 else dF

    if trapez:
        contributions = (A[:-1] + A[1:]) / 2.0
    else:
        contributions = A[:-1]

    if dF.ndim < contributions.ndim:
        dF = dF.reshape((-1,) + (1,) * (contributions.ndim - 1))

    increments = contributions * dF

    result = np.zeros_like(A, dtype=float)
    cum = np.cumsum(increments, axis=0)
    result[1:] = cum
    result = np.moveaxis(result, 0, axis)

    if cumulative:
        return result
    return np.take(result, -1, axis=axis)
